const Map<String, (String nameTh, String descTh)> kLandmarkTh = {
  'chengdu/panda': ('ศูนย์วิจัยแพนด้ายักษ์เฉิงตู', 'ศูนย์วิจัยและเพาะพันธุ์แพนด้ายักษ์แห่งเฉิงตูเป็นศูนย์อนุรักษ์แพนด้าที่ใหญ่ที่สุดในโลก ทุกปีมีผู้มาเยือนหลายล้านคนเพื่อชมแพนด้า สัญลักษณ์อันเป็นที่รักของเมือง กลิ้งเล่นอยู่ท่ามกลางดงไผ่'),
  'chengdu/hotpot': ('หม่าล่าหม้อไฟเสฉวน', 'หม้อไฟที่เดือดปุด ๆ ด้วยพริกหมาล่าเสฉวนชวนชาลิ้นและน้ำมันพริกสีแดงฉาน คือหัวใจของวัฒนธรรมการกินแห่งเฉิงตู ทุกคนจุ่มอาหารคำของตนลงในหม้อกลางโต๊ะ — การกินที่นี่จึงเป็นเหมือนเกมสนุกที่แบ่งปันร่วมกัน'),
  'chengdu/bianlian': ('การแสดงเปลี่ยนหน้ากาก', 'ในเปี้ยนเหลี่ยน ศิลปะเปลี่ยนหน้ากากอันน่าอัศจรรย์ของงิ้วเสฉวน เหล่าปรมาจารย์เปลี่ยนหน้ากากหลากสีได้ในชั่วพริบตาเพียงสะบัดมือครั้งเดียว เคล็ดลับนี้ถ่ายทอดจากอาจารย์สู่ศิษย์เท่านั้น'),
  'chengdu/jinli': ('ถนนโบราณจินหลี่', 'ถนนจิ๋นหลี่ที่สว่างไสวด้วยโคมแดงเป็นถนนตลาดเก่าแก่ที่สืบย้อนไปถึงยุคสามก๊ก ด้วยโรงน้ำชา หนังตะลุง และช่างวาดภาพด้วยน้ำตาล ที่นี่คือที่ที่คุณจะสัมผัสจังหวะชีวิตอันเนิบช้าเลื่องชื่อของเฉิงตูได้ดีที่สุด'),
  'nanjing/citywall': ('กำแพงเมืองหนานจิง', 'กำแพงยักษ์นี้สร้างโดยปฐมจักรพรรดิแห่งราชวงศ์หมิงเพื่อปกป้องเมืองหลวงของพระองค์ และเป็นกำแพงเมืองที่ยาวที่สุดในโลกที่ยังคงเหลืออยู่ อิฐทุกก้อนสลักชื่อช่างผู้ทำไว้เพื่อรับประกันคุณภาพ วันนี้คุณเดินบนกำแพงชมหนานจิงทั้งเมืองเก่าและเมืองใหม่ได้ในคราวเดียว'),
  'nanjing/plum': ('ดอกเหมย', 'ดอกเหมยที่บานฝ่าหิมะกลางฤดูหนาวเป็นสัญลักษณ์ของความอดทนและความหวังในวัฒนธรรมจีน — หนานจิงจึงเลือกให้เป็นดอกไม้ประจำเมือง ปลายฤดูหนาว เนินเขาเหมยฮวาจะกลายเป็นทะเลดอกไม้สีชมพูขาว ผู้คนพากันมาเดินเล่นใต้ต้นเหมย'),
  'nanjing/duck': ('เป็ดเค็มหนานจิง', 'เป็ดเค็มอันเป็นเอกลักษณ์ของหนานจิงหมักในน้ำเกลือเครื่องเทศ ตุ๋นอย่างอ่อนโยนแล้วเสิร์ฟเย็น เนื้อนุ่มละมุนและปรุงรสได้พอดิบพอดี เป็ดคือความหลงใหลของคนทั้งเมือง — มุกตลกท้องถิ่นบอกว่าไม่มีเป็ดตัวไหนออกจากหนานจิงได้ทั้งเป็น'),
  'nanjing/bridge': ('สะพานข้ามแม่น้ำแยงซีหนานจิง', 'สะพานหนานจิงข้ามแม่น้ำแยงซีสร้างเสร็จในปี 1968 โดยฝีมือวิศวกรจีนล้วน เป็นสะพานยักษ์สองชั้นที่รองรับทั้งถนนและทางรถไฟข้ามแม่น้ำ เพราะสร้างโดยไม่พึ่งความช่วยเหลือจากต่างชาติ สะพานจึงกลายเป็นสัญลักษณ์อันภาคภูมิแห่งการพึ่งพาตนเองของจีนยุคใหม่ และยังถูกเล่าขานในตำราเรียนจนทุกวันนี้'),
  'qingdao/beer': ('เบียร์ชิงเต่า', 'โรงเบียร์ชิงเต่าที่ก่อตั้งในยุคเยอรมันของเมือง ทำให้ชิงเต่าเป็นบ้านของเบียร์จีนที่โด่งดังที่สุด ทุกฤดูร้อนเทศกาลเบียร์นานาชาติทำให้ทั้งเมืองครึกครื้น และเบียร์สดใส่ถุงพลาสติกดูดด้วยหลอดก็ยังคงเป็นประเพณีข้างถนนที่น่ารักที่สุดของชิงเต่า'),
  'qingdao/sailing': ('เมืองแห่งการแล่นเรือใบ', 'การแข่งขันเรือใบของโอลิมปิก 2008 จัดขึ้นที่ท่าเรือมารีน่าของชิงเต่า และเมืองนี้ก็ครองสมญา "เมืองแห่งเรือใบ" นับแต่นั้นมา ด้วยอ่าวที่ลมพัดโชย ใบเรือขาวประดับขอบฟ้า และทางเดินเลียบทะเลอันยาวไกล ที่นี่คือเมืองหลวงแห่งกีฬาทางน้ำของจีน'),
  'qingdao/beach': ('ชายหาดชิงเต่า', 'ชายหาดของชิงเต่าทอดตัวอยู่เบื้องหน้าอาคารหลังคาแดงสไตล์เยอรมันบนเนินเขา มอบบรรยากาศเมืองชายทะเลแบบยุโรปที่หาได้ยากในจีน ฤดูร้อนหาดทรายเต็มไปด้วยนักว่ายน้ำ และเส้นทางเลียบชายฝั่งที่เชื่อมอ่าวสู่อ่าวคือเส้นทางเดินชมอาทิตย์อัสดงสุดคลาสสิก'),
  'qingdao/crab': ('อาหารทะเล', 'ชิงเต่าที่หันหน้าสู่ทะเลเหลืองกินของสดจากทะเลทุกวัน แผงหอยลาย หอยนางรม หอยเม่น และปูเรียงรายแน่นท่าเรือ วิถีท้องถิ่นคือนึ่งของสดที่จับได้วันนั้นแบบเรียบง่าย แล้วดื่มคู่กับเบียร์ชิงเต่าเย็นเจี๊ยบ'),
  'changsha/pepper': ('พริกหูหนาน', 'อาหารหูหนานต่างจากรสเผ็ดชาของเสฉวน ตรงที่ขึ้นชื่อเรื่องความเผ็ดร้อนแบบแห้งจัดจ้าน — พริกสดและพริกดองปรากฏอยู่แทบทุกจาน ในฉางชา ความเผ็ดคือคำตอบเก่าแก่ต่อภูมิอากาศชื้น ชาวเมืองชอบพูดติดตลกว่าพวกเขาไม่กลัวเผ็ด แต่กลัวไม่เผ็ดต่างหาก'),
  'changsha/tofu': ('เต้าหู้เหม็น', 'เต้าหู้เหม็นของฉางชาแช่ในน้ำหมักแล้วทอดจนข้างนอกดำสนิทกรุบกรอบ ข้างในขาวนุ่มดั่งหิมะ อย่าให้กลิ่นฉุนหลอกคุณ — เมื่อราดซอสพริก คำเล็ก ๆ นี้คือเมนูที่เรียกแถวยาวที่สุดในตลาดกลางคืน'),
  'changsha/fireworks': ('ดอกไม้ไฟ', 'หลิวหยาง เมืองเพื่อนบ้านของฉางชา ได้รับการยกย่องมาหลายศตวรรษว่าเป็นเมืองหลวงดอกไม้ไฟของโลก — ในบ้านเกิดของดินปืน งานฝีมือนี้สืบทอดจากรุ่นสู่รุ่น ในการแสดงที่จัดเป็นประจำริมแม่น้ำเซียง ท้องฟ้าและผืนน้ำเปล่งประกายสีสันไปพร้อมกัน'),
  'changsha/orange': ('เกาะส้ม', 'เกาะส้ม ผืนดินเรียวยาวกลางแม่น้ำเซียง ได้ชื่อมาจากสวนส้มที่เรียงรายริมฝั่ง เหมาเจ๋อตงเคยว่ายน้ำในสายน้ำนี้เมื่อวัยหนุ่มและแต่งบทกวีอันโด่งดังถึงเกาะแห่งนี้ วันนี้รูปสลักหินแกรนิตขนาดยักษ์ของเหมาในวัยหนุ่มทอดสายตามองแม่น้ำจากปลายเกาะ'),
  'zhengzhou/kungfu': ('กังฟูเส้าหลิน', 'ที่เชิงเขาซงซานใกล้เจิ้งโจวคือที่ตั้งของวัดเส้าหลิน แหล่งกำเนิดพุทธศาสนานิกายฉาน (เซน) และกังฟูเส้าหลิน รอบอารามอายุราวหนึ่งพันห้าร้อยปี นักเรียนหลายพันคนในโรงเรียนศิลปะการต่อสู้ยังคงสืบสานมรดกนี้ด้วยการฝึกซ้อมที่เริ่มตั้งแต่ฟ้าสาง'),
  'zhengzhou/train': ('ศูนย์กลางทางรถไฟ', 'เจิ้งโจวเติบโตเป็นมหานคร ณ จุดตัดของทางรถไฟสายหลักเหนือ-ใต้และตะวันออก-ตะวันตกของจีน เมืองนี้ถูกขนานนามว่า "เมืองที่รถไฟสร้างขึ้น" และยังคงเป็นชุมทางที่คึกคักที่สุดแห่งหนึ่งของเครือข่ายรถไฟความเร็วสูงของประเทศ'),
  'zhengzhou/wheat': ('ทุ่งข้าวสาลี', 'ที่ราบเหอหนานซึ่งหล่อเลี้ยงด้วยแม่น้ำเหลืองเป็นอู่ข้าวสาลีที่ยิ่งใหญ่ที่สุดแห่งหนึ่งของจีน ผืนดินอันอุดมนี้หล่อเลี้ยงจิตวิญญาณของอาหารจีนเหนือ — บะหมี่ดึงมือ เกี๊ยวนึ่ง และแผ่นแป้งย่าง ล้วนเริ่มต้นจากเมล็ดข้าวสาลีของท้องทุ่งแห่งนี้'),
  'zhengzhou/ding': ('ภาชนะสำริดติ่ง', 'เจิ้งโจวและพื้นที่โดยรอบเคยเป็นเมืองหลวงของราชวงศ์ซาง หนึ่งในราชวงศ์เก่าแก่ที่สุดของจีน การขุดค้นที่นี่พบภาชนะสัมฤทธิ์สำหรับพิธีกรรมที่เรียกว่า "ติ่ง" ภาชนะเหล่านี้เป็นสัญลักษณ์ของอำนาจและเครื่องเซ่นบรรพชน — เมืองนี้จึงนับเป็นหนึ่งในอู่อารยธรรมจีน'),
  'wuxi/lake': ('ทะเลสาบไท่หู', 'อู๋ซีตั้งอยู่ริมทะเลสาบไท่หู หนึ่งในทะเลสาบน้ำจืดที่ใหญ่ที่สุดของจีน ปลา กุ้ง และผักน้ำจากทะเลสาบคือรากฐานของอาหารท้องถิ่น เมื่อชมยามอาทิตย์อัสดงจากแหลมหยวนโถวจู่ ทะเลสาบจะงดงามราวมนตร์สะกดเป็นพิเศษในฤดูซากุระบาน'),
  'wuxi/peach': ('ลูกพีชหยางซาน', 'เมืองหยางซานในอู๋ซีโด่งดังไปทั่วจีนด้วยลูกท้อที่หวานฉ่ำจนตักกินด้วยช้อนได้ ผลไม้นี้สุกกลางฤดูร้อน เมื่อฤดูเก็บเกี่ยวนำพาบรรยากาศงานรื่นเริงมาสู่เมือง และสวนท้อก็เปิดต้อนรับผู้มาเยือน'),
  'wuxi/figurine': ('ตุ๊กตาดินเผาฮุ่ยซาน', 'ตุ๊กตาดินเผาฮุยซานเป็นงานฝีมือพื้นบ้านอายุหลายศตวรรษ ปั้นจากดินสีเข้มเนื้อนุ่มที่เชิงเขาฮุยของอู๋ซี ตัวที่เป็นที่รักที่สุดคืออาฝู เด็กแก้มยุ้ยผู้เป็นสัญลักษณ์ของความอุดมสมบูรณ์และความสุข ตุ๊กตาระบายสีสดใสด้วยมือเหล่านี้คือของฝากคลาสสิกประจำเมือง'),
  'wuxi/boat': ('เรือคลอง', 'คลองใหญ่ ทางน้ำที่มนุษย์สร้างขึ้นซึ่งยาวที่สุดในโลก ไหลผ่านใจกลางอู๋ซีพอดี การลงเรือในย่านสะพานชิงหมิงที่สว่างไสวด้วยแสงโคม แล้วล่องผ่านบ้านเก่าผนังขาวหลังคากระเบื้องดำ คือวิธีที่งดงามที่สุดในการทำความรู้จักเมืองนี้'),
  'nanning/tree': ('เมืองสีเขียว', 'หนานหนิงตั้งอยู่ในเขตร้อนทางตอนใต้ของจีน ได้ชื่อว่า "เมืองสีเขียว" จากถนนที่ร่มรื่นด้วยต้นไม้ใหญ่และสวนสาธารณะที่เขียวชอุ่มตลอดปี เมืองนี้อยู่ใกล้ชายแดนเวียดนาม และเป็นประตูการค้าและวัฒนธรรมระหว่างจีนกับเอเชียตะวันออกเฉียงใต้'),
  'nanning/noodle': ('ก๋วยเตี๋ยวเหล่าโหย่ว', 'เหล่าโหย่วเฝิ่น หรือ "บะหมี่เพื่อนเก่า" คือเมนูคลาสสิกรสเปรี้ยวเผ็ดของหนานหนิง ปรุงด้วยหน่อไม้ดอง ถั่วดำหมัก และพริก ตำนานเล่าว่าเจ้าของโรงน้ำชาปรุงซุปนี้ขึ้นครั้งแรกเพื่อรักษาเพื่อนเก่าที่ล้มป่วย — และมันก็เป็นยาแก้วันอากาศชื้นนับแต่นั้นมา'),
  'nanning/song': ('เพลงพื้นเมือง', 'ชาวจ้วงแห่งกว่างซีขับขานความรู้สึกผ่านเพลงพื้นบ้านโต้ตอบแบบด้นสดมาหลายศตวรรษ ทุกฤดูใบไม้ผลิ งานประชันเพลง "เดือนสาม" เต็มเมืองด้วยบทเพลงโต้กลอนของหนุ่มสาว และหลิวซานเจี่ย นักร้องในตำนาน ก็ยังคงเป็นวีรสตรีที่รักที่สุดของประเพณีนี้'),
  'nanning/mango': ('ผลไม้เขตร้อน', 'ภูมิอากาศเขตร้อนทำให้หนานหนิงเป็นดินแดนอุดมสมบูรณ์ของมะม่วง ลำไย ลิ้นจี่ และมะละกอ แผงข้างถนนล้นด้วยผลไม้สดตลอดทั้งปี ในค่ำคืนอันอบอุ่น ของหวานผลไม้ใส่น้ำแข็งและน้ำผลไม้คั้นสดคือวิธีคลายร้อนที่ชาวเมืองรักที่สุด'),
  'nanchang/pavilion': ('หอเถิงหวัง', 'หอเถิงหวังริมแม่น้ำก้านถูกทำลายและสร้างขึ้นใหม่หลายครั้งนับแต่ราชวงศ์ถัง เป็นหนึ่งในสามหอเลื่องชื่อที่สุดของจีนตอนใต้ อารัมภบทที่กวีหนุ่มหวังปั๋วประพันธ์ขึ้นที่นี่กลายเป็นวรรณกรรมชิ้นเอกของจีนและทำให้หอแห่งนี้เป็นอมตะ'),
  'nanchang/star': ('เหตุการณ์ 1 สิงหาคม', 'การลุกฮือที่หนานชางเมื่อวันที่ 1 สิงหาคม 1927 ถือเป็นจุดกำเนิดของกองทัพปลดปล่อยประชาชนจีน ทำให้หนานชางได้รับสมญา "เมืองแห่งวีรบุรุษ" ตัวอักษร "8-1" บนธงของกองทัพชี้ถึงวันสำคัญนั้น — และเป็นที่มาของชื่อจัตุรัสกลางเมืองด้วย'),
  'nanchang/porcelain': ('เครื่องเคลือบดินเผาหนานชาง', 'เจียงซี มณฑลของหนานชาง เป็นที่ตั้งของจิ่งเต๋อเจิ้น เมืองหลวงเครื่องกระเบื้องของโลก ตลอดหนึ่งพันปี เตาเผาหลวงที่นี่ผลิต "ทองคำขาว" ให้เหล่าพระราชวัง และกองคาราวานกับเรือสำเภาก็นำพาไปทั่วโลก — งานฝีมือนี้ยังมีชีวิตอยู่ในมือช่างรุ่นใหม่จนทุกวันนี้'),
  'nanchang/sunset': ('วิวแม่น้ำก้าน', 'เมื่อค่ำคืนมาเยือน สองฝั่งแม่น้ำก้านก็แปลงโฉม: ผนังอาคารหลายร้อยหลังกลายเป็นการแสดงแสงสีขนาดมหึมาที่ประสานจังหวะเป็นหนึ่งเดียว สวนริมน้ำและเงาเรืองแสงของหอเถิงหวังทำให้ที่นี่เป็นเส้นทางเดินเล่นยามเย็นที่ชาวหนานชางรักที่สุด'),
  'yinchuan/camel': ('เส้นทางสายไหม', 'อิ๋นชวน โอเอซิสที่หล่อเลี้ยงด้วยแม่น้ำเหลือง เคยเป็นประตูตะวันตกที่กองคาราวานเส้นทางสายไหมพักแรมก่อนเผชิญทะเลทราย นอกเมือง สุสานหลวงรูปทรงคล้ายพีระมิดของราชวงศ์เซี่ยตะวันตกยังคงตั้งตระหง่านเงียบงันใต้แสงตะวันแห่งทะเลทราย'),
  'yinchuan/grapes': ('ไร่องุ่นเหอหลาน', 'เชิงเขาด้านตะวันออกของเทือกเขาเฮ่อหลาน ด้วยแดดจัด อากาศแห้ง และดินกรวดหิน ได้รับการยกย่องว่าเป็นแหล่งไวน์ชั้นเลิศที่สุดของจีน ไวน์จากไร่องุ่นที่นี่คว้ารางวัลระดับนานาชาติมากมาย จนคอไวน์พากันขนานนามภูมิภาคนี้ว่า "บอร์โดซ์แห่งเมืองจีน"'),
  'yinchuan/desert': ('ทะเลทรายซาโพโถว', 'ที่ซาปอโถวใกล้อิ๋นชวน เนินทรายสีทองของทะเลทรายเถิงเก๋อร์มาบรรจบกับแม่น้ำเหลือง — หนึ่งในสถานที่หายากที่ทะเลทรายกับแม่น้ำอยู่เคียงข้างกัน การเล่นสไลด์ลงเนินทราย ขี่อูฐเข้าสู่ผืนทราย และข้ามแม่น้ำด้วยแพหนังแกะ คือการผจญภัยสุดคลาสสิกของภูมิภาคนี้'),
  'yinchuan/sheep': ('เนื้อแกะสไตล์หุย', 'เนื้อแกะคือดาวเด่นของอาหารมุสลิมหุยแห่งหนิงเซี่ย: เนื้อเสียบไม้ย่างโรยยี่หร่า แกะต้มเนื้อนุ่ม และซุปบะหมี่ดึงมือ เต็มโต๊ะอาหารทั่วเมือง แกะท้องถิ่นที่เลี้ยงบนทุ่งหญ้าสเตปป์เลื่องชื่อไปทั่วจีนด้วยเนื้อนุ่มและรสชาติสะอาดบริสุทธิ์'),
  'lhasa/mountain': ('พระราชวังโปตาลา', 'พระราชวังโปตาลาที่ตั้งตระหง่านบนยอดเขาแดงคือสุดยอดสถาปัตยกรรมทิเบต ด้วยห้องหลายร้อยห้อง สถูปศักดิ์สิทธิ์ และหอสวดมนต์ อาคารสีแดง-ขาวซึ่งเคยเป็นพระราชวังฤดูหนาวขององค์ดาไลลามะหลังนี้ เป็นมรดกโลกยูเนสโกและมองเห็นได้จากแทบทุกมุมของลาซา'),
  'lhasa/prayer': ('วัดโจคัง', 'ผู้จาริกแสวงบุญเดินทางสู่วัดโจคัง วัดที่ศักดิ์สิทธิ์ที่สุดของพุทธศาสนาทิเบต บางครั้งด้วยการกราบอัษฎางคประดิษฐ์ตลอดเส้นทาง บนเส้นทางบาร์คอร์รอบวัด สายธารผู้ศรัทธาที่หมุนกงล้อมนตราไม่เคยหยุดนิ่งตลอดวัน และกลิ่นธูปหอมก็อบอวลไปทั่วท้องถนน'),
  'lhasa/yak': ('วัฒนธรรมจามรี', 'จามรี สัตว์ที่เกิดมาเพื่อความหนาวของที่ราบสูง คือเสาหลักของชีวิตชาวทิเบต: นมของมันให้เนยและชีส ขนกลายเป็นเต็นท์และเสื้อผ้า มูลใช้เป็นเชื้อเพลิงก่อไฟ แม้แต่ตะเกียงที่จุดสว่างทั้งวันทั้งคืนในวัดก็หล่อเลี้ยงด้วยเนยจามรี'),
  'lhasa/tea': ('ชาเนยจามรี', 'ชาเนย ที่ได้จากการปั่นเนยจามรี เกลือ และชาดำรสเข้มเข้าด้วยกัน คือเครื่องดื่มประจำวันของชาวทิเบต ในความหนาวแห้งของที่สูง มันทั้งให้ความอบอุ่นและบำรุงร่างกายไปพร้อมกัน — และการคอยเติมชาให้แขกทุกครั้งที่ถ้วยพร่อง คือกฎอันแสนหวานของน้ำใจไมตรีแบบทิเบต'),
  'zhuhai/shell': ('อนุสาวรีย์สาวน้อยถือไข่มุก', 'รูปปั้นสาวชาวประมงที่ยืนบนโขดหินกลางทะเล ชูไข่มุกขึ้นสู่ฟ้า คือสัญลักษณ์ของจูไห่ เธอถือกำเนิดจากตำนานท้องถิ่นเรื่องนางฟ้าที่จำแลงกายเป็นมนุษย์เพราะรักชายชาวประมง และคอยทักทายทุกคนที่เดินเล่นบนถนนเลียบชายฝั่งด้วยท่วงท่าอันงามสง่า'),
  'zhuhai/bridge': ('สะพานฮ่องกง-จูไห่-มาเก๊า', 'สะพานฮ่องกง-จูไห่-มาเก๊าคือทางข้ามทะเลที่ยาวที่สุดในโลกด้วยระยะทาง 55 กิโลเมตร ประกอบด้วยสะพาน เกาะเทียม และอุโมงค์ลอดใต้ทะเล โครงสร้างยักษ์ที่เชื่อมสามเมืองแห่งสามเหลี่ยมปากแม่น้ำจูเจียงเข้าเป็นเส้นทางเดียวนี้ นับเป็นหนึ่งในผลงานชิ้นเอกของวิศวกรรมสมัยใหม่'),
  'zhuhai/island': ('หมู่เกาะร้อยเกาะ', 'ชื่อจูไห่แปลว่า "ทะเลไข่มุก" และมีเกาะกว่าร้อยเกาะกระจายอยู่ตามชายฝั่ง เกาะอย่างตงอ้าวและไว่หลิงติงที่ไปถึงได้ด้วยเรือเฟอร์รี มีหมู่บ้านชาวประมง อ่าวอันเงียบสงบ และร้านอาหารทะเลรอต้อนรับ — แต่ละเกาะใช้ชีวิตตามจังหวะของตัวเอง'),
  'zhuhai/lobster': ('อาหารทะเลสด', 'ณ จุดที่แม่น้ำจูเจียงบรรจบทะเล จูไห่จัดโต๊ะอาหารด้วยของทะเลที่จับได้วันต่อวัน: กุ้งมังกร กั้ง หอยเชลล์ และหอยนางรม ถูกเลือกเป็น ๆ จากตู้แล้วปรุงกันสด ๆ ตรงนั้น การนึ่งแบบกวางตุ้งอันนุ่มนวลช่วยขับความสดและรสหวานตามธรรมชาติให้เปล่งประกาย'),
  'yantai/apple': ('แอปเปิลหยานไถ', 'ภูมิอากาศทะเลเย็นสบายและแสงแดดอันอุดมของหยานไถปลูกแอปเปิลที่โด่งดังที่สุดของจีน — สีแดง กรอบ หอมหวานดั่งน้ำผึ้ง ส่งขายไปทุกมุมของประเทศ ในฤดูใบไม้ร่วง สวนผลไม้ตามชายฝั่งคึกคักด้วยการเก็บเกี่ยว และทั้งเมืองก็อบอวลด้วยกลิ่นหอมของแอปเปิล'),
  'yantai/wine': ('ไวน์จางอวี้', 'ฉางอวี้ โรงบ่มไวน์สมัยใหม่แห่งแรกของจีน ก่อตั้งขึ้นที่หยานไถในปี 1892 และยังคงเป็นบ้านไวน์ที่มีเรื่องราวยาวนานที่สุดของประเทศ ด้วยพิพิธภัณฑ์วัฒนธรรมไวน์ ห้องบ่มเก่าแก่ และเส้นทางไร่องุ่นใกล้เคียง หยานไถจึงติดอันดับ "เมืองแห่งไวน์" แท้จริงไม่กี่แห่งของเอเชีย'),
  'yantai/wave': ('ชายฝั่งเผิงไหล', 'ชายฝั่งเผิงไหลของหยานไถถูกเล่าขานในเทพปกรณัมจีนว่าเป็นจุดที่แปดเซียนออกเดินทางข้ามทะเล ภาพลวงตาที่ปรากฏระยิบระยับเหนือผืนน้ำเป็นครั้งคราวทำให้ชายฝั่งนี้ได้ชื่อว่าเป็น "แดนแห่งเทพเซียน" และหอเผิงไหลอันเก่าแก่ก็เฝ้ามองทะเลจากหน้าผาของมัน'),
  'yantai/cherry': ('สวนเชอร์รี', 'หยานไถเป็นหนึ่งในแหล่งปลูกเชอร์รีที่ยิ่งใหญ่ของจีน ภูมิอากาศชายฝั่งเย็นสบายเหมาะอย่างยิ่งกับผลเชอร์รีลูกโต ฉ่ำ และหวาน ต้นฤดูร้อนสวนผลไม้เปิดต้อนรับผู้มาเยือน และการเด็ดเชอร์รีจากกิ่งกินสด ๆ คือกิจกรรมเที่ยวที่หวานที่สุดของฤดูกาล'),
  'datong/buddha': ('ถ้ำหยุนกัง', 'ถ้ำหยุนกังที่สลักลงหน้าผาทางตะวันตกของต้าถงบรรจุพระพุทธรูปนับพันองค์จากยุคราชวงศ์เว่ยเหนือ — หนึ่งในจุดสูงสุดของพุทธศิลป์จีน บางองค์เล็กพอวางบนฝ่ามือ ขณะที่บางองค์สูงตระหง่านเท่าตึก ถ้ำเหล่านี้ได้รับการขึ้นทะเบียนเป็นมรดกโลกยูเนสโก'),
  'datong/citywall': ('กำแพงเมืองต้าถง', 'ต้าถง อดีตเมืองป้อมปราการชายแดน ได้บูรณะกำแพงยุคราชวงศ์หมิงขึ้นใหม่พร้อมประตูอันโอ่อ่าและหอมุมครบครัน การเดินบนเชิงเทินที่ประดับโคมยามพลบค่ำ คือวิธีที่ดีที่สุดในการชมหลังคาเมืองเก่าและแสงไฟของต้าถงใหม่ในภาพเดียวกัน'),
  'datong/noodle': ('บะหมี่ตัดด้วยมีด', 'ในเต้าเซียวเมี่ยน (บะหมี่มีดเฉือน) ความภาคภูมิใจของมณฑลซานซี พ่อครัวพาดก้อนแป้งไว้บนแขนแล้วใช้มีดเฉือนริ้วบะหมี่ให้ปลิวลงหม้อน้ำเดือดโดยตรง เส้นขอบหนาตรงกลางบางเหล่านี้อุ้มน้ำซอสได้อย่างสมบูรณ์แบบ — คลาสสิกที่ขาดไม่ได้ของโต๊ะอาหารต้าถง'),
  'datong/lantern': ('วัดแขวน', 'วัดแขวนที่ตรึงอยู่บนหน้าผาของภูเขาเหิงใกล้ต้าถง ดูราวกับลอยอยู่กลางอากาศบนเสาไม้เรียวบาง อาคารอายุราวหนึ่งพันห้าร้อยปีนี้ยังโดดเด่นไม่เหมือนใครด้วยอีกเหตุผลหนึ่ง: มันรวมพุทธ เต๋า และขงจื๊อไว้ใต้หลังคาเดียวกัน'),
  'baotou/horse': ('ม้าแห่งทุ่งหญ้า', 'ชื่อของเมืองเปาโถวมาจากภาษามองโกลแปลว่า \'ดินแดนแห่งกวาง\' และเมืองนี้ตั้งอยู่ริมขอบทุ่งหญ้าสเตปป์แห่งมองโกเลียใน บนทุ่งหญ้าโดยรอบ ม้ายังคงเป็นส่วนหนึ่งของชีวิตประจำวัน ชาวมองโกลผู้เลี้ยงสัตว์จัดการแข่งม้า และท่วงทำนองของซอหัวม้า \'มอริน คูร์\' ก็ล่องลอยอยู่ในกระโจมเกอร์'),
  'baotou/deer': ('สวนกวาง', 'เปาโถวได้รับสมญาว่า \'เมืองกวาง\' และฝูงกวางที่เดินเล่นอย่างอิสระในสวนสาธารณะก็ช่วยให้ชื่อนี้ยังมีชีวิตอยู่ นักท่องเที่ยวสามารถป้อนอาหารกวางด้วยมือของตนเอง ภาพอันอ่อนโยนกลางทุ่งหญ้าสเตปป์นี้เผยให้เห็นด้านที่นุ่มนวลอย่างน่าประหลาดใจของเมืองอุตสาหกรรม'),
  'baotou/factory': ('เมืองเหล็กกล้า', 'เปาโถวเป็นที่ตั้งของผู้ผลิตเหล็กกล้ารายใหญ่ที่สุดรายหนึ่งของจีน และครองตำแหน่งพิเศษบนแผนที่อุตสาหกรรมหนักของประเทศ ด้วยแหล่งแร่ในบริเวณใกล้เคียง เมืองนี้ยังเป็นที่รู้จักในฐานะศูนย์กลางธาตุหายาก (แรร์เอิร์ธ) ที่สำคัญที่สุดแห่งหนึ่งของโลกอีกด้วย'),
  'baotou/grass': ('ทริปทุ่งหญ้า', 'เดินทางจากตัวเมืองเพียงไม่นานก็จะถึงทุ่งหญ้าที่ทอดยาวสุดขอบฟ้า แขกผู้มาเยือนพักในกระโจมเกอร์ และได้รับการต้อนรับด้วยชานมกับเนื้อแกะย่าง ยามค่ำคืนเสียงเพลงมองโกลดังก้องรอบกองไฟ การต้อนรับแบบชาวทุ่งหญ้าที่นี่คือประเพณีที่สืบทอดมาหลายศตวรรษ'),
  'weifang/kite': ('เมืองหลวงแห่งว่าว', 'เหวยฟาง ดินแดนที่ได้ชื่อว่าเป็นบ้านเกิดของว่าว สืบสานงานฝีมือนี้มาหลายศตวรรษด้วยโครงไม้ไผ่และผ้าไหมวาดลวดลายด้วยมือ ทุกเดือนเมษายน เทศกาลว่าวนานาชาติเหวยฟางเปลี่ยนท้องฟ้าให้เป็นงานเฉลิมฉลองแห่งสีสัน โดยมีว่าวจากทั่วทุกมุมโลกมาร่วมโบยบิน'),
  'weifang/woodprint': ('ภาพพิมพ์หยางเจียปู้', 'หมู่บ้านหยางเจียปู้ในเหวยฟางเป็นหนึ่งในบ้านที่โด่งดังที่สุดของภาพพิมพ์แกะไม้หลากสีที่ติดประตูบ้านในช่วงตรุษจีน เทพทวารบาล เด็กน้อยจ้ำม่ำ และสัญลักษณ์แห่งความอุดมสมบูรณ์ ถูกพิมพ์สีทีละชั้นจากแม่พิมพ์ไม้แกะมือ เป็นงานฝีมือที่ส่งต่อจากรุ่นสู่รุ่น'),
  'weifang/dragon': ('ว่าวมังกร', 'ดาวเด่นแห่งท้องฟ้าเหวยฟางคือว่าวตะขาบหัวมังกรขนาดยักษ์: ห่วงไม้ไผ่หลายสิบวงเชื่อมกันด้วยลำตัวผ้าไหมที่พลิ้วไหวยาวหลายเมตรไปตามสายลม การปล่อยยักษ์ใหญ่เช่นนี้ขึ้นฟ้าต้องอาศัยทั้งฝีมือและพละกำลังของทีมนักเล่นว่าวทั้งทีม'),
  'weifang/radish': ('หัวไชเท้าเวยฟาง', 'หัวไชเท้าเขียวของเหวยฟางหวานฉ่ำเสียจนชาวเมืองปอกเปลือกหั่นกินเหมือนผลไม้ คำกล่าวท้องถิ่นคุยโวว่า "หัวไชเท้าเหวยฟางชนะลูกสาลี่" สะท้อนความภูมิใจที่มีต่อผักแสนธรรมดานี้ — การเสิร์ฟหัวไชเท้าคู่กับน้ำชาให้แขกคือน้ำใจไมตรีอันงดงามของเมืองนี้'),
  'dezhou/chicken': ('ไก่ตุ๋นเต๋อโจว', 'ไก่ตุ๋นเครื่องเทศของเต๋อโจวเคี่ยวจนเนื้อหลุดล่อนจากกระดูกได้เอง ชื่อเสียงของมันแพร่ไปทั่วประเทศด้วยทำเลอันคึกคักของเมืองบนคลองใหญ่และต่อมาบนเส้นทางรถไฟ ไก่ที่เคลือบน้ำผึ้ง ทอด แล้วตุ๋นช้า ๆ ในน้ำซุปเครื่องเทศนี้ ครั้งหนึ่งเคยถูกถวายบนโต๊ะเสวยของราชสำนัก'),
  'dezhou/sun': ('หุบเขาพลังงานแสงอาทิตย์', 'เต๋อโจวลงทุนในอุตสาหกรรมพลังงานแสงอาทิตย์ตั้งแต่ยุคแรกจนได้รับสมญา "เมืองพระอาทิตย์" ในวิทยาเขตหุบเขาสุริยะอันกว้างใหญ่ของเมือง โรงแรม ไฟถนน และบ้านเรือนล้วนขับเคลื่อนด้วยแสงตะวัน เมืองนี้ยืนหยัดเป็นหนึ่งในหน้าต่างโชว์พลังงานหมุนเวียนที่เห็นได้ชัดที่สุดของจีน'),
  'dezhou/grapes': ('แหล่งปลูกแตงและองุ่น', 'ผืนดินอุดมของที่ราบแม่น้ำเหลืองเปลี่ยนเต๋อโจวให้เป็นดินแดนผลไม้ฤดูร้อน: ท้องทุ่งเต็มไปด้วยแตงโม และซุ้มไม้เลื้อยก็ห้อยพวงองุ่นหนักอึ้ง แตงโมเย็นเจี๊ยบสักชิ้นจากแผงริมทาง คือการหยุดพักสุดคลาสสิกในวันร้อนของฤดูร้อน'),
  'dezhou/train': ('ท่าเรือคลองขุด', 'ในศตวรรษที่คลองใหญ่รุ่งเรือง เต๋อโจวเป็นท่าจอดอันพลุกพล่านของเรือบรรทุกธัญพืชที่มุ่งขึ้นเหนือ วันนี้ทางรถไฟรับช่วงบทบาทของคลองต่อ: เมืองบนเส้นทางปักกิ่ง-เซี่ยงไฮ้แห่งนี้ยังคงเป็นหนึ่งในประตูคมนาคมสำคัญของจีนเหนือ'),
  'xuzhou/stone': ('ภาพสลักหินสมัยราชวงศ์ฮั่น', 'สวีโจวคือบ้านเกิดของหลิวปัง ปฐมกษัตริย์แห่งราชวงศ์ฮั่น และเป็นดั่งหอจดหมายเหตุประวัติศาสตร์ที่สลักไว้บนหิน ภาพสลักหินสมัยฮั่นที่ประดับผนังห้องสุสานถ่ายทอดงานเลี้ยง รถม้าศึก และสัตว์ในตำนาน คลี่ชีวิตประจำวันเมื่อสองพันปีก่อนออกมาให้เห็นราวกับการ์ตูนช่องโบราณ'),
  'xuzhou/terracotta': ('กองทัพทหารดินเผา', 'ทหารดินเผาสมัยราชวงศ์ฮั่นเหล่านี้มีขนาดเล็กกว่ากองทัพอันโด่งดังที่ซีอาน ถูกค้นพบขณะยืนเฝ้าสุสานของกษัตริย์แห่งแคว้นฉู่ รูปปั้นสูงเพียงระดับเข่ายืนเรียงแถวอย่างเป็นระเบียบ แม้ตัวจะจิ๋วแต่ท่าทีอันขรึมขลังบอกเล่าถึงกองทัพที่ตั้งใจให้รับใช้ต่อไปแม้หลังความตาย'),
  'xuzhou/lake': ('ทะเลสาบอวิ๋นหลง', 'ทะเลสาบหยุนหลงซึ่งได้ชื่อมาจาก \'มังกรเมฆ\' คือผืนน้ำกว้างราวกระจกเงาที่มีเนินเขาโอบล้อม และถือเป็นปอดสีเขียวของเมือง ด้วยทางเดินริมน้ำ โรงน้ำชา และเนินเขาที่มีวัดตั้งอยู่บนยอด ชาวสวีโจวจึงหลั่งไหลมาที่นี่ทุกช่วงเวลา ตั้งแต่ออกกำลังกายยามเช้าไปจนถึงเดินเล่นยามเย็น'),
  'xuzhou/skewer': ('วัฒนธรรมปิ้งย่าง', 'สวีโจวภูมิใจเรียกตัวเองว่าเมืองหลวงบาร์บีคิวของจีน ควันหอมจากเนื้อแกะเสียบไม้ที่หมุนอยู่บนถ่านลอยอบอวลไปตามถนนจนดึกดื่น เตาถ่านเล็ก ๆ ถูกยกมาวางถึงโต๊ะให้ทุกคนย่างไม้ของตัวเอง เป็นวัฒนธรรมโต๊ะอาหารที่ครึกครื้นและอบอุ่น สนุกกับเพื่อนฝูงไปจนค่ำมืด'),
  'zhenjiang/vinegar': ('น้ำส้มสายชูดำเจิ้นเจียง', 'น้ำส้มสายชูข้าวดำของเจิ้นเจียงได้จากการหมักข้าวเหนียวอย่างยาวนานและอดทน รสเปรี้ยวนุ่มนวลแฝงหวานอ่อน ๆ ทำให้เป็นน้ำส้มสายชูที่โด่งดังที่สุดในครัวจีน โต๊ะเกี๊ยวจะสมบูรณ์ไม่ได้หากขาดมัน — ดังที่ชาวเมืองว่ากันว่า กลิ่นน้ำส้มสายชูล่องลอยไปทั่วท้องถนนของเจิ้นเจียง'),
  'zhenjiang/temple': ('วัดจินซาน', 'วัดจินซานริมแม่น้ำแยงซีคือฉากที่เร้าใจที่สุดของตำนานนางพญางูขาว นิทานพื้นบ้านที่ชาวจีนรักที่สุด: ที่นี่เองที่ไป๋ซู่เจิน วิญญาณงูขาว บันดาลน้ำท่วมวัดเพื่อความรักของเธอ เจดีย์บนยอดเขาโอบทัศนียภาพแม่น้ำและเมืองไว้ทั้งหมด'),
  'zhenjiang/pot': ('บะหมี่ฝาหม้อ', 'สำหรับกัวก้ายเมี่ยนของเจิ้นเจียง ฝาไม้ใบเล็กจะถูกวางลอยไว้ในหม้อต้มใบใหญ่ ฝานี้กันไม่ให้น้ำเดือดล้นและทำให้เส้นบะหมี่สุกกำลังดีพอดิบพอดี เส้นบะหมี่เส้นเล็กพบกับน้ำส้มสายชูท้องถิ่นและน้ำซุปซีอิ๊ว — นี่คือวิธีเริ่มต้นวันใหม่แบบคลาสสิกของเมืองนี้'),
  'zhenjiang/bridge': ('ริมฝั่งแม่น้ำแยงซี', 'เจิ้นเจียงเป็นเมืองท่าเก่าแก่ที่ก่อตั้งขึ้น ณ จุดยุทธศาสตร์ที่แม่น้ำแยงซีบรรจบกับคลองใหญ่ เขาสามลูกริมแม่น้ำ — จินซาน เป่ยกู้ซาน และเจียวซาน — เรียงรายด้วยเจดีย์ วัด และสวนทางเดิน เปลี่ยนริมน้ำให้เป็นริบบิ้นสีเขียวแห่งวัฒนธรรม'),
  'jiaxing/zongzi': ('บ๊ะจ่าง', 'เจียซิงคือเมืองหลวงของบ๊ะจ่าง ข้าวเหนียวห่อใบไผ่นึ่งหอมกรุ่น อาหารสัญลักษณ์ของเทศกาลเรือมังกรมีขายที่นี่ตลอดทั้งปี ทั้งไส้หมู ไส้ถั่วกวน และไข่แดงเค็ม การแกะบ๊ะจ่างร้อน ๆ สักลูกเปรียบดั่งพิธีเล็ก ๆ ที่เริ่มต้นด้วยกลิ่นหอมของใบไผ่'),
  'jiaxing/boat': ('เรือแดงแห่งทะเลสาบหนานหู', 'ในปี 1921 เมื่อจำต้องออกจากเซี่ยงไฮ้ การประชุมสมัชชาครั้งแรกของพรรคคอมมิวนิสต์จีนจึงมาเสร็จสิ้นบนเรือลำหนึ่งกลางทะเลสาบหนานหูของเจียซิง เรือจำลองของ \'เรือแดง\' ลอยลำอยู่ที่นั่นจนทุกวันนี้ สายน้ำเคล้าหมอก ต้นหลิว และศาลากลางเกาะช่วยเติมความสงบเชิงประวัติศาสตร์ให้การมาเยือน'),
  'jiaxing/silk': ('เมืองแห่งผ้าไหม', 'สวนหม่อนและวัฒนธรรมการเลี้ยงไหมของแดนเจียงหนานหล่อเลี้ยงเมืองริมคลองของเจียซิงมานานหลายศตวรรษ เส้นใยที่สาวจากรังไหมกลายเป็นผ้านวม ผืนผ้า และงานปักที่นี่ ความนุ่มละมุนของแพรไหมคือของขวัญจากภูมิอากาศชุ่มน้ำอันอ่อนโยนของภูมิภาค ที่ทอดยาวจากท้องทุ่งสู่ตู้เสื้อผ้า'),
  'jiaxing/canal': ('เมืองน้ำอูเจิ้น', 'อูเจิ้นซึ่งอยู่ในอาณาบริเวณของเจียซิง เป็นหนึ่งในเมืองสายน้ำที่งดงามที่สุดของเจียงหนาน ด้วยสะพานหิน บ้านหลังคากระเบื้องดำ และบันไดที่ทอดลงสู่ลำคลอง เมื่อโคมไฟสว่างขึ้นยามพลบค่ำ ผืนน้ำก็ฉาบไปด้วยแสงสีแดง งานฝีมือเก่าแก่อย่างการย้อมครามและหนังตะลุงยังมีชีวิตอยู่ในตรอกแคบ ๆ ของเมือง'),
  'lishui/mountains': ('ยอดเขาสีเขียว', 'ลี่สุ่ยคือมุมที่เต็มไปด้วยขุนเขาที่สุดของมณฑลเจ้อเจียง หุบเขาปกคลุมด้วยหมอก ส่วนสันเขาแน่นขนัดด้วยป่าไผ่และป่าสน หมู่บ้านหินที่เกาะอยู่ตามไหล่เขาและนาขั้นบันไดที่แตะปุยเมฆ ซุกซ่อนเมืองจีนสีเขียวจังหวะเนิบช้า ห่างไกลจากความอึกทึกของมณฑลชายฝั่ง'),
  'lishui/camera': ('สวรรค์ของช่างภาพ', 'หุบเขาที่อาบหมอกยามรุ่งสาง ชาวนาที่ปรากฏตัวบนนาขั้นบันได และทะเลเมฆที่แปรเปลี่ยนไปตามแสง ทำให้ลี่สุ่ยกลายเป็นจุดหมายแสวงบุญของช่างภาพ เมืองนี้เป็นที่รู้จักจากงานถ่ายภาพระดับนานาชาติ ภาพที่โด่งดังที่สุดคือวินาทีที่นาขั้นบันไดเจิ่งน้ำเปล่งประกายสีทองยามอาทิตย์ขึ้น'),
  'lishui/mushroom': ('ดินแดนแห่งเห็ด', 'อำเภอชิงหยวนของลี่สุ่ยได้ชื่อว่าเป็นแหล่งกำเนิดของการเพาะเห็ด วิธีปลูกเห็ดหอมบนท่อนไม้ถูกคิดค้นขึ้นในขุนเขาแห่งนี้เมื่อหลายศตวรรษก่อน ทุกวันนี้ตลาดหมู่บ้านยังหอมกลิ่นเห็ดตากแห้ง และครัวท้องถิ่นก็ภาคภูมิใจกับซุปและเมนูตุ๋นที่ปรุงจากเห็ดสดจากผลผลิตใหม่'),
  'lishui/raft': ('ล่องแพไม้ไผ่', 'แม่น้ำโอวไหลคดเคี้ยวผ่านหุบเขาเขียวขจีของลี่สุ่ย การล่องแพไม้ไผ่ไปตามสายน้ำใสแจ๋วนี้คือความรื่นรมย์อันเป็นเอกลักษณ์ของภูมิภาค ขณะคนถ่อแพคัดท้ายด้วยไม้ยาว หมู่บ้านชาวประมง เนินเขาเคล้าหมอก และทิวทัศน์ราวภาพวาดพู่กันจีนก็เลื่อนผ่านไปตามสองฟากฝั่ง'),
  'anqing/opera': ('งิ้วหวงเหมย', 'งิ้วหวงเหมยถือกำเนิดจากเพลงเก็บใบชาในชนบทรอบอันชิ่ง แล้วเติบโตเป็นหนึ่งในงิ้วท้องถิ่นที่ชาวจีนรักที่สุด ท่วงทำนองเรียบง่ายลื่นไหลและเรื่องรักที่เล่าด้วยภาษาชาวบ้านถูกจดจำขับร้องกันมาหลายชั่วอายุคน — และอันชิ่งก็ยังคงนับเป็นเมืองหลวงของศิลปะแขนงนี้'),
  'anqing/pagoda': ('เจดีย์เจิ้นเฟิง', 'เจดีย์เจิ้นเฟิงที่ตั้งตระหง่านริมฝั่งแยงซีทำหน้าที่เป็นประภาคารให้ชาวเรือมาหลายศตวรรษ จนได้รับสมญา "เจดีย์องค์แรกแห่งแยงซี" หอแปดเหลี่ยมยุคราชวงศ์หมิงนี้มอบทัศนียภาพโค้งน้ำอันกว้างไกลของแม่น้ำเป็นรางวัลแก่ผู้มาเยือนที่ปีนขึ้นไปทีละชั้น'),
  'anqing/tea': ('ชาเยว่ซี', 'ไหล่เขาเย็นชุ่มหมอกของเทือกเขาต้าเปี๋ยเบื้องหลังอันชิ่งคือสวนในอุดมคติของชาเขียวหอมกรุ่น ในอำเภอเยว่ซี ยอดใบอ่อนที่เก็บด้วยมือในฤดูใบไม้ผลิให้น้ำชารสเบากลิ่นดอกไม้ — และในหมู่บ้านกลางหุบเขา การเก็บเกี่ยวชาก็ยังคงเป็นเหตุการณ์ใหญ่ที่สุดของฤดูกาล'),
  'anqing/sail': ('ประตูแม่น้ำ', 'อันชิ่ง ชื่อที่มีความหมายว่า "การเฉลิมฉลองอันสงบสุข" คือเมืองท่าประวัติศาสตร์ประตูสู่แยงซีของมณฑลอานฮุย — พยางค์ "อัน" ในชื่อมณฑลเองก็มาจากเมืองนี้ ท่าเรือริมน้ำและย่านเก่าแก่ยังคงเก็บร่องรอยของวันคืนอันคึกคักในฐานะเมืองท่าเอาไว้'),
  'ganzhou/orange': ('ส้มนาเวลก้านหนาน', 'ดินสีแดงและภูมิอากาศอบอุ่นทางใต้ของก้านโจวเพาะปลูกส้มเนเวลก้านหนาน ซึ่งนับเป็นส้มที่หวานที่สุดชนิดหนึ่งของจีน ในฤดูเก็บเกี่ยว เนินเขาจะย้อมเป็นสีส้มทั่วทั้งผืน ผลส้มฉ่ำน้ำไร้เมล็ดนี้พาชื่อของเมืองไปทั่วประเทศอย่างน่าภาคภูมิ'),
  'ganzhou/house': ('บ้านดินชาวฮากกา', 'ชาวฮากกาผู้อพยพลงมาจากทางเหนือสร้างบ้านป้อมปราการไว้ตามหมู่บ้านกลางหุบเขาของก้านโจว หลังกำแพงหนาเพื่อการป้องกัน ครอบครัวหลายสิบครัวเรือนอาศัยอยู่ใต้ชายคาเดียวกัน ภายในมีลานบ้านส่วนกลาง หอบูชาบรรพบุรุษ และวัฒนธรรมความสามัคคีอันแน่นแฟ้นที่สืบทอดมาหลายร้อยปี'),
  'ganzhou/pavilion': ('ศาลาอวี้กู', 'หอยฺวี่กูไถตั้งตระหง่านมองลงมายังจุดที่แม่น้ำจางและแม่น้ำก้งไหลมาบรรจบกันเป็นแม่น้ำก้าน หอไม้แห่งนี้เคยเป็นแรงบันดาลใจในบทกวีของกวีสมัยราชวงศ์ซ่ง ผสานทิวทัศน์สายน้ำเข้ากับประเพณีกวีนิพนธ์นับพันปี ยามแสงโพล้เพล้ที่นี่คือมุมที่ชวนรำพึงที่สุดของเมือง'),
  'ganzhou/star': ('การเดินทัพทางไกล', 'ในปี 1934 กองทัพแดงเริ่มต้นการถอยทัพครั้งยิ่งใหญ่ที่ประวัติศาสตร์จารึกไว้ในชื่อ \'การเดินทัพทางไกล\' จากอำเภออวี้ตูในก้านโจว เรื่องราวของเหล่าทหารที่ข้ามแม่น้ำตลอดทั้งคืนถูกรำลึกถึงที่นี่ด้วยอนุสาวรีย์และพิพิธภัณฑ์ เมืองนี้คือเส้นสตาร์ทของจุดเปลี่ยนสำคัญในประวัติศาสตร์จีนสมัยใหม่'),
  'putian/shrine': ('ศาลเจ้าแม่หม่าโจ้ว', 'เจ้าแม่หม่าจู่ เทพีผู้คุ้มครองชาวเรือ ถือกำเนิดที่ผู่เถียน ศาลเจ้าแม่องค์แรกตั้งตระหง่านอยู่บนเกาะเหมยโจว และถือเป็นต้นกำเนิดของศาลเจ้าแม่หม่าจู่นับพันแห่งทั่วโลก ความเชื่อและประเพณีบูชาเจ้าแม่หม่าจู่ได้รับการขึ้นทะเบียนเป็นมรดกวัฒนธรรมที่จับต้องไม่ได้ของยูเนสโก ในวันงานเทศกาล ทั้งเกาะจะคลาคล่ำไปด้วยควันธูปและผู้จาริกแสวงบุญ'),
  'putian/lychee': ('สวนลิ้นจี่', 'ผู่เถียนยังมีอีกชื่อว่า \'เมืองลิ้นจี่\' ต้นลิ้นจี่อายุหลายร้อยปียังคงออกผลและแผ่ร่มเงาให้ถนนหนทางในเมือง ผลไม้รสหวานที่เปลือกแดงระเรื่อในฤดูเก็บเกี่ยวหน้าร้อนนี้ คือของหรูแดนใต้ที่ถูกยกย่องในบทกวีคลาสสิก การได้กินลิ้นจี่สดจากต้นคือหนึ่งในความสุขที่งดงามที่สุดของฤดูร้อนในผู่เถียน'),
  'putian/shoe': ('เมืองหลวงแห่งรองเท้า', 'ผู่เถียนคือยักษ์ใหญ่ผู้เงียบขรึมของอุตสาหกรรมรองเท้ากีฬาโลก โรงงานและเวิร์กช็อปของเมืองผลิตรองเท้าหลายล้านคู่ให้แบรนด์ชั้นนำ ที่นี่การทำรองเท้าเป็นเสมือนอาชีพประจำตระกูล ตั้งแต่ช่างแม่พิมพ์ถึงช่างเย็บ ห่วงโซ่งานฝีมือทั้งสายก่อร่างเป็นครัวลับเบื้องหลังแฟชั่นกีฬาระดับโลก'),
  'putian/wave': ('เกาะเหมยโจว', 'เกาะเหมยโจวที่ไปถึงได้ด้วยเรือเฟอร์รี มีชื่อเสียงจากหาดทรายสีทอง อ่าวหินผา และงานเทศกาลศาลเจ้าแม่หม่าจู่ ในวันเฉลิมฉลองวันประสูติของเจ้าแม่ ทั้งเกาะจะคึกคักด้วยเสียงกลองและขบวนแห่ ส่วนวันธรรมดาที่นี่คือสถานที่แสวงบุญและพักผ่อนริมทะเลอันสงบ มีสายลมทะเลพัดเย็นสบาย'),
  'mudanjiang/snow': ('หมู่บ้านหิมะ', '"เมืองหิมะแห่งประเทศจีน" ใกล้มู่ตันเจียงเป็นหนึ่งในหมู่บ้านที่หิมะตกหนาที่สุดของประเทศ หมอนหิมะหนานุ่มพองฟูอยู่บนหลังคาจนเปลี่ยนบ้านเรือนเป็นกระท่อมในเทพนิยาย เมื่อโคมแดงสว่างขึ้นยามพลบค่ำ ตรอกซอยที่ปกคลุมด้วยหิมะก็เรืองรองด้วยแสงอันอบอุ่น'),
  'mudanjiang/lake': ('ทะเลสาบจิ้งปัว', 'ทะเลสาบจิ้งปั๋วเกิดจากการปะทุของภูเขาไฟยุคโบราณที่ปิดกั้นลำน้ำ นับเป็นหนึ่งในทะเลสาบเขื่อนภูเขาไฟที่ใหญ่ที่สุดของจีน น้ำในทะเลสาบไหลทะลักลงน้ำตกเตี้ยวสุ่ยโหลว ซึ่งโด่งดังจากนักกระโดดหน้าผาผู้กล้าหาญในฤดูร้อนและทิวทัศน์น้ำแข็งอันตระการตาในฤดูหนาว'),
  'mudanjiang/tiger': ('สวนเสือไซบีเรีย', 'เหิงเต้าเหอจื่อในเขตมู่ตันเจียงเป็นหนึ่งในศูนย์ชั้นแนวหน้าของโลกด้านการอนุรักษ์และเพาะพันธุ์เสือไซบีเรีย แมวใหญ่ที่สุดในบรรดาแมวทั้งปวง ผู้มาเยือนเฝ้าชมเสือเดินท่องผืนป่าอันกว้างขวางจากเส้นทางที่มีการป้องกัน และศูนย์แห่งนี้ก็เต้นเป็นหัวใจของความพยายามปกป้องอนาคตของสัตว์หายากชนิดนี้'),
  'mudanjiang/ski': ('ฤดูกาลเล่นสกี', 'ในมู่ตันเจียง ใจกลางแถบหิมะของจีน ฤดูหนาวยาวนานและหิมะตกหนาแบบแห้งฟู เนินเขาป่าไม้รอบเมืองเต็มไปด้วยนักสกีทุกฤดูกาล เส้นทางสกีที่ผนวกกับทริปเที่ยวเมืองหิมะทำให้ภูมิภาคนี้เป็นหนึ่งในศูนย์กลางท่องเที่ยวฤดูหนาวของจีนตะวันออกเฉียงเหนือ'),
  'changzhou/dino': ('สวนสนุกไดโนเสาร์', 'สวนไดโนเสาร์ฉางโจว สวนสนุกธีมไดโนเสาร์ที่โด่งดังที่สุดของจีน ผสานพิพิธภัณฑ์ฟอสซิลเข้ากับสวนสนุกเต็มรูปแบบ จนได้รับฉายาอย่างเอ็นดูว่า "จูราสสิกพาร์กแห่งเมืองจีน" ด้วยหุ่นไดโนเสาร์ยักษ์ เครื่องเล่นทางน้ำ และรถไฟเหาะ ที่นี่คือจุดหมายอันดับหนึ่งของครอบครัวในเมือง'),
  'changzhou/pagoda': ('เจดีย์เทียนหนิง', 'เจดีย์สูง 153 เมตรของวัดเทียนหนิงใจกลางเมืองได้รับการยกย่องว่าเป็นเจดีย์ที่สูงที่สุดในโลก หอที่ผงาดขึ้นจากลานของวัดซึ่งมีประวัติกว่าหนึ่งพันปีนี้ เผยให้เห็นฉางโจวทั้งเมืองและโค้งสายน้ำของคลองใหญ่จากชั้นบนสุดราวกับแผ่อยู่แทบเท้าคุณ'),
  'changzhou/comb': ('งานหัตถกรรมหวี', 'หวีฉางโจวเป็นงานฝีมือเก่าแก่หลายศตวรรษ ประดิษฐ์จากไม้เนื้อดีอย่างไม้บ็อกซ์วูดและไม้มะเกลือผ่านขั้นตอนทำมือหลายสิบขั้น หวีที่ครั้งหนึ่งเคยถวายเป็นของกำนัลแด่ราชสำนักเหล่านี้ — ด้วยลายแกะสลักอันประณีตและภาพวาดด้วยมือ — ยังคงเป็นของที่ระลึกที่งามสง่าที่สุดของเมือง'),
  'changzhou/canal': ('คลองต้ายวิ่นเหอ', 'คลองใหญ่ไหลผ่านฉางโจวมาหลายศตวรรษ และเมืองก็มั่งคั่งขึ้นจากการค้าและการทอผ้าที่สายน้ำนำมาให้ ยามเย็น ย่านเก่าริมคลองสว่างเรืองรองด้วยแสงโคม และการเดินเลียบท่าหินคือความรื่นรมย์สุดคลาสสิกของเมืองนี้'),
  'shaoxing/wine': ('เหล้าเส้าซิง', 'เหล้าเหลืองสีอำพันของเส้าซิงหมักด้วยน้ำจากทะเลสาบเจี้ยนหูในท้องถิ่น ล้ำค่าทั้งในฐานะเครื่องดื่มและเครื่องปรุงรสที่ขาดไม่ได้ในครัวจีน ตามประเพณีที่งดงามที่สุดของเมือง ไหเหล้าจะถูกฝังไว้เมื่อลูกสาวถือกำเนิด และเปิดออกในวันแต่งงานของเธอ'),
  'shaoxing/bridge': ('สะพานหินโบราณ', 'ในเส้าซิงที่ถักทอด้วยคลอง เส้นทางน้ำคึกคักไม่แพ้ถนน และด้วยสะพานหินโค้งหลายร้อยแห่ง เมืองนี้จึงได้ชื่อว่าเป็น "พิพิธภัณฑ์สะพาน" สะพานบางแห่งยืนหยัดมาหลายศตวรรษ ซุ้มโค้งหินคลุมตะไคร่ของพวกมันยังคงทอดเงาให้เรือที่ลอยผ่านเบื้องล่างจนทุกวันนี้'),
  'shaoxing/pen': ('แหล่งกำเนิดอักษรวิจิตร', 'หวังซีจือ ผู้ได้รับการเทิดทูนเป็นปรมาจารย์อักษรวิจิตรที่ยิ่งใหญ่ที่สุด เขียนผลงานชิ้นเอก "อารัมภบทศาลากล้วยไม้" ในงานสังสรรค์ท่ามกลางดงไผ่ของเส้าซิง ประเพณีลอยจอกเหล้าไปตามลำธารพลางแต่งบทกวีเริ่มต้นจากวันนั้น และศาลาแห่งนี้ก็ยังคงเป็นจุดแวะอันศักดิ์สิทธิ์ของผู้รักพู่กัน'),
  'shaoxing/boat': ('เรืออูเผิง', 'ในเรืออูเผิงหลังคาดำของเส้าซิง คนแจวจะพายด้วยเท้าพลางคัดท้ายด้วยมือ — เทคนิคอันเป็นเอกลักษณ์ที่สืบทอดกันมาหลายชั่วอายุคน เรือเหล่านี้ลอยลอดใต้สะพานหินไปตามคลองแคบ และยังแล่นอยู่ในความทรงจำวัยเยาว์ของหลู่ซวิ่น นักเขียนเลื่องชื่อที่เมืองนี้ฟูมฟักขึ้นมา'),
  'bengbu/shell': ('ท่าเรือไข่มุก', 'ชื่อเปิ้งปู้มีความหมายว่า "ท่าหอยมุก" และริมฝั่งแม่น้ำหวยช่วงนี้ครั้งหนึ่งเคยเลื่องชื่อเรื่องนักงมไข่มุกน้ำจืด ไข่มุกยังคงเป็นสัญลักษณ์ของเมืองจนทุกวันนี้ ปรากฏอยู่ทุกหนแห่ง ตั้งแต่รูปปั้นกลางเมืองไปจนถึงตราประจำเทศบาล'),
  'bengbu/train': ('สถานีรถไฟเปิ่งปู้', 'เปิ้งปู้เติบโตจากเมืองเล็ก ๆ เป็นเมืองใหญ่ ณ จุดที่ทางรถไฟสายเทียนจิน-ผู่โข่วข้ามแม่น้ำหวย ประตูบนเส้นทางเหนือ-ใต้สายนี้ยังคงเชื่อมอานฮุยตอนเหนือเข้ากับโครงข่ายคมนาคมหลักของประเทศจนทุกวันนี้'),
  'bengbu/river': ('แม่น้ำหวย', 'แม่น้ำหวยถือเป็นเส้นแบ่งตามธรรมชาติระหว่างจีนเหนือกับจีนใต้: ทางเหนือของแม่น้ำปลูกข้าวสาลี ทางใต้ปลูกข้าวเจ้า และระบบทำความร้อนส่วนกลางในฤดูหนาวก็สิ้นสุดลงที่ริมฝั่งของมัน เปิ้งปู้ใช้ชีวิตอยู่บนเส้นเปลี่ยนผ่านนี้พอดี ท่ามกลางสองภูมิอากาศและสองสำรับอาหาร'),
  'bengbu/blossom': ('เทศกาลชมดอกไม้', 'ในฤดูใบไม้ผลิ สวนสาธารณะริมแม่น้ำหวยผลิบานสะพรั่ง และชาวเปิ้งปู้ก็ใช้วันหยุดสุดสัปดาห์ริมน้ำกับการปิกนิกและงานชมดอกไม้ สวนจางกงซานริมทะเลสาบกลายเป็นจุดนัดพบที่คึกคักที่สุดของเมืองเมื่อต้นซากุระและต้นท้อผลิดอก'),
  'jiujiang/mountain': ('เขาหลูซาน', 'ภูเขาหลูที่ผงาดขึ้นระหว่างแม่น้ำแยงซีกับทะเลสาบผัวหยาง คือขุนเขาที่เปี่ยมบทกวีที่สุดของจีน — ยอดเขาห่มหมอก น้ำตก และที่ราบสูงเย็นสบาย ซึ่งได้รับการขึ้นทะเบียนเป็นมรดกโลกยูเนสโก จากบทกวีถึงน้ำตกของหลี่ไป๋จนถึงวิลล่าหินของเมืองกู่หลิ่งบนไหล่เขา ทุกซอกทุกมุมล้วนมีเรื่องเล่า'),
  'jiujiang/tea': ('ชาอวิ๋นอู้', 'ชาหยุนอู้ ("เมฆหมอก") ที่ปลูกบนไหล่เขาห่มเมฆของภูเขาหลู ติดอันดับชาเขียวเลื่องชื่อของจีน ความชุ่มชื้นของขุนเขาและแสงแดดที่กรองผ่านหมอกมอบกลิ่นหอมสดชื่นหวานละมุนแก่ใบชา ยอดอ่อนแรกของฤดูใบไม้ผลิเก็บด้วยมือและได้รับการยกย่องว่าเป็นผลผลิตชั้นเลิศที่สุด'),
  'jiujiang/lake': ('ทะเลสาบโผหยาง', 'ผัวหยาง ทะเลสาบน้ำจืดที่ใหญ่ที่สุดของจีน บรรจบกับแม่น้ำแยงซีอยู่ข้างจิ่วเจียงพอดี ผืนน้ำของมันขยายและหดตัวไปตามฤดูกาล และทุ่งหญ้าชุ่มน้ำที่เผยตัวในฤดูหนาวก็ต้อนรับนกอพยพนับหมื่นตัว — ในจำนวนนั้นมีนกกระเรียนไซบีเรียอันหายากรวมอยู่ด้วย'),
  'jiujiang/scroll': ('เมืองแห่งบทกวี', 'เมืองท่าเก่าริมแยงซีแห่งนี้เคยต้อนรับกวีนามอุโฆษของจีน: ไป๋จวีอี้เขียน "เพลงผีผา" อันโด่งดังของเขาขึ้นที่นี่ โดยได้แรงบันดาลใจจากท่วงทำนองที่ได้ยินบนแม่น้ำ จิ่วเจียงที่ยืนอยู่ในร่มเงาของภูเขาหลู เป็นหนึ่งในประตูแม่น้ำที่ถูกเอ่ยชื่อบ่อยที่สุดในบทกวี'),
  'quanzhou/ship': ('เส้นทางสายไหมทางทะเล', 'เฉวียนโจว ที่โลกยุคกลางรู้จักในชื่อ "ไซตัน" เคยเป็นท่าเรือที่ยิ่งใหญ่ที่สุดของเส้นทางสายไหมทางทะเล — มาร์โค โปโลบรรยายว่าเป็นหนึ่งในท่าเรือที่พลุกพล่านที่สุดในโลก ด้วยมัสยิด วัด และโบสถ์ที่ตั้งเคียงข้างกัน มรดกอันหลากวัฒนธรรมนี้ทำให้เมืองได้รับการขึ้นทะเบียนเป็นมรดกโลกยูเนสโก'),
  'quanzhou/mosque': ('มัสยิดชิงจิ้ง', 'มัสยิดชิงจิ้งก่อตั้งโดยพ่อค้าชาวอาหรับในปี 1009 นับเป็นหนึ่งในมัสยิดเก่าแก่ที่สุดของจีนที่ยังคงเหลืออยู่ ประตูหินแกรนิตและกำแพงหินที่ได้แรงบันดาลใจจากสถาปัตยกรรมตะวันออกกลาง เป็นประจักษ์พยานว่าท่าเรือเฉวียนโจวในยุคเส้นทางสายไหมทางทะเลนั้นหลากหลายศาสนาและเป็นสากลเพียงใด'),
  'quanzhou/puppet': ('หุ่นเชิดฉวนโจว', 'ในศิลปะหุ่นชักของเฉวียนโจว ปรมาจารย์เสกชีวิตให้หุ่นไม้ด้วยการควบคุมเส้นด้ายเส้นเล็กหลายสิบเส้นพร้อมกัน — หุ่นสามารถเขียนพู่กันหรือชักดาบประลองกันได้ ประเพณีพันปีนี้ยังคงเป็นแขกเกียรติยศของงานวัดและเวทีการแสดงในเทศกาลต่าง ๆ'),
  'quanzhou/tea': ('ชาทิกวนอิม', 'อำเภอภูเขาอันซีในเฉวียนโจวคือบ้านเกิดของเถี่ยกวนอิน "เจ้าแม่กวนอิมเหล็ก" — ชาอู่หลงที่โด่งดังที่สุดในโลก ใบชากึ่งหมักของมันคลี่ตัวออกพร้อมกลิ่นหอมคล้ายกล้วยไม้ และพิธีชงชากงฟูด้วยจอกใบจิ๋วก็คือชีวิตประจำวันธรรมดา ๆ ของที่นี่'),
  'shanghai/pearl': ('หอไข่มุกตะวันออก', 'หอคอยทรงกลมสีชมพูที่ตั้งตระหง่านในย่านลู่เจียจุ่ยของเขตผู่ตง คือเส้นขอบฟ้าอันเป็นที่จดจำที่สุดของเซี่ยงไฮ้ยุคใหม่ จากชั้นชมวิวพื้นกระจก แม่น้ำหวงผู่และหาดไว่ทานบนฝั่งตรงข้ามทอดตัวอยู่เบื้องล่าง และยามค่ำคืนแสงสีของหอคอยก็ระยิบระยับบนผืนน้ำ'),
  'shanghai/bund': ('เดอะบันด์', 'อาคารธนาคารและโรงแรมเก่าแก่ที่เรียงรายริมแม่น้ำหวงผู่ยังคงความโอ่อ่าจากยุคที่เซี่ยงไฮ้เป็นเมืองท่าระดับโลก ยามเดินเล่นตอนเย็น ด้านหนึ่งคืออาคารการค้าเก่าประดับเสาหิน อีกด้านคือตึกระฟ้าของผู่ตงที่ส่องประกาย สองศตวรรษมาบรรจบกันในชั่วสายตาเดียว'),
  'shanghai/garden': ('สวนอวี้หยวน', 'สวนคลาสสิกสมัยราชวงศ์หมิงแห่งนี้ ด้วยภูเขาหินจำลอง สระน้ำ และสะพานซิกแซ็ก เป็นดั่งโอเอซิสใจกลางเมือง ตลาดรอบสวนคึกคักด้วยโรงน้ำชาและแผงขายของว่าง ขณะที่เบื้องหลังกำแพงประดับหัวมังกรซ่อนศิลปะการจัดสวนอันประณีตแบบเจียงหนานเอาไว้'),
  'shanghai/xlb': ('เสี่ยวหลงเปา', 'เสี่ยวหลงเปา เกี๊ยวแป้งบางที่กักเก็บน้ำซุปร้อน ๆ ไว้ข้างใน คือผลงานชิ้นเอกของอาหารเซี่ยงไฮ้ วิธีกินคือกัดขอบเบา ๆ เพื่อจิบน้ำซุปก่อน แล้วจึงจิ้มกับน้ำส้มดำใส่ขิง ทุกเช้าไอน้ำจากเข่งไม้ไผ่จะอบอวลไปทั่วท้องถนนของเมือง'),
  'hangzhou/lake': ('ทะเลสาบซีหู', 'ทะเลสาบซีหู ด้วยต้นหลิว เกาะน้อยใหญ่ และสะพานโค้ง คือภูมิทัศน์ที่ถูกยกย่องมากที่สุดในบทกวีจีน และเป็นมรดกโลกของยูเนสโก การเดินเล่นบนคันดินซูตีและไป๋ตีเป็นธรรมเนียมมาหลายศตวรรษ ส่วนสะพานขาดนั้นเล่าขานกันว่าเป็นจุดนัดพบของคู่รักในตำนานนางพญางูขาว'),
  'hangzhou/tea': ('ชาหลงจิ่ง', 'ชาเขียว \'หลงจิ่ง\' หรือ \'บ่อมังกร\' ที่ปลูกบนเนินเขารอบทะเลสาบ คือชาที่มีชื่อเสียงที่สุดของจีน ใบชาแบนราบยังคงถูกคั่วขึ้นรูปด้วยมือในกระทะร้อน และผลผลิตต้นฤดูใบไม้ผลิถือว่าล้ำค่าเหนือสิ่งอื่นใด ชาหลงจิ่งสักถ้วยในโรงน้ำชากลางหมู่บ้านมอบจิตวิญญาณแท้ ๆ ของหางโจว'),
  'hangzhou/temple': ('วัดหลิงอิ่น', 'วัดหลิงอิ่น \'อารามแห่งการเร้นกายของวิญญาณ\' เป็นหนึ่งในวัดพุทธที่เก่าแก่ที่สุดของจีน ฝั่งตรงข้ามคือยอดเขาเฟยไหลซึ่งมีพระพุทธรูปหลายร้อยองค์ถูกแกะสลักลงบนหน้าผาตลอดหลายศตวรรษ การเดินท่ามกลางควันธูปและร่มเงาต้นสนทำให้ลืมความอึกทึกของเมืองไปสิ้น'),
  'hangzhou/silk': ('เมืองผ้าไหม', 'ผ้าไหมหางโจวถูกถักทอมานานกว่าพันปี และเมืองนี้เคยเป็นสัญลักษณ์ของความมั่งคั่ง ณ ปลายทางตะวันออกของเส้นทางสายไหม ทุกวันนี้ผ้าผืน ผ้าพันคอ และงานปักเปลี่ยนมือกันในตลาดผ้าไหม ส่วนพิพิธภัณฑ์ผ้าไหมก็บอกเล่าการเดินทางจากรังไหมสู่กี่ทอ ด้วยสัมผัสอันนุ่มนวล ผ้าไหมหางโจวยังคงเป็นของขวัญที่งามสง่าที่สุด'),
  'chongqing/hongya': ('ถ้ำหงหยา', 'หงหยาต้ง กลุ่มบ้านไม้ยกเสาสูงแบบดั้งเดิมที่เกาะอยู่บนหน้าผา ยังคงรักษาสถาปัตยกรรมเก่าแก่ของเมืองภูเขาแห่งนี้เอาไว้ เมื่ออาคารซ้อนชั้นสว่างไสวยามค่ำคืน มันเปล่งประกายราวเทพนิยายเหนือแม่น้ำเจียหลิง และตรอกแคบ ๆ ข้างในก็อัดแน่นด้วยของกินพื้นเมืองและร้านงานฝีมือ'),
  'chongqing/hotpot': ('หม่าล่าหม้อไฟฉงชิ่ง', 'หม้อไฟที่เดือดพล่านด้วยน้ำมันพริกแดงฉานและพริกหอมเสฉวนที่ทำให้ลิ้นชา คือจิตวิญญาณอันร้อนแรงของฉงชิ่ง ตำนานเล่าว่ามันถือกำเนิดจากหม้อต้มของกรรมกรแบกหามตามท่าเรือริมแม่น้ำ ทุกคำที่จุ่มลงในหม้อเก้าช่องกลางโต๊ะจะกลายเป็นบทสนทนายาวนานที่แบ่งปันกับเพื่อนฝูง'),
  'chongqing/monorail': ('รถไฟฟ้ารางเดี่ยว', 'ในฉงชิ่งเมืองแห่งเนินเขา เส้นทางรถไฟฟ้าพาดข้ามหุบเขา และที่สถานีหนึ่ง รถไฟยังแล่นทะลุผ่านตัวอาคารอพาร์ตเมนต์อย่างเลื่องชื่อ ภาพนั้นกลายเป็นทิวทัศน์ประจำเมืองไปแล้ว ด้วยทางลาดชัน ลิฟต์ และสะพานมากมาย \'เมืองภูเขา\' แห่งนี้ท้าทายตรรกะแบนราบของแผนที่'),
  'chongqing/river': ('ช่องเขาแยงซี', 'ตัวเมืองตั้งตระหง่านตรงจุดที่แม่น้ำแยงซีบรรจบกับแม่น้ำเจียหลิง และเรือสำราญล่องช่องแคบสามผา (ซานเสีย) ก็ออกเดินทางจากท่าเรือเฉาเทียนเหมิน ขณะเรือแล่นผ่านหน้าผาสูงชัน ประวัติศาสตร์การค้าและบทกวีนับพันปีของแม่น้ำสายยิ่งใหญ่ที่สุดของจีนก็ไหลผ่านสายตาของคุณ'),
  'dalian/square': ('จัตุรัสซิงไห่', 'จัตุรัสซิงไห่ที่เปิดออกสู่ทะเล เป็นหนึ่งในจัตุรัสกลางเมืองที่ใหญ่ที่สุดในโลก และได้ชื่อมาจาก \'ทะเลแห่งดวงดาว\' ว่าวลอยละลิ่วเหนือสนามหญ้ากว้าง นักปั่นจักรยานแล่นไปตามถนนเลียบชายฝั่งยามเย็น และในช่วงเทศกาล จัตุรัสก็เนืองแน่นล้นหลามด้วยคอนเสิร์ตและการแสดง'),
  'dalian/beach': ('ชายหาดต้าเหลียน', 'ด้วยอ่าวหิน หาดทรายสะอาด และฤดูร้อนอันเย็นสบาย ต้าเหลียนคือเมืองตากอากาศริมทะเลยอดนิยมของจีนตอนเหนือ ถนนปินไห่ที่เลื้อยไปตามชายฝั่งมอบทิวทัศน์ชวนตะลึงระหว่างหน้าผากับอ่าวน้อยใหญ่ เมื่อความร้อนแผดเผา ชาวเหนือก็พากันมาสูดอากาศทะเลที่นี่'),
  'dalian/football': ('เมืองแห่งฟุตบอล', 'ต้าเหลียนได้ชื่อว่าเป็น \'อู่ฟุตบอล\' ของจีน สโมสรแชมป์ที่ครองลีกระดับชาติและนักเตะทีมชาติจำนวนนับไม่ถ้วนล้วนมาจากเมืองนี้ เด็ก ๆ ที่วิ่งไล่ลูกบอลในสวนริมทะเลสืบสานประเพณีต่อไป และในวันแข่งขัน ทั้งเมืองก็กลายเป็นอัฒจันทร์ที่เต้นเป็นจังหวะเดียวกัน'),
  'dalian/seafood': ('อาหารทะเล', 'ทะเลเหลืองอันหนาวเย็นและใสสะอาดส่งหอยเชลล์ กุ้ง หอยเม่น และปลิงทะเลขึ้นสู่โต๊ะอาหารของต้าเหลียน ในร้านอาหารริมฝั่ง คุณเลือกวัตถุดิบจากตู้เลี้ยงได้เอง แล้วมันจะถูกนึ่งเสร็จภายในไม่กี่นาที ส่วนกลิ่นปลาหมึกย่างหอมกรุ่นก็คือหัวใจของตลาดกลางคืน'),
  'shenyang/palace': ('พระราชวังมุกเดน', 'พระราชวังมุกเดน สร้างโดยผู้ก่อตั้งราชวงศ์ชิง เป็นที่ประทับแห่งแรกก่อนราชสำนักย้ายไปปักกิ่ง แม้มักถูกเรียกว่าน้องเล็กของพระราชวังต้องห้าม แต่ก็มีเอกลักษณ์เฉพาะตัวด้วยท้องพระโรงแปดเหลี่ยมกลิ่นอายแมนจู ปัจจุบันเป็นพิพิธภัณฑ์ที่ขึ้นทะเบียนมรดกโลกยูเนสโก'),
  'shenyang/tomb': ('สุสานราชวงศ์ชิง', 'สุสานตะวันออกและสุสานเหนือที่โอบล้อมเมือง คือสุสานอนุสรณ์ของปฐมกษัตริย์แห่งราชวงศ์ชิง และได้รับการขึ้นทะเบียนเป็นมรดกโลกยูเนสโก ทางเดินศักดิ์สิทธิ์เรียงรายด้วยรูปสลักสัตว์หินทอดผ่านป่าสนโบราณ และในฤดูใบไม้ร่วง อุทยานสุสานก็เปลี่ยนเป็นสีทองอร่าม'),
  'shenyang/factory': ('แหล่งกำเนิดอุตสาหกรรม', 'อุตสาหกรรมหนักของจีนส่วนใหญ่ถือกำเนิดที่เสิ่นหยาง โรงงานเครื่องจักรขนาดมหึมาทำให้เมืองได้ฉายา \'รูห์รแห่งตะวันออก\' โรงงานเก่าในเขตเถี่ยซีกำลังกลายเป็นพิพิธภัณฑ์และพื้นที่ศิลปะ ทว่าความภาคภูมิใจของคนหลายรุ่นที่เคยยืนหน้าเครื่องกลึงยังคงลอยอยู่ในอากาศ'),
  'shenyang/dumpling': ('เกี๊ยวเหล่าเปียน', 'เกี๊ยวนึ่งเหล่าเปียน ซึ่งทำกันมาตั้งแต่สมัยราชวงศ์ชิง คือจานประจำตัวของโต๊ะอาหารภาคเหนือ การนำไส้ไปปรุงสุกก่อนจนดูดซับน้ำหวานของตัวเองทำให้เกี๊ยวนุ่มละมุนอย่างหาใครเทียบ เกี๊ยวสักเข่งในภัตตาคารเก่าแก่ของเมืองแทบจะเป็นการต้อนรับอย่างเป็นทางการของเสิ่นหยาง'),
  'hefei/judge': ('ศาลท่านเปา', 'เปาเจิ่ง ตุลาการในตำนานแห่งราชวงศ์ซ่ง ผู้ที่ชาวไทยรู้จักกันดีในนาม \'เปาบุ้นจิ้น\' ถือกำเนิดที่เหอเฝย์ ผู้คนเรียกท่านว่า \'เปาชิงเทียน\' หมายถึงท้องฟ้าอันไร้มลทิน ความยุติธรรมที่ไม่ยอมก้มหัวให้สินบนของท่านเป็นแรงบันดาลใจให้ทั้งงิ้วและละครโทรทัศน์ อุทยานอนุสรณ์ริมทะเลสาบของท่านให้ความรู้สึกดั่งวิหารที่อุทิศแด่ความซื่อตรง'),
  'hefei/science': ('เมืองแห่งวิทยาศาสตร์', 'เหอเฝย์คือเมืองวิทยาศาสตร์ที่เป็นที่ตั้งของมหาวิทยาลัยและห้องปฏิบัติการชั้นนำของจีน โครงการวิจัยตั้งแต่การทดลองฟิวชันไปจนถึงการวิจัยควอนตัมล้วนดำเนินการที่นี่ วิทยาเขตและอุทยานเทคโนโลยีมอบจิตวิญญาณอันเยาว์วัยและใฝ่รู้ให้แก่เมือง'),
  'hefei/lake': ('ทะเลสาบเฉาหู', 'เฉาหูเป็นหนึ่งในห้าทะเลสาบน้ำจืดอันยิ่งใหญ่ของจีน ทอดตัวอยู่ทางใต้ของเหอเฝย์ ปลาเงิน กุ้งขาว และปูของทะเลสาบได้ชื่อว่าเป็น \'สามสมบัติ\' ในเมืองเล็ก ๆ ริมฝั่ง เรือประมงและโรงน้ำชาวิวทะเลสาบมอบจังหวะชีวิตที่เนิบช้าและผ่อนคลาย'),
  'hefei/cake': ('ขนมเปี๊ยะงาหลูโจว', 'ชื่อเดิมของเหอเฝย์คือหลูโจว และขนมงาไส้หวานก็เป็นของว่างเก่าแก่ที่สืบทอดชื่อนั้นมา กลิ่นหอมของงาคั่วผสานกับไส้นุ่มภายใต้เปลือกกรอบ ในช่วงเทศกาล ขนมชนิดนี้ครองตำแหน่งเด่นที่สุดในกล่องของขวัญเสมอ'),
  'foshan/wingchun': ('มวยหย่งชุน', 'ศิลปะการต่อสู้หย่งชุน (วิงชุน) เติบใหญ่จนสุกงอมที่ฝอซาน ปรมาจารย์ยิปมันในตำนานฝึกฝนวิชาที่นี่ และมรดกนี้ก็แพร่ไปทั่วโลกผ่านศิษย์ของท่านอย่างบรูซ ลี หออนุสรณ์และสำนักศิลปะการต่อสู้ในเมืองยังสืบสานประเพณี ภาพปรมาจารย์รำมวยในสวนยามเช้าเป็นสิ่งที่พบเห็นได้ทุกวัน'),
  'foshan/lion': ('เชิดสิงโต', 'ฝอซานคือเมืองหลวงของการเชิดสิงโตแบบใต้ และหวงเฟยหง วีรบุรุษพื้นบ้านชื่อดัง ก็มาจากดินแดนแถบนี้เช่นกัน ในงานเทศกาล สิงโตหลากสีสันกระโดดข้ามเสาสูงตามจังหวะกลอง ส่วนการประดิษฐ์หัวสิงโตก็เป็นงานหัตถศิลป์อันประณีตที่ส่งต่อจากรุ่นสู่รุ่น'),
  'foshan/ceramic': ('เครื่องปั้นดินเผาฉือวาน', 'เตาเผาเครื่องปั้นดินเผาของสือวานลุกโชนไม่เคยดับมาหลายศตวรรษ เตาหนานเฟิงเป็นหนึ่งในเตาฟืนที่เก่าแก่ที่สุดของจีนที่ยังใช้งานอยู่ ด้วยตุ๊กตาดินเผาสีหน้าท่าทางมีชีวิตชีวาและเครื่องประดับหลังคาเคลือบเงา เซรามิกสือวานถึงกับประดับอยู่บนหลังคาวัดวาอารามทั่วมณฑลกวางตุ้ง'),
  'foshan/opera': ('งิ้วกวางตุ้ง', 'งิ้วกวางตุ้ง ศิลปะการแสดงอันเป็นที่รักที่สุดของจีนตอนใต้ เติบโตเต็มวัยบนผืนดินแห่งนี้ ครั้งหนึ่งคณะงิ้วเคยล่อง \'เรือแดง\' ไปทั่วสามเหลี่ยมปากแม่น้ำจูเจียง เปิดการแสดงจากหมู่บ้านสู่หมู่บ้าน เครื่องแต่งกายวิจิตร กายกรรม และท่วงทำนองภาษากวางตุ้งยังคงทำให้โรงงิ้วเนืองแน่นจนทุกวันนี้'),
  'guiyang/pavilion': ('ศาลาเจี่ยซิ่ว', 'หอเจี๋ยซิ่วสามชั้นที่ตั้งอยู่บนโขดหินกลางแม่น้ำหนานหมิง เป็นสัญลักษณ์ของเมืองมาตั้งแต่สมัยราชวงศ์หมิง ชื่อของมันหมายถึง \'บัณฑิตอันดับหนึ่ง\' สร้างขึ้นด้วยความหวังให้เมืองผลิตปราชญ์ผู้สอบขุนนางได้สำเร็จ เมื่อแสงไฟกระทบผืนน้ำยามค่ำคืน ทิวทัศน์ที่งามสง่าที่สุดของกุ้ยหยางก็ถือกำเนิดขึ้น'),
  'guiyang/sourfish': ('ต้มปลาซุปเปรี้ยว', 'ปลาต้มซุปเปรี้ยวคือจานประจำตัวของกุ้ยโจว หยั่งรากในประเพณีการหมักดองของชาวเหมียว ปลาน้ำจืดถูกเคี่ยวในน้ำซุปสีแดงสดที่เปรี้ยวด้วยมะเขือเทศและข้าวหมัก การเริงระบำของรสเปรี้ยว เผ็ด และเครื่องหอมนั้นเข้ากับภูมิอากาศของแดนใต้อันเต็มไปด้วยขุนเขาอย่างลงตัว'),
  'guiyang/waterfall': ('น้ำตกหวงกั่วซู่', 'น้ำตกหวงกั่วซู่ซึ่งเดินทางไปได้จากกุ้ยหยาง เป็นหนึ่งในน้ำตกที่ใหญ่ที่สุดของเอเชีย คุณสามารถเดินลอด \'ถ้ำม่านน้ำ\' ด้านหลังม่านน้ำที่โถมซัดคำราม และละอองน้ำก็สาดสายรุ้งขึ้นกลางแสงแดด ในฤดูฝน เสียงกึกก้องของมันดังไปไกลหลายกิโลเมตรตลอดหุบเขา'),
  'guiyang/miao': ('วัฒนธรรมชาวม้ง', 'หมู่บ้านกลางขุนเขาของกุ้ยโจวคือบ้านของชาวเหมียว ผู้เลื่องชื่อเรื่องเครื่องประดับศีรษะเงิน ในงานเทศกาล หญิงสาวสวมมงกุฎเงินทำมือและอาภรณ์ปักลวดลาย ผู้คนล้อมวงเต้นรำตามท่วงทำนองแคนหลูเซิง ส่วนผ้าบาติกและงานปักคือภาษาที่ส่งต่อจากแม่สู่ลูกสาว'),
  'changchun/film': ('เมืองแห่งภาพยนตร์', 'สตูดิโอภาพยนตร์ฉางชุนคือแหล่งกำเนิดวงการภาพยนตร์ของจีนยุคใหม่ ภาพยนตร์คลาสสิกของประเทศหลายชั่วอายุคนถ่ายทำกันที่นี่ เมืองนี้จึงได้ชื่อว่าเป็น \'ฮอลลีวูดแห่งตะวันออก\' โรงถ่ายเก่ากลายเป็นสวนสนุกธีมภาพยนตร์ไปแล้ว ขณะที่ประเพณีเทศกาลภาพยนตร์ยังคงดำเนินต่อไป'),
  'changchun/car': ('เมืองแห่งยานยนต์', 'รถบรรทุกคันแรกและรถยนต์คันแรกที่จีนผลิตเองแล่นออกจากโรงงานของฉางชุน และรถลีมูซีนหงฉีที่ใช้รับส่งประมุขแห่งรัฐก็ผลิตที่นี่เช่นกัน ฉายา \'เมืองยานยนต์\' จึงไม่ได้มาโดยบังเอิญ ด้วยโรงงาน พิพิธภัณฑ์ และงานแสดงรถ วัฒนธรรมรถยนต์คือตัวตนแท้จริงของเมืองนี้'),
  'changchun/palace': ('พระราชวังหุ่นเชิด', 'ผู่อี๋ จักรพรรดิองค์สุดท้ายของจีน เคยพำนักในพระราชวังแห่งนี้ในฐานะผู้ปกครองหุ่นเชิดยุคแมนจูกัว ปัจจุบันวังกลายเป็นพิพิธภัณฑ์ที่บอกเล่าการถูกจับตามองและความโดดเดี่ยวเบื้องหลังท้องพระโรงอันโอ่อ่า พระราชวังแห่งนี้คือหน้าต่างเงียบงันที่เปิดสู่ความปั่นป่วนของศตวรรษที่ยี่สิบ'),
  'changchun/snow': ('หิมะฤดูหนาว', 'ฤดูหนาวอันยาวนานและขาวโพลนของฉางชุนเปลี่ยนเมืองให้กลายเป็นเทศกาลหิมะ ประติมากรรมน้ำแข็งเรืองรองด้วยแสงไฟหลากสียามค่ำคืน และทะเลสาบกลางป่าจิ้งเยว่ถานก็ต้อนรับนักเล่นสกีและนักเล่นเลื่อนหิมะ แม้อากาศจะหนาวเหน็บ ฤดูหนาวที่นี่กลับเป็นฤดูที่รื่นเริงที่สุดของปี'),
  'xining/lake': ('ทะเลสาบชิงไห่', 'ทะเลสาบชิงไห่คือทะเลสาบที่ใหญ่ที่สุดของจีน ทอดตัวดั่งทะเลสีเทอร์ควอยซ์กลางที่ราบสูง ในฤดูร้อน ชายฝั่งถูกห่มคลุมด้วยทุ่งดอกอิ๋วไช่สีเหลืองทอง และนกอพยพก็ลงเกาะพักตามเกาะแก่ง การปั่นจักรยานรอบทะเลสาบคือการผจญภัยบนที่ราบสูงสุดโปรดของนักเดินทาง'),
  'xining/monastery': ('วัดถ่าเอ๋อร์', 'อารามคุมบุม (วัดถาเอ่อร์) เป็นหนึ่งในอารามที่ยิ่งใหญ่ที่สุดของพุทธศาสนาแบบทิเบต ตั้งตระหง่าน ณ สถานที่ประสูติของพระซงคาปา ผู้ก่อตั้งนิกายเกลุก ประติมากรรมเนยจามรีหลากสี จิตรกรรมฝาผนัง และงานผ้าปะติดของที่นี่เลื่องชื่อในนาม \'สามศิลปะ\' และในลานวัด กงล้อมนตร์ของผู้แสวงบุญก็ไม่เคยหยุดหมุน'),
  'xining/flower': ('ดอกเรปซีด', 'เมื่อเดือนกรกฎาคมมาถึง ที่ราบสูงชิงไห่ก็ถูกปกคลุมด้วยดอกอิ๋วไช่สีเหลืองทองไปจนสุดขอบฟ้า ริมทะเลสาบและตีนเขาพลิ้วไหวเป็นสีเหลืองนับพันเฉด ท่ามกลางอากาศเย็นสบายของที่ราบสูง ภาพตระการตานี้ดึงดูดช่างภาพและคู่ฮันนีมูนมาเยือนปีแล้วปีเล่า'),
  'xining/lamb': ('เนื้อจามรีและเนื้อแกะ', 'โต๊ะอาหารของซีหนิงคือจุดนัดพบของอาหารชาวหุยและชาวทิเบต บะหมี่ดึงมือเสิร์ฟในชามร้อนควันฉุย เนื้อแกะเสียบไม้ส่งเสียงเปรี๊ยะบนถ่านไฟ ส่วนโยเกิร์ตจามรีและชาเนยคือรสชาติประจำวันของที่ราบสูง ยามค่ำคืนตลาดก็อบอวลด้วยกลิ่นเครื่องเทศ'),
  'guilin/karst': ('เขาหินปูนแม่น้ำหลี', 'แม่น้ำหลีเจียงคดเคี้ยวไประหว่างยอดเขาหินปูนที่โผล่พ้นสายหมอก ภาพนี้เองที่ถูกพิมพ์อยู่บนธนบัตร 20 หยวน เรือที่ล่องจากกุ้ยหลินสู่หยางซั่ว แพไม้ไผ่ และชาวประมงนกกาน้ำ ประกอบกันเป็นภาพวาดจีนที่มีชีวิต'),
  'guilin/elephant': ('เขาช้างงวง', 'โขดหินที่ดูราวช้างกำลังหย่อนงวงลงดื่มน้ำในแม่น้ำหลีเจียง คือสัญลักษณ์อันเป็นที่รักที่สุดของกุ้ยหลิน ช่องโค้งระหว่างงวงกับลำตัวสะท้อนบนผืนน้ำดูดั่งจันทร์เต็มดวง จึงได้ชื่อว่า \'ถ้ำน้ำและจันทรา\' เหล่ากวีร้อยเรียงทิวทัศน์นี้เป็นบทกวีมาแล้วหลายศตวรรษ'),
  'guilin/terrace': ('นาขั้นบันไดหลงจี๋', 'นาขั้นบันไดหลงจี๋ หรือ \'กระดูกสันหลังมังกร\' ที่โอบสันเขาไล่เป็นชั้น ๆ คือผลงานจากหยาดเหงื่อหลายศตวรรษของชาวจ้วงและชาวเหยา ฤดูใบไม้ผลิ ผืนนาที่เจิ่งน้ำเปล่งประกายดั่งกระจกเงา ฤดูใบไม้ร่วงก็เปลี่ยนเป็นสีทอง ส่วนหมู่บ้านเรือนไม้บนที่สูงยังคงดำเนินวิถีชีวิตดั้งเดิม'),
  'guilin/osmanthus': ('ดอกหอมหมื่นลี้', 'ชื่อของกุ้ยหลินหมายถึง \'ป่าดอกหอมหมื่นลี้\' และในฤดูใบไม้ร่วง ทั้งเมืองก็อาบไปด้วยกลิ่นหอมหวานของดอกไม้จิ๋วเหล่านี้ ชา เหล้า และขนมหวานจากดอกหอมหมื่นลี้ครองอันดับต้นของของอร่อยท้องถิ่น การเดินเล่นใต้แมกไม้หอมกรุ่นริมแม่น้ำคือพิธีกรรมที่งดงามที่สุดของฤดูกาล'),
  'wenzhou/merchant': ('จิตวิญญาณนักธุรกิจ', 'ชาวเวินโจวเลื่องชื่อว่าเป็นหนึ่งในชุมชนนักธุรกิจที่กล้าได้กล้าเสียที่สุดของจีน พวกเขาสร้างสะพานการค้าจากยุโรปถึงทวีปอเมริกาผ่านเครือข่ายครอบครัวและคนบ้านเดียวกัน ในฐานะผู้บุกเบิกธุรกิจเอกชนในยุคปฏิรูป เมืองนี้เต็มไปด้วยเรื่องราวที่ทอดยาวจากโรงงานเล็ก ๆ สู่ตลาดโลก'),
  'wenzhou/shoe': ('รองเท้าและเครื่องหนัง', 'เวินโจวถือเป็นเมืองหลวงรองเท้าและเครื่องหนังของจีน รองเท้าหนังส่วนใหญ่ของโลกออกเดินทางจากเมืองโรงงานแห่งนี้ ด้วยความเชี่ยวชาญในสินค้าชิ้นเล็กตั้งแต่ไฟแช็กจนถึงแว่นตา เมืองนี้ยังคงจิตวิญญาณช่างฝีมือแห่งยุคที่ทุกบ้านคือโรงงานเล็ก ๆ'),
  'wenzhou/mountain': ('เขาเยี่ยนตั่ง', 'เทือกเขาหยานตั้งที่เลื่องชื่อด้วยน้ำตกและยอดเขาแหลมคม ได้รับการยกย่องว่าเป็น \'ภูเขาแห่งแรกริมทะเล\' น้ำตกมังกรใหญ่โถมลงจากหน้าผาเสียงกึกก้อง และยามพลบค่ำ เงาของยอดเขาบางลูกก็ดูราวกำลังแปลงร่าง เทือกเขานี้เป็นอุทยานธรณีที่ได้รับการคุ้มครองด้วยคุณค่าทางธรณีวิทยา'),
  'wenzhou/seafood': ('อาหารทะเล', 'อาหารของเวินโจวซึ่งเปิดออกสู่ทะเลจีนตะวันออกนั้นเบาและสดใหม่ ปลาหมึก หอยเชลล์ และปลาคือหัวใจของโต๊ะอาหารประจำวัน อาหารโอวพื้นถิ่นปล่อยให้รสธรรมชาติของอาหารทะเลเป็นพระเอก ส่วนซุปลูกชิ้นปลาตำมือคือเมนูริมทางที่ชาวเมืองรักที่สุด'),
  'tangshan/memorial': ('อนุสรณ์สถานแผ่นดินไหว', 'แผ่นดินไหวครั้งใหญ่ปี 1976 ทำให้ถังซานราบเป็นหน้ากลอง ในอุทยานอนุสรณ์ทุกวันนี้ ชื่อของผู้เสียชีวิตถูกจารึกไว้บนกำแพงหินแกรนิตยาวเหยียด พิธีรำลึกจัดขึ้นทุกปีข้างสระน้ำอันเงียบสงบ เมืองที่สร้างขึ้นใหม่ได้กลายเป็นสัญลักษณ์ของความเข้มแข็งและการเกิดใหม่'),
  'tangshan/coal': ('เหมืองถ่านหินและทางรถไฟแห่งแรก', 'เหมืองถ่านหินสมัยใหม่แห่งแรกของจีนและทางรถไฟยุคแรก ๆ สายหนึ่งเปิดดำเนินการที่ถังซาน หัวรถจักรไอน้ำคันแรกของประเทศก็ถูกสร้างขึ้นที่นี่เช่นกัน เมืองนี้จึงนับเป็นอู่กำเนิดของอุตสาหกรรมจีน วัฒนธรรมเหมืองแร่และเหล็กกล้ายังคงถักทออยู่ในตัวตนของเมืองมาจนทุกวันนี้'),
  'tangshan/ceramic': ('เครื่องปั้นดินเผาถังซาน', 'ถังซานเป็นที่รู้จักในนาม \'เมืองเครื่องเคลือบแห่งภาคเหนือ\' โด่งดังเหนือสิ่งอื่นใดด้วยเครื่องกระเบื้องโบนไชน่า ภาชนะสีขาวเนื้อบางโปร่งแสงของเมืองประดับโต๊ะอาหารทั่วประเทศจีน งานแสดงเซรามิกและโรงช่างของเหล่าปรมาจารย์ช่วยให้ประเพณีนี้ยังคงมีชีวิตอยู่ในเมือง'),
  'tangshan/lake': ('สวนสาธารณะหนานหู', 'หนานหูถือกำเนิดจากการเปลี่ยนพื้นที่ทรุดตัวของเหมืองเก่าให้เป็นทะเลสาบและสวนเขียวชอุ่ม ทุกวันนี้มันคือปอดสีเขียวของเมือง เส้นทางจักรยานและสวนดอกไม้เรียงรายริมฝั่ง อุทยานแห่งนี้ยังเคยเป็นเจ้าภาพงานพืชสวนครั้งใหญ่มาแล้ว ที่นี่คือสัญลักษณ์ของเมืองอุตสาหกรรมที่คืนดีกับธรรมชาติ'),
  'anshan/steel': ('เมืองเหล็กกล้า', 'อันซานคือที่ตั้งของโรงงานเหล็กกล้าที่ใหญ่ที่สุดแห่งหนึ่งของจีน และได้ชื่อว่าเป็น \'เมืองหลวงเหล็กกล้า\' ของประเทศ แสงเรืองจากเตาถลุงส่องสว่างค่ำคืนของเมืองมาหลายชั่วอายุคน ที่นี่การถลุงเหล็กไม่ใช่เพียงอาชีพ หากคือตัวตนแท้จริงของเมือง'),
  'anshan/jade': ('หยกซิ่วเหยียน', 'ซิ่วเหยียนในเขตอันซานคือหนึ่งในดินแดนหยกอันยิ่งใหญ่ของจีน วังพระพุทธรูปหยกในเมืองจัดแสดงพระพุทธรูปเลื่องชื่อระดับโลกซึ่งแกะสลักจากหินหยกมหึมาเพียงก้อนเดียว โรงช่างและตลาดหยกเปี่ยมล้นด้วยฝีมือเชิงช่างที่มอบชีวิตให้แก่ศิลา'),
  'anshan/mountain': ('เขาเชียนซาน', 'เชียนซาน \'ยอดบัวพันดอก\' คือภูเขาศักดิ์สิทธิ์แห่งภาคตะวันออกเฉียงเหนือ ยอดหินแกรนิตของมันเรียงรายดั่งกลีบบัว วัดพุทธและวัดเต๋ากระจายอยู่ตามลาดเขา และหินยักษ์ก้อนหนึ่งก็เลื่องชื่อว่ามีรูปทรงคล้ายพระพุทธรูปประทับนั่ง ในฤดูใบไม้ผลิ ทั้งภูเขาถูกห่มคลุมด้วยดอกไม้บานสะพรั่ง'),
  'anshan/spring': ('น้ำพุร้อนถังกังจื่อ', 'ผู้คนแสวงหาการบำบัดที่บ่อน้ำพุร้อนทังกังจื่อมานานนับพันปี หลายชั่วอายุคนได้แช่น้ำแร่ร้อนและโคลนภูเขาไฟที่เชื่อกันว่าช่วยบรรเทาอาการปวดข้อ บ่อน้ำพุที่เคยต้อนรับกษัตริย์และแขกผู้มีชื่อเสียงตลอดหน้าประวัติศาสตร์ ยังคงเป็นที่พักพิงของผู้แสวงหาการพักผ่อน'),
  'linyi/market': ('ตลาดค้าส่งหลินอี๋', 'หลินอี๋คือศูนย์กลางการค้าส่งที่ใหญ่ที่สุดของจีนตอนเหนือ โถงตลาดอันมหึมามีสินค้าครบครันตั้งแต่เข็มเย็บผ้าไปจนถึงเฟอร์นิเจอร์ รถบรรทุกที่ออกเดินทางจากที่นี่ขนส่งสินค้าไปทุกมุมของประเทศ ความคึกคักนี้ทำให้เมืองได้รับสมญาว่า \'เมืองหลวงโลจิสติกส์\''),
  'linyi/brush': ('บ้านเกิดปรมาจารย์พู่กัน', 'หวังซีจือ \'ปราชญ์แห่งอักษรศิลป์\' ของจีน ถือกำเนิดที่หลินอี๋ ลายพู่กันอันพลิ้วไหวของท่านถูกยึดเป็นแบบอย่างมานานกว่าพันปี ศาลอนุสรณ์และเทศกาลอักษรศิลป์ในเมืองสืบสานมรดกของท่าน ในหลินอี๋ กลิ่นน้ำหมึกคือท่วงทำนองงามสง่าที่ขับรับเสียงอึงคะนึงของการค้า'),
  'linyi/mountain': ('เขาเหมิงซาน', 'เหมิงซาน ไข่มุกแห่งเทือกเขาอี๋เหมิง เป็นหนึ่งในภูเขาที่สูงที่สุดของมณฑลซานตง ป่าทึบ น้ำตก และอากาศบริสุทธิ์ใสกระจ่างทำให้ได้ฉายาว่า \'บาร์ออกซิเจนธรรมชาติ\' ด้วยเส้นทางเดินป่า หมู่บ้านไหล่เขา และน้ำผึ้งป่า ที่นี่มอบการหลีกลี้อันเงียบสงบให้แก่นักเดินทาง'),
  'linyi/pancake': ('แผ่นแป้งอี้เหมิง', 'แผ่นแป้งข้าวโพดและธัญพืชบางเฉียบคืออาหารหลักเก่าแก่ของชาวเขาแถบอี๋เหมิง ปิ้งบนแผ่นหินร้อน และตามธรรมเนียมจะกินโดยห่อต้นหอมสดไว้ข้างใน ขนมปังที่ทนทานและอิ่มท้องนี้เป็นเพื่อนคู่ใจที่ซื่อสัตย์ตลอดชีวิตอันตรากตรำของหมู่บ้านกลางหุบเขา'),
  'cangzhou/lion': ('สิงโตเหล็กชางโจว', 'สิงโตเหล็กหล่อขนาดยักษ์ที่ยืนหยัดมานานกว่าพันปี คือเครื่องหมายแห่งความภาคภูมิของชางโจว และเป็นหนึ่งในโบราณวัตถุเหล็กที่ใหญ่ที่สุดของจีน ชาวบ้านเรียกมันว่า \'เสียงคำรามสยบทะเล\' เล่ากันว่าถูกหล่อขึ้นเพื่อทัดทานอุทกภัย เมืองโอบกอดสัญลักษณ์ของตนดั่งผู้พิทักษ์'),
  'cangzhou/martial': ('ศิลปะการต่อสู้ชางโจว', 'ชางโจวเลื่องชื่อว่าเป็น \'บ้านเกิดวูซู\' ของจีน สำนักหมัดมวยอันหนักหน่วงอย่างปาจี๋เฉวียนเติบโตขึ้นที่นี่ ในอดีต ผู้คุ้มกันติดอาวุธที่อารักขากองคาราวานพ่อค้าจำนวนมากล้วนมาจากเมืองนี้ สำนักฝึกและการแข่งขันยังคงเชิดชูประเพณีให้ยืนหยัดอย่างสง่างามจนทุกวันนี้'),
  'cangzhou/canal': ('คลองขุดต้ายวิ่นเหอ', 'คลองใหญ่ที่เชื่อมปักกิ่งกับหางโจวไหลผ่านใจกลางเมืองชางโจวพอดี และเมืองก็มั่งคั่งขึ้นจากการค้าทางคลองมาหลายศตวรรษ ท่าเรือเก่าและย่านริมน้ำยังคงเก็บร่องรอยของวันวานเหล่านั้นไว้ ส่วนสวนสาธารณะริมคลองก็กลายเป็นที่โปรดปรานสำหรับการเดินเล่นยามเย็น'),
  'cangzhou/jujube': ('พุทราทองคำ', 'พุทรา \'เส้นไหมทอง\' เปลือกบางหวานดั่งน้ำผึ้งของชางโจว ได้รับการยกย่องให้เป็นราชาแห่งผลไม้แห้ง ชื่อของมันมาจากเส้นใยสีทองละเอียดที่ยืดออกจากเนื้อเมื่อฉีกผลออกเป็นสองซีก สวนพุทราแดงระเรื่อในฤดูเก็บเกี่ยวใบไม้ร่วง ส่วนชาและขนมพุทราก็เป็นของประจำโต๊ะอาหารท้องถิ่น'),
  'nantong/textile': ('เมืองแห่งสิ่งทอ', 'เรื่องราวสิ่งทอสมัยใหม่ของหนานทงเริ่มต้นจากโรงปั่นฝ้ายที่จางเจี้ยน นักอุตสาหกรรมผู้ยิ่งใหญ่ก่อตั้งขึ้น ทุกวันนี้เมืองนี้คือเมืองหลวงสิ่งทอเครื่องใช้ในบ้านของจีน ผ้าปูที่นอนและผ้าม่านของเมืองไปถึงตลาดทั่วโลก วัฒนธรรมการทอยังมีชีวิตอยู่ในผ้าพิมพ์ลายสีน้ำเงิน-ขาวพื้นถิ่นอีกด้วย'),
  'nantong/mountain': ('เขาหลางซาน', 'หลางซานห้ายอด ตั้งตระหง่านตรงจุดที่แม่น้ำแยงซีบรรจบกับทะเล คือเขาศักดิ์สิทธิ์ประจำภูมิภาค ผู้แสวงบุญและนักเดินทางไต่บันไดขึ้นสู่วัดพุทธเก่าแก่หลายศตวรรษบนยอดเขา จากเบื้องบน ภาพแม่น้ำสายยิ่งใหญ่หลอมรวมกับทะเลก็คลี่กางอยู่ใต้ฝ่าเท้า'),
  'nantong/kite': ('ว่าวเสียงหวีด', 'ว่าว \'ปันเหยา\' ของหนานทงส่งเสียงหึ่งก้องท้องฟ้าผ่านนกหวีดเล็ก ๆ หลายสิบตัวที่ติดอยู่บนโครงว่าว เมื่อลมพัดแรงขึ้น เสียงก็เอ่อท้นกลายเป็นวงออร์เคสตรา การทำว่าวหวีดนี้คืองานหัตถศิลป์เก่าแก่ที่ส่งต่อจากรุ่นสู่รุ่นและได้รับการดูแลรักษาอย่างพิถีพิถันโดยช่างฝีมือท้องถิ่น'),
  'nantong/school': ('ต้นกำเนิดการศึกษาแผนใหม่', 'จางเจี้ยน นักอุตสาหกรรมและนักปฏิรูป อุทิศทรัพย์สินให้แก่บ้านเกิด ก่อตั้งโรงเรียนสมัยใหม่ ห้องสมุด และพิพิธภัณฑ์แห่งแรกของจีนที่ก่อตั้งโดยชาวจีนเอง เมืองจึงกลายเป็นผู้บุกเบิกด้านการศึกษา อุดมการณ์ \'กอบกู้ชาติด้วยอุตสาหกรรม\' ของท่านยังคงมีชีวิตอยู่ในความทรงจำของชาวเมือง'),
  'taizhou/opera': ('เหมยหลานฟาง', 'รากเหง้าของเหมยหลานฟาง ปรมาจารย์ในตำนานแห่งงิ้วปักกิ่ง สืบย้อนกลับไปถึงไท่โจว ความงามสง่าที่ท่านมอบให้บทบาทตัวนางได้นำพาศิลปะนี้ไปสู่สายตาชาวโลก อุทยานอนุสรณ์และพิพิธภัณฑ์เล่าเรื่องราวของท่านผ่านชุดแสดงและภาพถ่ายบนเวที ทุกวันนี้ท่วงทำนองงิ้วยังคงแว่วมาจากสวนสาธารณะของเมือง'),
  'taizhou/tea': ('น้ำชาตอนเช้า', 'ไท่โจวเริ่มต้นวันใหม่ด้วย \'เจ่าฉา\' หรือชายามเช้า ซาลาเปานึ่ง เต้าหู้แห้งหั่นฝอยละเอียด และซุปลูกชิ้นปลาถูกยกมาเสิร์ฟพร้อมกาน้ำชาแก่ ๆ ชายามเช้าที่นี่ไม่เคยเร่งรีบ เพื่อนบ้านมารวมตัวกันในโรงน้ำชาและค่อย ๆ ก้าวเข้าสู่วันใหม่ผ่านบทสนทนา'),
  'taizhou/boat': ('เทศกาลเรือฉินถง', 'ทุกฤดูใบไม้ผลิ เรือหลายร้อยลำมารวมตัวกันบนพื้นที่ชุ่มน้ำของเมืองฉินถง ฝีพายแข่งขันกันตามจังหวะกลอง ละอองน้ำขาวสาดกระเซ็นเมื่อไม้ถ่อกระทบผืนน้ำ เทศกาลเรือเก่าแก่หลายศตวรรษนี้คือวันที่ครึกครื้นที่สุดของวัฒนธรรมเมืองสายน้ำ และได้รับการขึ้นทะเบียนเป็นมรดกแห่งชาติ'),
  'taizhou/meatball': ('หมูสับหัวสิงโต', 'ลูกชิ้นหมูก้อนโตเนื้อนุ่มที่เรียกว่า \'หัวสิงโต\' คือจานคลาสสิกของอาหารหวยหยาง ได้ชื่อนี้มาจากเนื้อสัมผัสฟูฟ่องที่ชวนให้นึกถึงแผงคอสิงโต เคี่ยวด้วยไฟอ่อนนานหลายชั่วโมงจนละลายในปาก ส่วนสูตรที่เพิ่มไข่ปูเข้าไปคือของเลิศอันทรงเกียรติที่สุดของโต๊ะอาหารฤดูใบไม้ร่วง'),
  'jinhua/ham': ('แฮมจินหัว', 'แฮมจินหัวบ่มด้วยกรรมวิธีหมักเกลือและตากลมที่มีอายุหลายศตวรรษ เนื้อตัดขวางสีแดงเข้มและกลิ่นหอมลึกล้ำทำให้มันเป็นแฮมที่โด่งดังที่สุดของจีน ส่วนใหญ่ใช้เพิ่มความกลมกล่อมลุ่มลึกให้แก่ซุปและอาหารตุ๋น แฮมจินหัวชั้นเลิศคือผลผลิตของความอดทนที่ยาวนานนับปี'),
  'jinhua/film': ('กองถ่ายเหิงเตี้ยน', 'เหิงเตี้ยนในเขตจินหัวคือโรงถ่ายภาพยนตร์กลางแจ้งที่ใหญ่ที่สุดในโลก ภายในตั้งตระหง่านด้วยแบบจำลองขนาดมหึมาของพระราชวังต้องห้ามและพระราชวังโบราณ ภาพยนตร์และละครย้อนยุคนับไม่ถ้วนถ่ายทำกันที่นี่ ระหว่างเดินชมฉาก ผู้มาเยือนอาจได้สวนทางกับนักแสดงในชุดแต่งกายเต็มยศ'),
  'jinhua/cave': ('ถ้ำซวงหลง', 'การเข้าถ้ำซวงหลงหรือ \'มังกรคู่\' นั้นน่าจดจำไม่รู้ลืม ผู้มาเยือนต้องนอนราบไปกับเรือเพื่อลอดผ่านช่องหินเตี้ย ๆ เข้าไป ข้างในเปิดออกเป็นโลกใต้ดินเย็นฉ่ำที่ประดับประดาด้วยหินงอกหินย้อย ถ้ำแห่งนี้ยังได้รับการยกย่องในบันทึกของนักเดินทางยุคโบราณอีกด้วย'),
  'jinhua/bridge': ('สะพานโบราณ', 'ชนบทรอบจินหัว ซึ่งครั้งหนึ่งเคยมีชื่อว่าอู๋โจว ประดับประดาด้วยสะพานหินโค้งและเมืองสายน้ำที่ถักทอด้วยลำคลอง บ้านผนังขาวหลังคากระเบื้องดำสะท้อนเงาระยิบระยับบนผืนน้ำ โรงน้ำชากระจุกตัวอยู่ที่หัวสะพาน ภาพเหล่านี้นำพาวิถีชีวิตอันงามสง่าแบบเจียงหนานมาสู่ปัจจุบัน'),
  'wuhu/park': ('สวนสนุกฟางเท่อ', 'อู๋หูเป็นที่ตั้งของกลุ่มสวนสนุกที่ใหญ่ที่สุดแห่งหนึ่งของจีน มอบวันแห่งความตื่นเต้นเร้าใจแก่ครอบครัว ตั้งแต่รถไฟเหาะไปจนถึงโลกแอนิเมชัน เมืองนี้จึงเติบโตกลายเป็นเมืองหลวงความบันเทิงของภูมิภาค ดึงดูดผู้มาเยือนหลั่งไหลมาจากมณฑลข้างเคียงในทุกสุดสัปดาห์'),
  'wuhu/ironart': ('ภาพวาดเหล็ก', 'ในศิลปะ \'ภาพวาดเหล็ก\' ของอู๋หู เหล็กดัดถูกตีขึ้นรูปเป็นภาพอันงามสง่าที่สะท้อนรอยพู่กัน งานฝีมืออายุราวสามศตวรรษนี้นำจิตวิญญาณของภาพวาดหมึกจีนมาสู่โลหะ ด้วยค้อนและทั่ง เหล่าปรมาจารย์ขึ้นรูปขุนเขา ต้นสน และนกกา ผลงานเหล่านี้คือของขวัญที่เป็นเอกลักษณ์ที่สุดของเมือง'),
  'wuhu/rice': ('ท่าเรือข้าว', 'ในหน้าประวัติศาสตร์ อู๋หูเคยเป็นหนึ่งในตลาดข้าวที่ยิ่งใหญ่ที่สุดของจีน ด้วยทำเลบนแม่น้ำแยงซี ผลผลิตของภาคใต้จึงเปลี่ยนมือกันที่นี่ ทุกวันนี้โกดังทันสมัยเข้าแทนที่กรรมกรแบกกระสอบบนท่าเรือแล้ว แต่เมืองยังคงภาคภูมิใจในมรดกการค้าธัญพืชของตน'),
  'wuhu/river': ('ท่าเรือแม่น้ำแยงซี', 'ท่าเรืออันคึกคักริมแม่น้ำแยงซีทำให้อู๋หูเป็นประตูของมณฑลอานฮุยที่เปิดออกสู่โลกกว้าง เรือสินค้าและเครนยกตู้คอนเทนเนอร์ไม่เคยหยุดพักตลอดลำน้ำ และความเคลื่อนไหวนี้ก็ชมได้อย่างเพลิดเพลินจากสวนริมน้ำ แม่น้ำนำพาทั้งการค้าและสายลมเย็นยามค่ำมาสู่เมือง'),
  'huangshan/peak': ('ภูเขาหวงซาน', 'ด้วยยอดหินแกรนิต ทะเลเมฆ ต้นสนคดโค้ง และบ่อน้ำพุร้อน หวงซานคือภูเขาที่มีชื่อเสียงที่สุดของจีนและเป็นมรดกโลกยูเนสโก ความงามที่ขนานนามกันว่า \'สี่สิ่งมหัศจรรย์\' นี้เป็นแรงบันดาลใจแก่จิตรกรและกวีมาหลายศตวรรษ การได้ยืนอยู่เหนือทะเลเมฆยามอาทิตย์อุทัยคือความทรงจำที่ติดตัวไปชั่วชีวิต'),
  'huangshan/village': ('หมู่บ้านหงชุน', 'หงชุน หมู่บ้านสไตล์ฮุยโจวผนังขาวหลังคากระเบื้องดำ ถักทอด้วยคลองส่งน้ำและสระน้ำรูปพระจันทร์ ดูราวหลุดออกมาจากภาพวาดและได้รับการขึ้นทะเบียนมรดกโลกยูเนสโก ผังหมู่บ้านถูกออกแบบให้ลากเส้นตามรูปร่างของวัว เมื่อหมอกยามเช้าลอยเรี่ยผิวน้ำ เหล่าจิตรกรก็ตั้งขาหยั่งวาดภาพเรียงรายริมฝั่ง'),
  'huangshan/tea': ('ชาเหมาเฟิง', 'หวงซานเหมาเฟิง เก็บจากลาดเขาที่หมอกปกคลุม เป็นหนึ่งในชาเขียวที่เลื่องชื่อที่สุดของจีน ได้ชื่อมาจากใบชาปลายมีขนอ่อนรูปทรงคล้ายยอดเขา ผลผลิตต้นฤดูใบไม้ผลิถือว่าล้ำค่าที่สุด ในถ้วยชาทิ้งกลิ่นกล้วยไม้อ่อนจาง ราวกับเมฆหมอกแห่งขุนเขาถูกถักทอไว้ในใบชา'),
  'huangshan/ink': ('หมึกและศิลปะหุยโจว', 'ดินแดนฮุยโจวเก่าผลิตแท่งหมึกและแท่นฝนหมึกหินอันทรงเกียรติที่สุดของจีน ซึ่งนักอักษรศิลป์เสาะแสวงหามาหลายศตวรรษ คฤหาสน์ที่ประดับด้วยงานแกะสลักไม้ อิฐ และหิน ก็ผุดขึ้นจากจิตวิญญาณเชิงช่างเดียวกัน วัฒนธรรมฮุยหลอมรวมหมึกกับสถาปัตยกรรมไว้ในสุนทรียะหนึ่งเดียว'),
  'yichun/moon': ('ภูเขาหมิงเยว่', 'เขาหมิงเยว่ ชื่อที่แปลว่า \'จันทร์กระจ่าง\' คือสัญลักษณ์ของอี๋ชุน เมืองที่ยังเลื่องชื่อด้วยเทศกาลในธีมพระจันทร์ กระเช้าลอยฟ้าพาผู้มาเยือนขึ้นสู่เส้นทางเลียบหน้าผาและทุ่งหญ้าบนภูเขาสูง เมื่อสายหมอกจางหายที่ยอดเขา หุบเขาเบื้องล่างก็เรืองรองด้วยแสงสีเงินยวง'),
  'yichun/spring': ('บ่อน้ำพุร้อน', 'น้ำพุร้อนของเมืองเวินถังในอี๋ชุนอุดมด้วยแร่ซีลีเนียมอันหายาก และเชื่อกันมาช้านานว่ามีสรรพคุณบำบัดรักษา โรงแรมสปาและสระน้ำกลางแจ้งต้อนรับผู้มาเยือนตลอดทั้งปี การบรรจบกันของอากาศภูเขากับสายน้ำร้อนไอระอุทำให้เมืองนี้เป็นหนึ่งในจุดหมายน้ำพุร้อนสุดโปรดของจีน'),
  'yichun/zen': ('พุทธศาสนานิกายฉาน', 'ขุนเขาแห่งอี๋ชุนคือหนึ่งในดินแดนที่สำนักสำคัญของพุทธศาสนานิกายฉาน (เซน) หยั่งรากลง วัดเก่าแก่หลายศตวรรษกระจายตัวอยู่ตามหุบเขาอันเงียบสงบ สวนชาและหอปฏิบัติสมาธิของเหล่าภิกษุเชื้อเชิญผู้มาเยือนให้ชะลอฝีเท้า เสียงระฆังก้องกังวานผ่านผืนป่าที่หมอกปกคลุม'),
  'yichun/rice': ('ที่ราบลุ่มแม่น้ำหยวนเหอ', 'ที่ราบอันอุดมของแม่น้ำหยวนเป็นยุ้งฉางของมณฑลเจียงซีมาช้านาน ผืนนาน้ำท่าบริบูรณ์ให้ผลผลิตข้าวอันงอกงามปีแล้วปีเล่า ฤดูเก็บเกี่ยวในหมู่บ้านผ่านไปราวงานเทศกาล เส้นหมี่จากข้าวใหม่และเหล้าข้าวพื้นถิ่นนำความเอื้ออารีของท้องทุ่งขึ้นสู่โต๊ะอาหาร'),
  'zhangzhou/narcissus': ('ดอกนาร์ซิสซัส', 'หัวดอกจุ๊ยเซียน (นาร์ซิสซัส) ที่เลื่องชื่อที่สุดของจีนปลูกกันที่จางโจว และดอกไม้นี้คือเครื่องประดับที่ขาดไม่ได้ของเทศกาลตรุษจีน ช่างฝีมือแกะสลักหัวดอกด้วยรอยกรีดพิเศษเพื่อให้ดอกผลิบานเป็นทรวดทรงงดงาม จุ๊ยเซียนที่บานในบ้านช่วงปีใหม่ถือเป็นสิริมงคลของปีที่กำลังจะมาถึง'),
  'zhangzhou/tulou': ('บ้านดินถู่โหลว', 'ป้อมปราการดินอัดทรงกลมขนาดยักษ์ที่เรียกว่า \'ถู่โหลว\' รวมทั้งหมู่บ้านไว้ใต้หลังคาเดียวกัน และได้รับการขึ้นทะเบียนมรดกโลกยูเนสโก กำแพงหนาให้ทั้งการป้องกันภัยและความเย็นสบาย ชีวิตส่วนรวมในลานกลางบ้านดำเนินต่อเนื่องมาหลายศตวรรษ กลุ่มถู่โหลวที่เรียงรายท่ามกลางเนินเขาเขียวขจีวาดภาพราวกับหลุดจากนิทาน'),
  'zhangzhou/banana': ('ผลไม้เมืองร้อน', 'ดินดอนสามเหลี่ยมอันอบอุ่นชุ่มชื้นของจางโจวออกผลตลอดทั้งปี สวนกล้วย ป่าลำไย และไร่ส้มทอดยาวไปสุดขอบฟ้า ส้มโอลูกโตเนื้อฉ่ำของถิ่นนี้ก็เป็นขวัญใจของโต๊ะอาหารเช่นกัน ไม่ว่าฤดูไหน ตลาดผลไม้ก็ละลานตาด้วยสีสันและหอมกรุ่นด้วยกลิ่นผลไม้'),
  'zhangzhou/coast': ('เกาะตงซาน', 'เกาะตงซาน ด้วยหาดทรายสีทองและหมู่บ้านชาวประมง คือไข่มุกแห่งชายฝั่งทะเลตอนใต้ ภาพที่เลื่องชื่อที่สุดของเกาะคือ \'หินลมโยก\' ก้อนมหึมาที่ทรงตัวอยู่ริมหน้าผาและว่ากันว่าจะแกว่งไกวเบา ๆ ตามสายลม ยามเย็น เรือที่กลับเข้าฝั่งก็นำปลาสด ๆ ที่จับได้ในวันนั้นมาสู่ท่าเรือ'),
  'guangzhou/tower': ('แคนตัน ทาวเวอร์', 'หอคอยที่ตั้งตระหง่านริมแม่น้ำจูเจียงมีลำตัวเรียวบิดเกลียวอย่างงดงาม จนชาวเมืองตั้งฉายาให้อย่างเอ็นดูว่า \'สาวเอวบาง\' หอคอยแห่งนี้เป็นหนึ่งในหอที่สูงที่สุดในโลก ยามค่ำคืนจะเปล่งประกายด้วยแสงไฟ LED นับพันดวงที่เปลี่ยนสีสันไปเรื่อย ๆ ราวมงกุฎยุคใหม่ประดับเส้นขอบฟ้าของกว่างโจว พร้อมวิวกว้างไกลเหนือดินดอนสามเหลี่ยมปากแม่น้ำ'),
  'guangzhou/dimsum': ('ติ่มซำ', 'เช้าวันใหม่ในกว่างโจวเริ่มต้นด้วย \'ยำฉา\' คือการจิบชาร้อน ๆ คู่กับติ่มซำที่นึ่งมาในเข่งไม้ไผ่ซ้อนกันเป็นชั้น ๆ ฮะเก๋ากุ้ง ขนมจีบ และเพสตรีกรอบ ๆ ช่วยหล่อเลี้ยงวงสนทนาที่ยืดยาวได้เป็นชั่วโมง ธรรมเนียมนี้ถือเป็นหัวใจของวัฒนธรรมอาหารกวางตุ้งเลยทีเดียว'),
  'guangzhou/academy': ('ศาลบรรพชนตระกูลเฉิน', 'ศาลบรรพชนอันโอ่อ่าหลังนี้สร้างขึ้นปลายราชวงศ์ชิง ด้วยเงินสมทบจากครอบครัวที่ใช้แซ่เฉินร่วมกัน โดดเด่นด้วยงานแกะสลักไม้ ภาพนูนหิน และตุ๊กตาเซรามิกหลากสีที่ประดับแน่นอยู่บนสันหลังคา ปัจจุบันที่นี่เป็นพิพิธภัณฑ์ศิลปะพื้นบ้านที่จัดแสดงสุดยอดงานฝีมือของจีนตอนใต้'),
  'guangzhou/flower': ('นครแห่งดอกไม้', 'ด้วยภูมิอากาศอบอุ่นสบาย ดอกไม้ในกว่างโจวจึงเบ่งบานได้ตลอดทั้งปี เมืองนี้จึงได้รับสมญาแต่โบราณว่า \'เมืองดอกไม้\' ก่อนถึงเทศกาลตรุษจีน ตลาดดอกไม้ขนาดมหึมาจะผุดขึ้นเต็มท้องถนน ครอบครัวต่าง ๆ พากันมาซื้อต้นส้มจี๊ดและกิ่งดอกท้อ เพื่อนำโชคลาภเข้าบ้านรับปีใหม่'),
  'wuhan/crane': ('หอเหลือง', 'หอกระเรียนเหลืองที่ทอดสายตาลงสู่แม่น้ำแยงซี มีประวัติย้อนไปถึงยุคสามก๊ก และนับเป็นหอคอยที่เลื่องชื่อที่สุดแห่งหนึ่งของจีน หอแห่งนี้เป็นแรงบันดาลใจให้บทกวีของกวีเอกอย่างชุยเฮ่าและหลี่ไป๋ แม้จะถูกทำลายและสร้างขึ้นใหม่หลายต่อหลายครั้ง แต่จิตวิญญาณแห่งบทกวีของมันยังคงอยู่เสมอมา'),
  'wuhan/noodle': ('บะหมี่แห้งร้อน', 'เร่อกานเมี่ยน หรือ \'บะหมี่แห้งร้อน\' ทำจากเส้นบะหมี่เหนียวนุ่มที่ลวกแล้วคลุกกับซอสงาเข้มข้น ผักดอง และต้นหอมซอย ชาวอู่ฮั่นเริ่มต้นวันด้วยบะหมี่ชามนี้จากแผงริมถนน วัฒนธรรมอาหารเช้าที่นี่ถึงกับมีชื่อเรียกเฉพาะว่า \'กั้วเจ่า\' ซึ่งหมายถึงการใช้ยามเช้าอย่างมีความสุข'),
  'wuhan/duckneck': ('คอเป็ดพะโล้รสเผ็ด', 'คอเป็ดที่ตุ๋นนานหลายชั่วโมงในน้ำพะโล้หอมกรุ่นด้วยพริกและเครื่องเทศ คือของว่างยอดนิยมที่สุดของอู่ฮั่น รสเผ็ดชาลิ้นของมันชวนให้แทะเพลินไปถึงกระดูก และเป็นเพื่อนคู่ใจของวงสนทนาริมแม่น้ำกับเบียร์เย็น ๆ ในค่ำคืนฤดูร้อนอันยาวนาน'),
  'wuhan/university': ('ซากุระมหาวิทยาลัยอู่ฮั่น', 'ทุกฤดูใบไม้ผลิ วิทยาเขตเก่าแก่ของมหาวิทยาลัยอู่ฮั่นจะถูกปกคลุมด้วยดอกซากุระสีชมพูขาวราวหมู่เมฆ ดึงดูดผู้มาเยือนจากทั่วประเทศจีน ภาพดอกไม้บานตัดกับอาคารเก่าบนเชิงเขาลั่วเจีย กลายเป็นทิวทัศน์ฤดูใบไม้ผลิที่โรแมนติกที่สุดของเมืองนี้'),
  'tianjin/eye': ('เทียนจินอาย', 'ชิงช้าสวรรค์ยักษ์ \'เทียนจินอาย\' ตั้งอยู่กลางสะพานข้ามแม่น้ำไห่เหอพอดี นับเป็นชิงช้าสวรรค์หายากของโลกที่สร้างอยู่เหนือสายน้ำไหลโดยตรง เมื่อกระเช้าขึ้นถึงจุดสูงสุด สองฟากฝั่งแม่น้ำจะแผ่กว้างอยู่ใต้เท้าคุณ ฝั่งหนึ่งคืออาคารสไตล์ยุโรปยุคเก่า อีกฝั่งคือตึกกระจกสูงระยับ'),
  'tianjin/baozi': ('ซาลาเปาโกวปู้หลี่', 'ซาลาเปาโกวปู้หลี่ทำกันมาตั้งแต่สมัยราชวงศ์ชิง ขึ้นชื่อเรื่องแป้งบาง ไส้หมูฉ่ำ และจีบรอยพับที่ประณีตเรียบร้อย ชื่อแปลก ๆ ของมันแปลว่า \'ขนาดสุนัขยังไม่สนใจ\' ตำนานเล่าว่าเจ้าของร้านง่วนอยู่กับการปั้นซาลาเปาจนไม่มีเวลาพูดคุยกับลูกค้าเลย'),
  'tianjin/crosstalk': ('เซี่ยงเซิง', 'เซียงเซิงคือศิลปะการแสดงดั้งเดิม ที่นักแสดงตลกสองคนโต้คารมกันด้วยมุกเร็วจี๋ การเล่นคำ และการเลียนเสียงจนผู้ชมหัวเราะกันครืน ศิลปะแขนงนี้หยั่งรากในโรงน้ำชาของเทียนจิน จนทำให้เมืองได้ชื่อว่าเป็นแหล่งกำเนิดของวงการตลกจีน และทุกวันนี้ผู้ชมก็ยังนั่งชมกันพร้อมจิบชาร้อน ๆ'),
  'tianjin/architecture': ('ย่านสถาปัตยกรรมยุโรป', 'อู่ต้าเต้า หรือ \'ห้าถนนสายใหญ่\' ยังคงรักษาวิลล่าสไตล์ยุโรปนับร้อยหลังจากยุคเขตเช่าต่างชาติเอาไว้ ย่านที่สถาปัตยกรรมแบบอังกฤษ ฝรั่งเศส และอิตาลีเรียงรายเคียงกันนี้ ทำให้เทียนจินได้สมญาว่า \'พิพิธภัณฑ์สถาปัตยกรรมโลก\' และวิธีเที่ยวชมที่ดีที่สุดคือนั่งรถม้าหรือปั่นจักรยาน'),
  'xiamen/island': ('เกาะกูลั่งอวี่', 'บนเกาะกู่ล่างอวี่นอกชายฝั่งเซี่ยเหมิน ไม่มีรถยนต์แม้แต่คันเดียว ตรอกซอยแคบ ๆ จึงมีเพียงเสียงฝีเท้าและเสียงเปียโนล่องลอยมาให้ได้ยิน เกาะแห่งนี้ได้รับการขึ้นทะเบียนเป็นมรดกโลกของยูเนสโก ด้วยอาคารสถานกงสุลเก่าและวิลล่าที่ปกคลุมด้วยดอกเฟื่องฟ้า ราวพิพิธภัณฑ์กลางแจ้งที่นั่งเรือเฟอร์รีไปถึงได้ในเวลาสั้น ๆ'),
  'xiamen/piano': ('เกาะเปียโน', 'ดนตรีตะวันตกหยั่งรากบนเกาะกู่ล่างอวี่ตั้งแต่ศตวรรษที่สิบเก้า โดยมิชชันนารีและพ่อค้าที่มาตั้งรกรากเป็นผู้นำเข้ามา เกาะนี้มีเปียโนต่อครัวเรือนมากเป็นพิเศษจนได้ชื่อว่า \'เกาะเปียโน\' และยังคงสืบสานประเพณีนี้ผ่านพิพิธภัณฑ์เปียโนกับนักดนตรีที่ถือกำเนิดที่นี่รุ่นแล้วรุ่นเล่า'),
  'xiamen/egret': ('นกยางขาว', 'ชื่อเก่าของเซี่ยเหมินคือ \'หลู่เต่า\' ที่แปลว่า \'เกาะนกยาง\' และทุกวันนี้นกยางขาวแสนสง่าก็ยังโผบินอยู่เหนือชายฝั่งและบึงน้ำของเมือง นกชนิดนี้ได้รับเลือกเป็นสัญลักษณ์ประจำเมือง ปรากฏอยู่ทุกหนแห่งตั้งแต่รูปปั้นไปจนถึงชื่อถนน คอยย้ำเตือนถึงสายใยแน่นแฟ้นระหว่างเซี่ยเหมินกับทะเลและธรรมชาติ'),
  'xiamen/oyster': ('หอยทอด', 'หอยนางรมสดคลุกกับไข่และแป้งมันเทศ ทอดจนขอบกรอบแต่ข้างในนุ่มลื่น คือไข่เจียวหอยนางรมตำรับสตรีทฟู้ดคลาสสิกของชายฝั่งหมิ่นหนาน จานเด็ดนี้เสิร์ฟพร้อมซอสรสหวานเผ็ดตามตลาดกลางคืนของเซี่ยเหมิน และเป็นที่รักไม่แพ้กันในไต้หวันฝั่งตรงข้ามช่องแคบ'),
  'harbin/ice': ('เทศกาลน้ำแข็ง', 'ทุกฤดูหนาว ก้อนน้ำแข็งยักษ์ที่ตัดจากแม่น้ำซงฮวาอันเยือกแข็งจะถูกนำมาก่อเป็นปราสาท หอคอย และสไลเดอร์ ซึ่งเปล่งแสงสีสดใสยามค่ำคืน เทศกาลน้ำแข็งและหิมะฮาร์บินคือเทศกาลประติมากรรมน้ำแข็งที่ใหญ่ที่สุดในโลก เปลี่ยนเมืองอันหนาวเหน็บให้กลายเป็นดินแดนเทพนิยายต้อนรับผู้มาเยือนนับล้านคน'),
  'harbin/cathedral': ('มหาวิหารเซนต์โซเฟีย', 'โบสถ์เซนต์โซเฟียกับโดมหัวหอมสีเขียวและผนังอิฐแดง คือสิ่งก่อสร้างที่งดงามที่สุดที่หลงเหลือจากยุคทางรถไฟรัสเซียของฮาร์บิน ปัจจุบันโบสถ์ทำหน้าที่เป็นพิพิธภัณฑ์สถาปัตยกรรม ส่วนจัตุรัสด้านหน้าที่มีฝูงนกพิราบโบยบินและนักดนตรีข้างถนนบรรเลงเพลง ก็เป็นจุดนัดพบยอดนิยมของชาวเมือง'),
  'harbin/sausage': ('ไส้กรอกแดง', 'ไส้กรอกแดงรมควันซึ่งเริ่มผลิตตามตำรับรัสเซียที่ผู้อพยพนำเข้ามาเมื่อกว่าศตวรรษก่อน คือรสชาติอันเป็นเอกลักษณ์ของฮาร์บิน กลิ่นหอมควันไม้และรสกระเทียมอ่อน ๆ ของมันเข้ากันดีเหลือเกินกับขนมปังอบใหม่และเบียร์เย็น ๆ นำรากเหง้ายุโรปของเมืองนี้มาสู่โต๊ะอาหารโดยตรง'),
  'harbin/accordion': ('เมืองแห่งดนตรี', 'ไวโอลิน หีบเพลงแอคคอร์เดียน และวัฒนธรรมอุปรากรเดินทางมาพร้อมผู้ตั้งถิ่นฐานชาวรัสเซีย ทำให้ฮาร์บินกลายเป็นศูนย์กลางดนตรีตะวันตกยุคแรก ๆ ของจีน เมืองนี้เป็นบ้านของวงซิมโฟนีออร์เคสตราบุกเบิกของประเทศ และยังคงรักษาสมญา \'เมืองดนตรี\' ไว้ด้วยเทศกาลดนตรีฤดูร้อนที่จัดต่อเนื่องมายาวนาน'),
  'fuzhou/alley': ('ซานฟางชีเซี่ยง', 'ย่าน \'สามตรอกเจ็ดซอย\' ยังคงรักษาบ้านผนังขาวหลังคากระเบื้องดำจากสมัยราชวงศ์หมิงและชิงไว้อย่างดี ครั้งหนึ่งเหล่าบัณฑิตและขุนนางเคยอาศัยอยู่ตามตรอกหินแคบ ๆ เหล่านี้ ปัจจุบันคฤหาสน์แบบมีลานในกลายเป็นร้านน้ำชาและร้านงานฝีมือ ทำให้ย่านเก่าแห่งนี้ยังมีชีวิตชีวาเสมือนพิพิธภัณฑ์ที่มีลมหายใจ'),
  'fuzhou/banyan': ('เมืองแห่งต้นไทร', 'ด้วยโครงการปลูกต้นไม้ที่เริ่มขึ้นตั้งแต่สมัยราชวงศ์ซ่ง ถนนหนทางของฝูโจวจึงเต็มไปด้วยต้นไทรอายุหลายศตวรรษที่ยังยืนต้นมาจนทุกวันนี้ รากอากาศของมันห้อยระย้าราวหนวดเครายาว ทอดร่มเงาเย็นสบายให้คลายร้อนในฤดูร้อนอันอบอ้าว เมืองนี้จึงได้ชื่อเรียกอย่างรักใคร่ว่า \'หรงเฉิง\' หรือเมืองแห่งต้นไทร'),
  'fuzhou/hotspring': ('บ่อน้ำพุร้อน', 'น้ำพุร้อนธรรมชาติผุดขึ้นใจกลางเมืองฝูโจวพอดี หล่อเลี้ยงวัฒนธรรมโรงอาบน้ำที่สืบทอดมานานกว่าพันปี ชาวเมืองยังคงแช่น้ำคลายเมื่อยตามสปาประจำย่านของตน ฝูโจวจึงเป็นหนึ่งในเมืองหายากของจีนที่ตั้งอยู่บนขุมทรัพย์พลังงานความร้อนใต้พิภพโดยตรง'),
  'fuzhou/soup': ('พระกระโดดกำแพง', 'ฝอเที่ยวเฉียง หรือ \'พระกระโดดกำแพง\' คือซุปในตำนานที่เคี่ยววัตถุดิบล้ำค่านับสิบชนิด ทั้งหอยเชลล์ เห็ด เป๋าฮื้อ และอื่น ๆ ในไหดินเผานานหลายชั่วโมง ชื่อของมันมาจากบทกวีที่ว่ากลิ่นหอมนั้นเย้ายวนเสียจนแม้แต่พระยังยอมกระโดดข้ามกำแพงมาลิ้มลอง และซุปนี้ก็ยังครองตำแหน่งมงกุฎแห่งอาหารฝูเจี้ยนมาจนทุกวันนี้'),
  'dongguan/robot': ('โรงงานของโลก', 'ตงกวนซึ่งตั้งอยู่ใจกลางดินดอนสามเหลี่ยมปากแม่น้ำจูเจียง คือเมืองอุตสาหกรรมยักษ์ใหญ่ที่โรงงานผลิตสินค้าอิเล็กทรอนิกส์และของเล่นส่วนสำคัญของโลก ทุกวันนี้สายพานการผลิตที่ใช้แรงงานเข้มข้นกำลังถูกแทนที่ด้วยโรงงานอัจฉริยะและแขนกลหุ่นยนต์ \'โรงงานของโลก\' แห่งนี้กำลังปรับโฉมตัวเองสู่ยุคใหม่'),
  'dongguan/basketball': ('เมืองแห่งบาสเกตบอล', 'บาสเกตบอลคือความหลงใหลของชาวตงกวน แทบทุกย่านมีสนามบาส และมีระบบพัฒนานักกีฬาที่เข้มแข็งจากสนามข้างบ้านสู่ลีกอาชีพ สโมสรกวางตุ้งเซาเทิร์นไทเกอร์ส หนึ่งในทีมที่คว้าแชมป์มากที่สุดของวงการบาสเกตบอลจีน ก็มีเมืองนี้เป็นบ้าน ตงกวนจึงได้รับการประกาศอย่างเป็นทางการให้เป็น \'เมืองบาสเกตบอล\' ของจีน'),
  'dongguan/keyuan': ('สวนเข่อหยวน', 'สวนเข่อหยวนซึ่งสร้างโดยขุนนางสมัยราชวงศ์ชิง มีชื่อเสียงจากการจัดวางศาลา สระน้ำ และระเบียงทางเดินคดเคี้ยวลงในพื้นที่อันแสนจำกัดได้อย่างชาญฉลาด สวนแห่งนี้นับเป็นหนึ่งในสี่สุดยอดสวนคลาสสิกของมณฑลกวางตุ้ง และกลั่นความประณีตเงียบงามของศิลปะภูมิทัศน์จีนตอนใต้ไว้อย่างครบถ้วน'),
  'dongguan/cannon': ('ป้อมปราการหู่เหมิน', 'ป้อมปราการหู่เหมินเคยทำหน้าที่เฝ้าปากแม่น้ำจูเจียงด้วยปืนใหญ่ที่เรียงรายเป็นแถว บนชายฝั่งแห่งนี้เองที่ข้าหลวงหลินเจ๋อสวีสั่งทำลายฝิ่นที่ยึดมาได้ในปี 1839 จนจุดชนวนสงครามฝิ่น ปัจจุบันแนวป้อมและพิพิธภัณฑ์บอกเล่าจุดเปลี่ยนสำคัญครั้งนี้ในประวัติศาสตร์จีนยุคใหม่'),
  'lanzhou/beefnoodle': ('บะหมี่เนื้อหลานโจว', 'บะหมี่ดึงมือของหลานโจวมีสูตรอันเลื่องชื่อ คือน้ำซุปเนื้อใสสะอาด หัวไชเท้าขาว น้ำมันพริกแดง และผักชีเขียวสด นายช่างจะยืดนวดแป้งให้กลายเป็นเส้นเรียวละเอียดต่อหน้าต่อตาคุณภายในไม่กี่วินาที บะหมี่ร้อน ๆ ยามเช้าชามนี้เป็นทั้งกิจวัตรประจำวันของชาวเมือง และหนึ่งในอาหารจานเลื่องชื่อที่สุดของจีน'),
  'lanzhou/waterwheel': ('กังหันน้ำ', 'กังหันน้ำไม้ขนาดยักษ์ที่สร้างขึ้นครั้งแรกในสมัยราชวงศ์หมิง เพื่อวิดน้ำจากแม่น้ำเหลืองขึ้นสู่ไร่นา ได้กลายเป็นสัญลักษณ์คู่เมืองหลานโจว ในสวนกังหันน้ำริมแม่น้ำ กังหันจำลองที่สร้างตามแบบดั้งเดิมยังคงหมุนอยู่จนทุกวันนี้ เสียงเอียดอาดช้า ๆ ของมันสะท้อนภูมิปัญญาชลประทานอันชาญฉลาดที่สืบทอดมาหลายศตวรรษ'),
  'lanzhou/statue': ('อนุสาวรีย์มารดาแม่น้ำเหลือง', 'ประติมากรรม \'มารดาแม่น้ำเหลือง\' ริมฝั่งน้ำ เป็นรูปมารดาผมสยายพลิ้วนอนอย่างสงบ โดยมีทารกน้อยเอนกายอยู่บนอก มารดาคือตัวแทนของแม่น้ำเหลืองที่หล่อเลี้ยงอารยธรรมจีน ส่วนเด็กน้อยคือผู้คนที่ถือกำเนิดจากสายน้ำแห่งนี้ ประติมากรรมนี้จึงเป็นถ้อยแถลงจากหัวใจของหลานโจวที่มีต่อแม่น้ำอันเป็นที่รัก'),
  'lanzhou/raft': ('แพหนังแกะ', 'แพหนังแกะที่ทำจากหนังแกะเป่าลมผูกเข้ากับโครงไม้ เคยขนส่งสินค้าและผู้โดยสารไปตามแม่น้ำเหลืองนานหลายศตวรรษ ทุกวันนี้แพแบบดั้งเดิมเหล่านี้พานักท่องเที่ยวล่องชมริมฝั่งน้ำของหลานโจว การลอยละล่องเหนือสายน้ำสีขุ่นตะกอนยังคงเป็นประสบการณ์ที่แท้จริงดั้งเดิมที่สุดของเมืองนี้'),
  'urumqi/bazaar': ('ตลาดแกรนด์บาซาร์', 'แกรนด์บาซาร์แห่งอุรุมชี ด้วยหอคอยที่ได้แรงบันดาลใจจากสถาปัตยกรรมอิสลามและอาคารตลาดหลังคาโดม ยังคงสืบสานจิตวิญญาณการค้าแห่งเส้นทางสายไหมเอาไว้ แผงร้านค้าอัดแน่นด้วยผลไม้แห้ง เครื่องเทศ ผ้าไหม และมีดทำมือ พอตกค่ำลานกว้างก็คึกคักขึ้นด้วยการแสดงดนตรีและระบำพื้นเมือง'),
  'urumqi/tianshan': ('ทะเลสาบเทียนฉือ', 'เทียนฉือ หรือ \'ทะเลสาบสวรรค์\' ทอดตัวอยู่ใต้ยอดเขาป๋อเก๋อต๋าที่ปกคลุมด้วยหิมะในเทือกเขาเทียนซาน น้ำสีน้ำเงินเข้มของมันถูกโอบล้อมด้วยป่าสนสพรูซ ตำนานเล่าว่าที่นี่คือสถานที่จัดงานเลี้ยงของเจ้าแม่ซีหวังหมู่ผู้ครองแดนตะวันตก และทะเลสาบยังเป็นส่วนหนึ่งของเทือกเขาเทียนซานที่ขึ้นทะเบียนมรดกโลกยูเนสโกด้วย'),
  'urumqi/kebab': ('เนื้อแกะย่าง', 'เนื้อแกะเสียบไม้ย่างบนถ่านร้อนจนส่งเสียงฉ่า โรยด้วยยี่หร่าและพริกป่น กลิ่นหอมควันลอยอบอวลไปทั่วท้องถนนของอุรุมชี เคบับคือสัญลักษณ์ของอาหารอุยกูร์ และจะอร่อยที่สุดเมื่อกินที่ตลาดกลางคืน คู่กับแป้งนานอบใหม่จากเตาทันดูร์และชาร้อนรสเข้มสักกา'),
  'urumqi/dance': ('ระบำอุยกูร์', 'ระบำอุยกูร์ที่หมุนคว้างไปตามจังหวะกลองและเสียงสายของพิณราวาปกับดูทาร์ คือดาวเด่นของงานแต่งงานและเทศกาลทุกงาน ด้วยท่วงท่ามืออันอ่อนช้อยและการหมุนตัวที่เร่งเร็วขึ้นเรื่อย ๆ ระบำนี้เป็นศิลปะแห่งความรื่นเริงร่วมกันของชุมชน และแขกผู้มาเยือนย่อมถูกดึงเข้าสู่วงเต้นรำด้วยเสมอ'),
  'haikou/coconut': ('เมืองแห่งมะพร้าว', 'ในไหโข่ว เมืองเอกของเกาะไหหลำ ถนนหนทางร่มรื่นด้วยแถวต้นมะพร้าวเรียงราย เมืองนี้จึงได้ฉายาว่า \'เย่เฉิง\' หรือเมืองมะพร้าว พ่อค้าริมทางใช้มีดพร้าฟันเปิดลูกมะพร้าวเย็นเจี๊ยบให้ลูกค้าในพริบตา เป็นยาดับร้อนเขตร้อนที่เป็นธรรมชาติที่สุดแล้ว'),
  'haikou/arcade': ('ย่านตึกแถวฉีโหลว', 'ถนนการค้าเก่าแก่ของไหโข่วเรียงรายด้วยตึกแถว \'ฉีโหลว\' อาคารพาณิชย์แบบมีทางเดินโค้งใต้ตัวตึก ซึ่งสร้างโดยพ่อค้าที่กลับมาจากเอเชียตะวันออกเฉียงใต้ ทางเดินมีหลังคาคลุมเหล่านี้ช่วยกำบังทั้งฝนเขตร้อนและแดดจ้าให้ผู้จับจ่าย เป็นสถาปัตยกรรมแห่งร่มเงาอันงามสง่าที่รับใช้เมืองนี้มาราวหนึ่งศตวรรษ'),
  'haikou/crater': ('อุทยานภูเขาไฟ', 'ชานเมืองไหโข่วมีทุ่งภูเขาไฟโบราณที่กลายเป็นจีโอพาร์คเขียวชอุ่ม เต็มไปด้วยปล่องภูเขาไฟที่ดับสนิทแล้วและอุโมงค์ลาวา หินบะซอลต์ที่หลงเหลือจากการปะทุครั้งบรรพกาลยังคงหล่อหลอมชีวิตท้องถิ่น ทั้งบ้านเรือนและกำแพงไร่นาในหมู่บ้านล้วนก่อจากหินชนิดนี้ และผู้มาเยือนยังเดินลงไปถึงก้นปากปล่องภูเขาไฟได้ด้วย'),
  'haikou/turtle': ('ทะเลเขตร้อน', 'น่านน้ำอุ่นใสสะอาดนอกชายฝั่งไหหลำเป็นที่พักพิงของแนวปะการังและทุ่งหญ้าทะเลที่อุดมด้วยสรรพชีวิต เต่าทะเลมาหากินและวางไข่ตามชายฝั่งเหล่านี้ และด้วยโครงการอนุรักษ์ต่าง ๆ ภาพลูกเต่าตะกายลงสู่เกลียวคลื่นก็กลับมาเป็นภาพแห่งความหวังอีกครั้งหนึ่ง'),
  'luoyang/grotto': ('ถ้ำหินหลงเหมิน', 'ถ้ำหินหลงเหมินที่สลักลงบนหน้าผาสองฟากแม่น้ำอี๋ เก็บรักษาพระพุทธรูปไว้นับหมื่นองค์และได้รับการขึ้นทะเบียนเป็นมรดกโลกยูเนสโก งานแกะสลักเริ่มขึ้นในสมัยราชวงศ์เว่ยเหนือและรุ่งเรืองสูงสุดในสมัยถัง โดยมีมงกุฎแห่งผลงานคือพระไวโรจนพุทธะองค์มหึมาที่แย้มรอยยิ้มอันสงบงาม'),
  'luoyang/peony': ('เมืองหลวงแห่งดอกโบตั๋น', 'ลั่วหยางผูกพันกับดอกโบตั๋นมาตั้งแต่สมัยราชวงศ์ถัง ตำนานเล่าว่าโบตั๋นถูกเนรเทศมาที่นี่ เพราะเป็นดอกไม้เพียงชนิดเดียวที่ขัดพระบัญชาของพระนางบูเช็กเทียนที่ให้บานกลางฤดูหนาว ทุกเดือนเมษายน เมืองทั้งเมืองจะระเบิดสีสันในเทศกาลดอกโบตั๋น เพื่อเทิดเกียรติดอกไม้ที่ประเพณียกย่องให้เป็น \'ราชาแห่งบุปผา\''),
  'luoyang/whitehorse': ('วัดม้าขาว', 'วัดม้าขาวซึ่งก่อตั้งขึ้นเมื่อ ค.ศ. 68 ได้รับการยกย่องว่าเป็นวัดพุทธแห่งแรกของจีน ชื่อวัดรำลึกถึงม้าขาวที่เชื่อกันว่าแบกพระคัมภีร์ศักดิ์สิทธิ์เดินทางมาจากอินเดีย วัดแห่งนี้คือสัญลักษณ์การมาถึงของพระพุทธศาสนาในแผ่นดินจีน และยังคงเป็นสถานที่สักการะและจาริกแสวงบุญที่มีชีวิตชีวาจนทุกวันนี้'),
  'luoyang/capital': ('เมืองหลวงเก่า', 'ลั่วหยางเคยเป็นเมืองหลวงของสิบสามราชวงศ์ รวมทั้งราชวงศ์ฮั่นและถัง จึงยืนอยู่ใจกลางประวัติศาสตร์จีนโดยแท้ เมืองโบราณแห่งลุ่มแม่น้ำเหลืองนี้ยังเป็นปลายทางฝั่งตะวันออกของเส้นทางสายไหม พิพิธภัณฑ์และโบราณสถานของเมืองเก็บรักษาความทรงจำแห่งจักรวรรดิที่สั่งสมมานับพันปี'),
  'shantou/gongfutea': ('ชาฉงฟู', 'ชากังฟูของแถบเฉาซ่านคือศิลปะพิธีการชงชา ที่รินชาลงจอกใบจิ๋วแล้วดื่มและชงซ้ำเป็นรอบ ๆ อย่างพิถีพิถัน การยกน้ำชาให้แขกที่นี่คือการแสดงความเคารพอย่างลึกซึ้งที่สุด และธรรมเนียมการจัดจอกสามใบพร้อมท่วงท่าอันประณีตก็ถ่ายทอดจากรุ่นสู่รุ่นอย่างไม่ขาดสาย'),
  'shantou/beefpot': ('หม้อไฟเนื้อ', 'หม้อไฟเนื้อแบบแต้จิ๋วเลื่องชื่อเรื่องความทุ่มเทต่อความสด เนื้อวัวที่ชำแหละวันต่อวันจะถูกแยกตามส่วนต่าง ๆ แล้วจุ่มลวกในน้ำซุปใสเพียงไม่กี่วินาที เนื้อแต่ละส่วนมีเวลาลวกเฉพาะของตัวเองอย่างแม่นยำ ก่อนนำไปจิ้มน้ำจิ้มสะเต๊ะหอมมันถั่ว ที่ช่วยขับความหวานธรรมชาติของเนื้อให้เด่นชัดยิ่งขึ้น'),
  'shantou/opera': ('งิ้วแต้จิ๋ว', 'งิ้วแต้จิ๋วซึ่งมีประวัติยาวนานหลายศตวรรษ ตรึงใจผู้ชมด้วยท่วงทำนองอ่อนหวานที่ขับร้องเป็นภาษาแต้จิ๋ว และเครื่องแต่งกายปักลวดลายวิจิตรตระการตา ศิลปะการแสดงนี้เดินทางข้ามน้ำข้ามทะเลไปกับชาวแต้จิ๋วโพ้นทะเล แพร่หลายทั่วเอเชียตะวันออกเฉียงใต้ และยังคงเชื่อมโยงชุมชนเข้ากับรากเหง้าของตนจนทุกวันนี้'),
  'shantou/harbor': ('เมืองท่าซัวเถา', 'ท่าเรือซัวเถาซึ่งเปิดรับการค้าต่างชาติในศตวรรษที่สิบเก้า กลายเป็นประตูที่ชาวแต้จิ๋วนับไม่ถ้วนอพยพออกสู่โพ้นทะเล ครอบครัวเชื้อสายจีนมากมายทั่วเอเชียตะวันออกเฉียงใต้สืบรากเหง้ามาจากที่นี่ สายใยนี้ยังถูกจารึกไว้ในจดหมาย \'เคียวพี\' ที่ผู้อพยพเคยส่งกลับมายังบ้านเกิดพร้อมเงินทองและความคิดถึง'),
  'baoding/mansion': ('จวนผู้ว่าการเป่าติ้ง', 'จวนข้าหลวงจื๋อลี่คือที่ว่าการของเหล่าอุปราชผู้ปกครองมณฑลจื๋อลี่ ดินแดนที่โอบล้อมเมืองหลวงของจักรวรรดิในสมัยราชวงศ์ชิง บุคคลผู้ทรงอิทธิพลอย่างหลี่หงจางและหยวนซื่อไข่เคยดำรงตำแหน่งที่นี่ ลานและโถงต่าง ๆ ที่ได้รับการอนุรักษ์ไว้อย่างดีจึงเป็นบันทึกที่มีชีวิตของการปกครองหัวเมืองในยุคจักรวรรดิ'),
  'baoding/donkeyburger': ('ขนมปังเนื้อลา', '\'ลฺหวีโร่วหั่วเซา\' คือแซนด์วิชเนื้อลา ทำจากเนื้อลาปรุงเครื่องเทศตุ๋นไฟอ่อนจนนุ่ม ยัดใส่แป้งอบใหม่กรอบร้อนจากเตา คำกล่าวท้องถิ่นยกย่องอาหารนี้ว่า \'บนฟ้ามีเนื้อมังกร บนดินมีเนื้อลา\' นี่คือสตรีทฟู้ดที่โด่งดังที่สุดของเป่าติ้ง และเป็นความภาคภูมิใจอันแรงกล้าของคนท้องถิ่น'),
  'baoding/balls': ('ลูกเหล็กเป่าติ้ง', 'ลูกบอลสุขภาพเป่าติ้ง ที่ใช้หมุนคลึงในอุ้งมือ เป็นอุปกรณ์บริหารมือแบบดั้งเดิมที่ผลิตกันมาตั้งแต่สมัยราชวงศ์หมิง แผ่นเสียงภายในจะส่งเสียงกังวานสองโทน โทนหนึ่งสูงโทนหนึ่งต่ำขณะลูกบอลหมุน และเชื่อกันว่าการฝึกเป็นประจำช่วยบำรุงทั้งความคล่องแคล่วของนิ้วมือและจิตใจที่สงบมีสมาธิ'),
  'baoding/reeds': ('บึงไป๋หยางเตี้ยน', 'ไป๋หยางเตี้ยน หนึ่งในพื้นที่ชุ่มน้ำที่ใหญ่ที่สุดของจีนตอนเหนือ คือเขาวงกตของบึงน้ำหลายร้อยแห่งที่เชื่อมถึงกันด้วยลำคลองขนาบด้วยดงอ้อ ฤดูร้อนดอกบัวจะบานสะพรั่งทั่วผืนน้ำ ขณะที่ดงอ้อดังก้องด้วยเสียงนกร้อง ชาวบ้านยังคงหาปลาและเกี่ยวต้นอ้อจากเรือลำเรียว ที่นี่จึงได้สมญาว่า \'ไข่มุกแห่งแดนเหนือ\''),
  'jilin/rime': ('ปรากฏการณ์น้ำค้างแข็งจี๋หลิน', 'ในคืนฤดูหนาว ไอน้ำที่ลอยขึ้นจากแม่น้ำซงฮวาซึ่งไม่ยอมกลายเป็นน้ำแข็ง จะจับตัวบนกิ่งไม้ริมฝั่งเป็นเกล็ดน้ำแข็งขาวใสราวผลึก ปรากฏการณ์นี้เรียกว่า \'อู้ซง\' นับเป็นหนึ่งในสี่สิ่งมหัศจรรย์ทางธรรมชาติของจีน และเมื่อแสงอรุณสาดส่อง ต้นไม้เคลือบเงินก็ระยิบระยับราวฉากในเทพนิยาย'),
  'jilin/snowboard': ('สกีรีสอร์ตจี๋หลิน', 'ด้วยฤดูหนาวที่ยาวนานและหิมะหนา จี๋หลินจึงเป็นหนึ่งในภูมิภาคกีฬาฤดูหนาวชั้นนำของจีน รีสอร์ตทันสมัยตามเทือกเขาโดยรอบดึงดูดนักสกีและนักสโนว์บอร์ดด้วยหิมะแป้งแห้งคุณภาพเยี่ยม และพื้นที่แห่งนี้ยังบ่มเพาะนักกีฬาโอลิมปิกฤดูหนาวของประเทศมาแล้วมากมาย'),
  'jilin/meteorite': ('พิพิธภัณฑ์อุกกาบาต', 'ในปี 1976 อุกกาบาตลูกหนึ่งแตกกระจายกลางท้องฟ้าเหนือเมืองจี๋หลิน ก่อให้เกิดฝนอุกกาบาตหินครั้งใหญ่ที่สุดครั้งหนึ่งเท่าที่เคยบันทึกไว้ ชิ้นหลักที่หนักกว่าหนึ่งตันจัดแสดงอยู่ในพิพิธภัณฑ์อุกกาบาตของเมือง ที่ซึ่งผู้มาเยือนได้เผชิญหน้ากับแขกผู้มาเยือนจากห้วงอวกาศตัวจริงอย่างใกล้ชิด'),
  'jilin/skate': ('แม่น้ำซงฮวาแข็งตัว', 'เมื่อฤดูหนาวมาถึง แม่น้ำซงฮวาบางช่วงจะจับตัวเป็นน้ำแข็งหนา กลายเป็นลานสเกตกลางแจ้งของทั้งเมือง นักสเกตลื่นไถลผ่านไปมา ผู้เฒ่าผู้แก่ตีลูกข่างบนน้ำแข็ง เด็ก ๆ แข่งเลื่อนหิมะกันสนุกสนาน ในเดือนอันหนาวเหน็บ ริมแม่น้ำนี่เองคือแหล่งชุมนุมที่ครึกครื้นที่สุดของจี๋หลิน'),
  'ordos/khan': ('สุสานเจงกิสข่าน', 'สุสานเจงกีสข่านบนทุ่งหญ้าออร์ดอส สร้างขึ้นเพื่อรำลึกถึงมหาข่านผู้ยิ่งใหญ่ ภายใต้โดมสามหลังที่มีรูปทรงเหมือนกระโจมมองโกล เหล่าผู้พิทักษ์ชาวดาร์ฮัดดูแลไฟพิธีและเครื่องเซ่นสักการะที่นี่มาหลายศตวรรษ ทำให้สุสานแห่งนี้เป็นหนึ่งในสถานที่ศักดิ์สิทธิ์ที่สุดของวัฒนธรรมมองโกล'),
  'ordos/cashmere': ('ผ้าแคชเมียร์เออร์โดส', 'แพะที่ทนทานผ่านฤดูหนาวอันโหดร้ายของทุ่งหญ้าสเตปป์ออร์ดอส จะสร้างขนชั้นในเส้นละเอียดที่ให้แคชเมียร์คุณภาพดีที่สุดในโลกส่วนหนึ่ง เส้นใยที่ได้ชื่อว่า \'ทองคำนุ่ม\' นี้ทำให้เมืองกลายเป็นศูนย์กลางการผลิตแคชเมียร์ระดับโลก เปลี่ยนประเพณีการเลี้ยงปศุสัตว์ให้กลายเป็นอุตสาหกรรมสินค้าหรูสมัยใหม่'),
  'ordos/sanddune': ('เนินทรายร้องเพลง', 'เนินทรายสูงตระหง่านของทะเลทรายคูปู้ฉีจะส่งเสียงหึ่งก้องทุ้มลึกเมื่อคุณลื่นไถลลงมาตามลาดทราย จึงได้ชื่อว่า \'ทรายร้องเพลง\' ผู้มาเยือนข้ามเนินทรายด้วยขบวนอูฐหรือเล่นกระดานโต้ทราย และเมื่อตะวันลับฟ้า ทะเลทรายก็เรืองสีทองในความเงียบสงัดราวบทกวี'),
  'ordos/yurt': ('กระโจมมองโกล', 'กระโจมมองโกลทรงกลมที่หุ้มด้วยผ้าสักหลาดขาว ถูกออกแบบให้ต้านทานลมแรงแห่งทุ่งหญ้าสเตปป์ แต่ก็พับเก็บเคลื่อนย้ายได้ง่ายเมื่อถึงคราวอพยพครั้งต่อไป ประตูกระโจมหันหน้าไปทางทิศใต้ และเตาไฟตรงกลางคือหัวใจของชีวิตครอบครัว การได้ค้างคืนในกระโจมบนทุ่งหญ้าออร์ดอสคือวิธีลิ้มรสน้ำใจไมตรีของชาวเร่ร่อนที่ดีที่สุด'),
  'jining/confucius': ('วัดขงจื๊อ', 'เมืองชวีฟู่ในเขตจี้หนิงคือบ้านเกิดของขงจื๊อ มหาปราชญ์ผู้ยิ่งใหญ่ วิหารที่สร้างขึ้นเพื่อเทิดเกียรติท่าน คฤหาสน์ตระกูลข่งที่ลูกหลานเคยพำนัก และสุสานประจำตระกูลกลางป่าไม้ ได้รับการขึ้นทะเบียนเป็นมรดกโลกยูเนสโกร่วมกัน ลานต้นสนไซเปรสและศิลาจารึกโบราณคือประจักษ์พยานเงียบงันของความเคารพนับถือที่สืบเนื่องมากว่าสองพันปี'),
  'jining/barge': ('คลองต้ายวิ่นเหอ', 'จี้หนิงคือท่าเรือที่คึกคักบนคลองใหญ่ที่เชื่อมปักกิ่งกับหางโจว เมืองเจริญรุ่งเรืองมาหลายศตวรรษจากเรือลำเลียงธัญพืชและการค้าขายที่ไหลเวียนไม่ขาดสาย การค้าทางคลองนำความมั่งคั่งและวัฒนธรรมท่าน้ำอันมีชีวิตชีวามาสู่เมือง และคลองช่วงตอนใต้ของเส้นทางน้ำอันยิ่งใหญ่นี้ก็ยังคงขนส่งสินค้าอยู่จนทุกวันนี้'),
  'jining/sword': ('วีรบุรุษเหลียงซาน', 'ในวรรณกรรมคลาสสิกเรื่อง \'ซ้องกั๋ง\' วีรบุรุษ 108 คนที่ถูกขุนนางฉ้อฉลกลั่นแกล้ง มารวมตัวกันบนเขาเหลียงซานที่ล้อมรอบด้วยบึงน้ำ เหล่าผู้กล้านอกกฎหมายภายใต้การนำของซ่งเจียง ต่อสู้เพื่อคนยากไร้และต่อต้านผู้กดขี่ ปัจจุบันเหลียงซานต้อนรับผู้มาเยือนด้วยสถานที่ต่าง ๆ ที่ชวนให้รำลึกถึงฉากในตำนานของนิยายเรื่องนี้'),
  'jining/fishnet': ('ทะเลสาบเวยซาน', 'ทะเลสาบเวยซาน หนึ่งในทะเลสาบน้ำจืดที่ใหญ่ที่สุดของจีนตอนเหนือ จะถูกปกคลุมด้วยทุ่งดอกบัวที่ทอดยาวสุดขอบฟ้าในทุกฤดูร้อน ครอบครัวชาวประมงยังคงทอดแหด้วยวิธีที่สืบทอดกันมาหลายชั่วอายุคน ใช้ชีวิตตามจังหวะของทะเลสาบ และครัวท้องถิ่นก็ยกย่องปลาสดกับรากบัวกรุบกรอบเป็นของขึ้นชื่อ'),
  'langfang/culture': ('ศูนย์วัฒนธรรมเส้นทางสายไหม', 'ศูนย์วัฒนธรรมสมัยใหม่ขนาดมหึมาของหลางฝาง เมืองที่ตั้งอยู่ระหว่างปักกิ่งกับเทียนจิน รวบรวมนิทรรศการธีมเส้นทางสายไหม ศิลปะการแสดง และงานหัตถกรรมไว้ใต้ชายคาเดียวกัน อาคารที่ได้แรงบันดาลใจจากสุนทรียะแห่งเส้นทางกองคาราวานโบราณนี้ เป็นสัญลักษณ์บทบาทของเมืองในฐานะสะพานวัฒนธรรมเชื่อมสองมหานคร'),
  'langfang/furniture': ('เมืองเฟอร์นิเจอร์', 'อำเภอเซียงเหอในหลางฝางติดอันดับศูนย์กลางการผลิตและค้าเฟอร์นิเจอร์ที่ใหญ่ที่สุดของจีน โชว์รูมและโรงช่างทอดยาวต่อเนื่องหลายกิโลเมตร มีให้เลือกครบทุกแนวตั้งแต่งานไม้พะยูงเข้าเดือยแบบคลาสสิกไปจนถึงดีไซน์สมัยใหม่ ครอบครัวที่กำลังแต่งบ้านจากทั่วจีนตอนเหนือล้วนมุ่งหน้ามาจับจ่ายที่นี่'),
  'langfang/tunnel': ('อุโมงค์สงครามโบราณ', 'ตามแนวชายแดนเก่าระหว่างราชวงศ์ซ่งกับอาณาจักรเหลียวทางเหนือ มีการขุดโครงข่ายอุโมงค์ลับใต้ดินไว้เพื่อการป้องกันเมือง ทางเดินกรุอิฐเหล่านี้ยืนหยัดมาราวหนึ่งพันปี พร้อมช่องระบายอากาศและห้องซุ่มโจมตี เป็นประจักษ์พยานใต้พิภพของสงครามชายแดนในยุคโบราณ'),
  'langfang/themepark': ('อุทยานเมืองอันดับหนึ่ง', '\'เทียนเซี่ยตี้อีเฉิง\' หรือ \'เมืองอันดับหนึ่งใต้หล้า\' คือสวนสนุกขนาดมหึมาที่จำลองกำแพงและประตูเมืองปักกิ่งโบราณขึ้นใหม่อย่างยิ่งใหญ่อลังการ ด้วยงานวัดแบบดั้งเดิม การแสดงพื้นบ้าน และสถาปัตยกรรมคลาสสิก ที่นี่พาครอบครัวออกเดินทางย้อนเวลาสู่อดีตอันรุ่งโรจน์ของราชธานี'),
  'yancheng/salt': ('เมืองแห่งเกลือ', 'ชื่อเมืองเหยียนเฉิงแปลว่า \'เมืองเกลือ\' นาเกลือชายฝั่งของเมืองเคยเติมเต็มท้องพระคลังของจักรวรรดิมาหลายศตวรรษ เกลือที่ได้จากการตากน้ำทะเลให้ระเหยกลางแดดได้กำหนดชะตากรรมของเมืองนี้ และมรดกดังกล่าวยังมีชีวิตอยู่ในพิพิธภัณฑ์ ชื่อสถานที่ และเรื่องเล่าพื้นบ้านจนทุกวันนี้'),
  'yancheng/crane': ('นกกระเรียนมงกุฎแดง', 'พื้นที่ชุ่มน้ำชายฝั่งของเหยียนเฉิงคือแหล่งพักพิงฤดูหนาวที่ใหญ่ที่สุดในโลกของนกกระเรียนมงกุฎแดงป่า นกสง่างามชนิดนี้เป็นสัญลักษณ์แห่งความยืนยาวและความสง่าผ่าเผยในวัฒนธรรมจีน พวกมันอพยพจากแดนเหนือมาที่นี่ทุกฤดูหนาว และท่วงท่าโผบินช้า ๆ เหนือดงอ้อของพวกมันก็ตราตรึงใจนักดูนกยิ่งนัก'),
  'yancheng/elk': ('กวางมิลู่', 'กวางมิลู่เคยสูญพันธุ์ไปจากธรรมชาติของจีน เหลือรอดเพียงในสวนสัตว์ต่างแดนเท่านั้น เมื่อถูกนำกลับมาปล่อยในเขตอนุรักษ์ต้าเฟิงของเหยียนเฉิง กวางชนิดนี้ก็แพร่พันธุ์เจริญงอกงาม ปัจจุบันฝูงมิลู่ที่ใหญ่ที่สุดในโลกท่องไปอย่างอิสระบนทุ่งหญ้าชุ่มน้ำชายฝั่งแห่งนี้ นับเป็นชัยชนะอันงดงามของงานอนุรักษ์'),
  'yancheng/wetland': ('พื้นที่ชุ่มน้ำชายฝั่ง', 'หาดโคลนน้ำขึ้นน้ำลงตามชายฝั่งทะเลเหลืองคือจุดแวะพักขนาดมหึมาของนกอพยพ ซึ่งได้รับการขึ้นทะเบียนเป็นมรดกโลกของยูเนสโก นกชายเลนหลายล้านตัวบนเส้นทางบินเอเชียตะวันออก-ออสตราเลเซียมาพักผ่อนและหาอาหารที่นี่ เติมเต็มผืนหาดโคลนด้วยเสียงกระพือปีกในทุกฤดูใบไม้ผลิและใบไม้ร่วง'),
  'huzhou/brush': ('พู่กันหู', 'พู่กันหูที่ผลิตในหูโจวคือพู่กันจีนที่ได้รับการยกย่องสูงสุด และเป็นหนึ่งใน \'สี่สมบัติล้ำค่าแห่งห้องหนังสือ\' ปลายพู่กันทำจากขนแพะ ขนกระต่าย และขนวีเซิล ต้องผ่านขั้นตอนอันพิถีพิถันหลายสิบขั้นจนได้หัวพู่ที่ทั้งแหลมคมและยืดหยุ่น เหล่านักอักษรศิลป์จึงหวงแหนพู่กันนี้ยิ่งกว่าสิ่งใด'),
  'huzhou/bamboo': ('ทะเลไผ่อานจี๋', 'ป่าไผ่ที่ปกคลุมเนินเขาแห่งอันจี๋พลิ้วไหวตามสายลมราวทะเลสีเขียวอันไร้ขอบเขต ป่าแห่งนี้คือฉากถ่ายทำอันน่าจดจำของภาพยนตร์เรื่อง \'พยัคฆ์ระห่ำ มังกรผยองโลก\' และยังชุบชูใจผู้มาเยือนด้วยอากาศเย็นสดชื่น เส้นทางเดินป่า และอาหารท้องถิ่นที่รังสรรค์จากหน่อไม้อ่อนนุ่ม'),
  'huzhou/silkworm': ('หนอนไหม', 'หูโจวบนชายฝั่งทางใต้ของทะเลสาบไท่หู เป็นดินแดนหัวใจของการเลี้ยงไหมด้วยใบหม่อนมานานหลายพันปี ระบบการผลิตดั้งเดิมที่จับคู่สวนหม่อนกับบ่อเลี้ยงปลาของที่นี่ ปัจจุบันได้รับการยกย่องเป็นมรดกทางการเกษตรระดับโลก และผ้าไหมหูโจวก็เคยเป็นอาภรณ์ของจักรพรรดิและราชสำนักมาแล้วในอดีต'),
  'huzhou/whitetea': ('ชาขาวอานจี๋', 'ชาขาวอันจี๋แท้จริงแล้วคือชาเขียว ทำจากพันธุ์ชาหายากที่ใบอ่อนฤดูใบไม้ผลิแตกยอดออกมาสีซีดจางจนดูเกือบขาว ชานี้เป็นที่รักของคอชาด้วยรสหวานสดชื่นอ่อนละมุนและความฝาดต่ำ ช่วงเก็บเกี่ยวอันแสนสั้นของมันยิ่งทำให้เป็นหนึ่งในชาที่ถูกตามหามากที่สุดของจีน'),
  'quzhou/go': ('หมากล้อม (เว่ยฉี)', 'ตำนานเล่าถึงคนตัดฟืนบนเขาหลานเคอ ผู้เฝ้าดูเซียนสององค์เล่นหมากล้อมอย่างเพลิดเพลินจนกาลเวลาผ่านไปเนิ่นนาน กระทั่งด้ามขวานของเขาผุพังไป ด้วยตำนานนี้ ชวีโจวจึงได้รับการเคารพในฐานะดินแดนศักดิ์สิทธิ์ของหมากล้อม และเกมกลยุทธ์โบราณนี้ก็ยังได้รับการเฉลิมฉลองอย่างภาคภูมิทั่วทั้งเมือง'),
  'quzhou/peaks': ('ภูเขาเจียงหลาง', 'เสาหินมหึมาสามต้นของเขาเจียงหลางตั้งตระหง่านพุ่งขึ้นสู่ท้องฟ้าจากผืนป่าเขียวขจี ภูเขานี้เป็นตัวอย่างอันโดดเด่นของภูมิประเทศหินทรายแดงแบบ \'ตันเซี๋ย\' จนได้รับการขึ้นทะเบียนเป็นมรดกโลกยูเนสโก และการเดินผ่านซอกผาแคบ ๆ ระหว่างเสาหินทั้งสามก็เป็นประสบการณ์ที่ชวนเวียนหัวไม่น้อยเลย'),
  'quzhou/ponkan': ('ส้มพอนคานฉวีโจว', 'ส้มพอนกันที่ปลูกบนเนินเขาอากาศอบอุ่นของชวีโจว ขึ้นชื่อเรื่องเปลือกที่ปอกง่ายและกลีบเนื้อหวานฉ่ำราวน้ำผึ้ง ปลายฤดูใบไม้ร่วงสวนส้มจะลุกโชนเป็นสีส้มทั่วทั้งเนิน ฤดูเก็บเกี่ยวพาสมาชิกครอบครัวมาพบกันใต้ร่มเงาต้นส้ม และผลส้มนี้ก็แต่งแต้มความสดใสให้โต๊ะอาหารฤดูหนาวทั่วทั้งภูมิภาค'),
  'quzhou/cake': ('ขนมปังแบนอบ', 'แผ่นแป้งอบของชวีโจวทำโดยแปะก้อนแป้งหมักลงบนผนังด้านในอันร้อนระอุของเตาอบทรงถัง ใต้เปลือกกรอบเคลือบงาซ่อนไส้เค็มหอมรสกลมกล่อมเอาไว้ และภาพผู้คนต่อแถวหน้าร้านทุกเช้าก็บอกได้ดีว่า ชาวเมืองรักการเริ่มต้นวันใหม่ด้วยแป้งอบร้อน ๆ นี้เพียงใด'),
  'huainan/tofu': ('แหล่งกำเนิดเต้าหู้', 'ตำนานยกความดีความชอบการคิดค้นเต้าหู้ให้เหล่านักเล่นแร่แปรธาตุของเจ้าชายหลิวอันบนเขาปากงในสมัยราชวงศ์ฮั่น เมื่อน้ำเต้าหู้ถูกทำให้จับตัวเป็นก้อนครั้งแรก อาหารแสนเรียบง่ายที่ถือกำเนิดที่นี่เมื่อราวสองพันปีก่อน ได้แพร่หลายไปสู่ครัวทั่วโลก และหวยหนานก็เฉลิมฉลองมรดกนี้ด้วยเทศกาลเต้าหู้ประจำปี'),
  'huainan/coalmine': ('เมืองถ่านหิน', 'หวยหนานซึ่งตั้งอยู่เหนือสายแร่ถ่านหินอันอุดมสมบูรณ์ เป็นฐานพลังงานของจีนตะวันออกมาช้านาน เหมืองและโรงไฟฟ้าของเมืองหล่อเลี้ยงโครงข่ายไฟฟ้าของภูมิภาค ขณะเดียวกันเมืองก็ทยอยเปลี่ยนพื้นที่เหมืองเก่าให้กลายเป็นทะเลสาบและสวนสาธารณะ นำพามรดกอุตสาหกรรมมุ่งสู่อนาคตที่เขียวขจียิ่งขึ้น'),
  'huainan/oldtown': ('เมืองเก่าโช่วเซี่ยน', 'เมืองเก่าโซ่วเซี่ยนคือหนึ่งในเมืองจีนไม่กี่แห่งที่กำแพงเมืองสมัยราชวงศ์ซ่งยังคงอยู่ครบสมบูรณ์ กำแพงอิฐหนาและประตูโค้งของเมืองถึงกับเคยปกป้องชาวเมืองจากอุทกภัยมาแล้ว ส่วนถนนหนทางภายในกำแพงยังเก็บรักษาร่องรอยของรัฐฉู่โบราณ ซึ่งเคยตั้งราชธานีแห่งสุดท้ายไว้ที่นี่'),
  'huainan/classic': ('หวยหนานจื่อ', 'หวยหนานจื่อคือคัมภีร์ปรัชญาคลาสสิกที่เรียบเรียงโดยเหล่าปราชญ์ในราชสำนักของหลิวอัน เจ้าชายแห่งหวยหนานในสมัยราชวงศ์ฮั่น คัมภีร์นี้ผสานความคิดลัทธิเต๋า จักรวาลวิทยา และศาสตร์การปกครองเข้าด้วยกัน ทั้งยังเก็บรักษาตำนานอันเป็นที่รักอย่างเรื่องเทพธิดาหนี่วาซ่อมแซมฟ้าที่แตกร้าวไว้ให้คนรุ่นหลังด้วย'),
  'jingdezhen/porcelain': ('นครแห่งเครื่องเคลือบดินเผา', 'จิ่งเต๋อเจิ้นเผาเครื่องกระเบื้องมานานกว่าหนึ่งพันปี ในฐานะศูนย์กลางเตาเผาหลวง เมืองนี้ส่งชิ้นงานอันประณีตที่สุดถวายราชสำนักมาโดยตลอด ดินขาวเกาลิน วัตถุดิบสำคัญของเครื่องกระเบื้อง ก็ได้ชื่อมาจากหมู่บ้านเกาหลิงใกล้เมืองนี้เอง และทุกวันนี้จิ่งเต๋อเจิ้นยังคงดึงดูดศิลปินเซรามิกจากทั่วทุกมุมโลก'),
  'jingdezhen/kiln': ('เตาเผาโบราณ', 'ที่แหล่งมรดกเตาเผาโบราณ เตาเผาฟืนแบบดั้งเดิมและโรงช่างหัตถกรรมยังคงสืบสานเทคนิคเก่าแก่ให้มีชีวิต จากเตามังกรที่ทอดยาวไปตามไหล่เขาจนถึงเตาทรงไข่ ผู้มาเยือนได้ติดตามบททดสอบด้วยไฟของเครื่องกระเบื้องอย่างใกล้ชิด ขณะที่เหล่านายช่างขึ้นรูป เคลือบ และวาดลวดลายให้ชมกันตรงหน้า'),
  'jingdezhen/bluewhite': ('เครื่องลายคราม', '\'ชิงฮวา\' หรือเครื่องลายคราม คือการวาดลวดลายสีน้ำเงินโคบอลต์ใต้เคลือบบนเนื้อกระเบื้องขาวบริสุทธิ์ อันเป็นลายเซ็นระดับโลกของจิ่งเต๋อเจิ้น ศิลปะแขนงนี้บรรลุความสมบูรณ์แบบในสมัยราชวงศ์หยวนและหมิง ก่อนเดินทางไปทั่วโลกผ่านเส้นทางสายไหมและเส้นทางเดินเรือ จนกลายเป็นของสะสมสุดหลงใหลในราชสำนักยุโรป'),
  'jingdezhen/painting': ('จิตรกรรมเครื่องเคลือบดินเผา', 'ในจิ่งเต๋อเจิ้น เครื่องกระเบื้องไม่ใช่แค่ภาชนะ แต่คือผืนผ้าใบ เหล่านายช่างใช้พู่กันเส้นละเอียดที่สุดวาดทิวทัศน์ นก และบทกวีลงบนพื้นผิว เทคนิคอย่างการวาดใต้เคลือบและการลงยาบนเคลือบถ่ายทอดกันจากรุ่นสู่รุ่น และผลงานที่มีลายเซ็นของนายช่างก็ถูกสะสมประหนึ่งภาพจิตรกรรมชั้นครู'),
  'jian/jinggang': ('เทือกเขาจิ่งกัง', 'เทือกเขาจิ่งกังที่ปกคลุมด้วยสายหมอก คือที่ตั้งฐานที่มั่นชนบทแห่งแรกของการปฏิวัติจีน ซึ่งก่อตั้งขึ้นในปี 1927 ปัจจุบันเทือกเขานี้เป็นหัวใจของ \'การท่องเที่ยวสีแดง\' ต้อนรับผู้มาเยือนด้วยสถานที่ทางประวัติศาสตร์ เคียงคู่กับน้ำตก ป่าไผ่ และทะเลเมฆที่ม้วนตัวอยู่เบื้องล่างยอดเขา'),
  'jian/torch': ('ประกายไฟปฏิวัติ', 'คำกล่าวที่ว่า \'ประกายไฟเพียงดวงเดียวก็ลามทุ่งได้ทั้งผืน\' บอกเล่าการแผ่ขยายของการปฏิวัติจากเทือกเขาแห่งนี้ไปทั่วประเทศ อนุสรณ์สถาน พิพิธภัณฑ์ และกองบัญชาการที่อนุรักษ์ไว้ในเขตจิ่งกังบันทึกการต่อสู้อันยากลำบากในยุคนั้น ขณะที่นักเดินป่าก็ได้เดินตามเส้นทางประวัติศาสตร์ท่ามกลางทิวทัศน์ขุนเขาอันกว้างใหญ่'),
  'jian/academy': ('สถาบันไป๋ลู่โจว', 'สำนักศึกษาไป๋ลู่โจว ก่อตั้งขึ้นในสมัยราชวงศ์ซ่งบนเกาะกลางแม่น้ำก้าน ได้บ่มเพาะบัณฑิตมาหลายศตวรรษ หนึ่งในนั้นคือเหวินเทียนเสียง วีรบุรุษของชาติ ลานอันเงียบสงบที่มีสายน้ำโอบล้อมทุกด้าน ยังคงเป็นความทรงจำอันงดงามของประเพณีการศึกษาแบบคลาสสิกของจีน'),
  'jian/pine': ('สนจิ่งกัง', 'ต้นสนที่หยั่งรากบนไหล่ผาสูงชันของเทือกเขาจิ่งกัง ยืนต้นมั่นคงท้าทายทั้งหมอกและสายลม ต้นไม้ที่เติบโตด้วยการเกาะเกี่ยวหินเปลือยเปล่าเหล่านี้ กลายเป็นสัญลักษณ์ของความทรหดอดทนและความหวัง และภาพเงาต้นสนที่โผล่พ้นทะเลเมฆยามรุ่งอรุณก็เป็นทัศนียภาพที่ยากจะลืมเลือน'),
  'nanping/wuyi': ('ภูเขาอู่อี๋', 'เทือกเขาอู่อี๋ ด้วยหน้าผาสีแดงชาด หุบเขาเขียวขจี และลำธารใสที่คดเคี้ยวไปมาระหว่างกลาง ได้รับการขึ้นทะเบียนมรดกโลกยูเนสโกทั้งด้านธรรมชาติและวัฒนธรรม จารึกโบราณบนหน้าผา ไร่ชาขั้นบันได และร่องรอยสำนักศึกษาของจูซี ล้วนถักทอเทือกเขานี้เข้าเป็นส่วนหนึ่งของประวัติศาสตร์ภูมิปัญญาจีนด้วย'),
  'nanping/rocktea': ('ชาต้าหงเผา', 'ต้าหงเผา หรือ \'จีวรแดงผืนใหญ่\' คือราชันแห่ง \'ชาหิน\' ชาอูหลงที่ปลูกในดินอุดมแร่ธาตุบนหน้าผาอู่อี๋ ใบชาจากต้นแม่พันธุ์เก่าแก่ที่เกาะอยู่บนหน้าผาหินเคยถูกประมูลในราคาระดับตำนาน และรสชาติลุ่มลึกหอมกลิ่นคั่วไฟของชานี้ก็ได้รับความเคารพอย่างสูงในหมู่คนรักชาทั่วโลก'),
  'nanping/bambooraft': ('แพไม้ไผ่เก้าโค้ง', 'ธารเก้าโค้งไหลคดเคี้ยวผ่านหน้าผาสีแดงของเทือกเขาอู่อี๋เป็นโค้งใหญ่เก้าโค้ง ผู้มาเยือนนั่งแพไม้ไผ่ที่คนแจวถ่อนำทาง ล่องผ่านโลงศพรูปเรือโบราณอันลี้ลับซึ่งฝังอยู่สูงลิบบนซอกผา พลางชมทิวทัศน์ที่เปลี่ยนโฉมไปในทุก ๆ โค้งน้ำ'),
  'nanping/scholar': ('จูซี', 'จูซี ปรมาจารย์ผู้ยิ่งใหญ่แห่งลัทธิขงจื๊อใหม่ ใช้ชีวิตส่วนใหญ่อยู่แถบเทือกเขาอู่อี๋ ก่อตั้งสำนักศึกษาและอบรมสั่งสอนศิษย์ที่นี่ คำสอนของท่านซึ่งตีความปรัชญาขงจื๊อขึ้นใหม่ ได้หล่อหลอมระบบการศึกษาและการสอบคัดเลือกขุนนางทั่วจีนและเอเชียตะวันออกมานานหลายศตวรรษ'),
  'shenzhen/skyscraper': ('ตึกระฟ้า', 'เซินเจิ้นซึ่งเมื่อสี่สิบปีก่อนยังเป็นหมู่บ้านชาวประมง กลายร่างเป็นป่าตึกระฟ้าหลังได้รับการประกาศให้เป็นเขตเศรษฐกิจพิเศษแห่งแรกของจีน เส้นขอบฟ้าที่มีตึกผิงอันพุ่งเสียดเมฆเป็นมงกุฎ คือสัญลักษณ์ของความเร็วแห่งยุคปฏิรูป ผู้คนที่นี่พูดถึง \'ความเร็วเซินเจิ้น\' ที่ตึกสูงขึ้นทีละชั้นได้ในชั่วข้ามคืน'),
  'shenzhen/chip': ('เมืองเทคโนโลยี', 'ในตลาดอิเล็กทรอนิกส์หัวเฉียงเป่ย ชิป แผงวงจร และชิ้นส่วนโดรนไหลเวียนจากแผงหนึ่งสู่อีกแผงหนึ่ง ยักษ์ใหญ่อย่างเทนเซ็นต์ หัวเว่ย และดีเจไอต่างเติบโตขึ้นในเมืองนี้ ที่ \'ซิลิคอนแวลลีย์ของจีน\' ไอเดียกลายเป็นต้นแบบได้ภายในไม่กี่วัน เซินเจิ้นคือเมืองหลวงโลกของสตาร์ทอัพสายฮาร์ดแวร์'),
  'shenzhen/miniature': ('หน้าต่างโลก', 'สวนสนุก \'หน้าต่างสู่โลก\' รวบรวมสิ่งก่อสร้างชื่อดังของโลกในขนาดจำลอง ตั้งแต่หอไอเฟลไปจนถึงพีระมิด คุณเดินข้ามทวีปได้ในบ่ายวันเดียว \'หอไอเฟล\' ประจำสวนจะเปิดไฟสว่างไสวยามค่ำคืน สะท้อนจิตวิญญาณขี้เล่นแต่ทะเยอทะยานของเซินเจิ้นได้อย่างครบถ้วน'),
  'shenzhen/mangrove': ('อ่าวเซินเจิ้น', 'ป่าชายเลนของอ่าวเซินเจิ้นที่ทอดตัวอยู่ใต้เงาตึกระฟ้า คือจุดแวะพักสำคัญของนกบนเส้นทางอพยพ นกยางขาวและนกชายฝั่งหากินอยู่บนหาดเลน ขณะทางเดินเลียบชายฝั่งของสวนสาธารณะมอบภาพหายากแก่ชาวเมือง ที่ธรรมชาติกับมหานครยืนเคียงข้างกัน'),
  'xian/terracotta': ('กองทัพทหารดินเผา', 'ทหารดินเผานับพันที่เฝ้าสุสานจิ๋นซีฮ่องเต้ถูกค้นพบโดยบังเอิญในปี 1974 โดยชาวบ้านที่กำลังขุดบ่อน้ำ ใบหน้าของทหารแต่ละนายไม่ซ้ำกันเลย กองทัพที่ยืนเรียงแถวอย่างเงียบงันนี้แสดงถึงอำนาจของจักรพรรดิผู้แสวงหาความเป็นอมตะ และได้รับสมญาว่าสิ่งมหัศจรรย์อันดับแปดของโลก'),
  'xian/citywall': ('กำแพงเมืองซีอาน', 'กำแพงเมืองสมัยราชวงศ์หมิงของซีอานคือกำแพงเมืองที่คงสภาพสมบูรณ์ที่สุดในจีน ตัวกำแพงหนาแน่นโอบล้อมเมืองเก่าเป็นรูปสี่เหลี่ยมผืนผ้าไม่ขาดตอน การเช่าจักรยานปั่นบนกำแพงคือประสบการณ์คลาสสิกของซีอาน จากหอสังเกตการณ์ เมืองสมัยใหม่กับนครหลวงโบราณปรากฏอยู่ในภาพเดียวกัน'),
  'xian/drumtower': ('หอระฆัง', 'หอระฆังสมัยราชวงศ์หมิงที่ตั้งอยู่ใจกลางเมืองพอดี คือหัวใจของนครหลวงโบราณ ครั้งหนึ่งเสียงระฆังของหอเคยประกาศเวลาของแต่ละวัน เมื่อรวมกับหอกลองที่อยู่ใกล้กันและถนนอาหารของย่านมุสลิมที่อยู่ด้านหลัง ที่นี่จึงเป็นจัตุรัสที่คึกคักที่สุดของค่ำคืนซีอาน'),
  'xian/roujiamo': ('โร่วเจียหมัว', 'เนื้อตุ๋นเครื่องเทศนานหลายชั่วโมงยัดไส้ในแป้งอบกรอบ นี่คือเหตุผลที่โร่วเจียโหมวถูกเรียกว่า \'แฮมเบอร์เกอร์จีน\' อาหารริมทางเก่าแก่ของมณฑลส่านซีชิ้นนี้เข้ากันดีกับความเร่งรีบของนครหลวงแห่งเส้นทางสายไหม ถือกินได้ด้วยมือเดียว และเพียงสองคำก็เชื่อมคุณเข้ากับประเพณีรสชาติพันปี'),
  'suzhou/garden': ('สวนโบราณซูโจว', 'สวนคลาสสิกของซูโจวคือผลงานชั้นครูที่จำลองธรรมชาติไว้ในพื้นที่จำกัดด้วยภูเขาหินจำลอง สระน้ำ และศาลาพักผ่อน สวนที่งดงามที่สุดได้รับการขึ้นทะเบียนเป็นมรดกโลกของยูเนสโก หน้าต่างทุกบานถูกจัดวางราวกรอบภาพวาด การเดินในสวนจึงเหมือนการคลี่ม้วนภาพจิตรกรรมที่เปลี่ยนไปทุกย่างก้าว'),
  'suzhou/watertown': ('เมืองน้ำ', 'ด้วยลำคลอง สะพานหินหลังโค้ง และบ้านผนังปูนขาว ซูโจวจึงได้สมญาว่า \'เวนิสแห่งตะวันออก\' ตามตรอกเก่าอย่างถนนผิงเจียง สายน้ำไหลผ่านหน้าประตูบ้านพอดี ขณะล่องเรือช้า ๆ คุณจะได้ยินเสียงพิณผีผาและท่วงทำนองเพลงพื้นบ้านลอยมาจากโรงน้ำชา'),
  'suzhou/embroidery': ('ผ้าปักซูโจว', 'งานปักซูคืองานฝีมือพันปีของซูโจวที่ปักลงบนผ้าไหมด้วยเส้นด้ายเล็กละเอียดยิ่งกว่าเส้นผม ช่างชั้นครูสามารถปักลวดลายต่างกันบนผ้าผืนเดียวกันทั้งสองด้าน ศิลปะที่จับประกายขนแมวหรือเกล็ดปลาไว้ได้ด้วยปลายเข็มนี้ คือสัญลักษณ์แห่งความอดทนและความประณีตของเมือง'),
  'suzhou/kunqu': ('คุนฉวี่', 'อุปรากรคุนฉวี่ที่ได้รับยกย่องเป็นมารดาแห่งอุปรากรจีนทั้งปวง ถือกำเนิดในแถบซูโจว โดดเด่นด้วยท่วงทำนองที่ลื่นไหลดั่งสายน้ำและท่วงท่ามือที่งามสง่า ศิลปะแขนงนี้ได้รับการขึ้นทะเบียนเป็นมรดกวัฒนธรรมที่จับต้องไม่ได้ของยูเนสโก และยังคงถูกสืบสานในศาลากลางสวนและโรงละครเล็ก ๆ จนทุกวันนี้'),
  'kunming/stoneforest': ('ป่าหิน', 'เสาหินปูนยักษ์ที่สายน้ำกัดเซาะมานานหลายล้านปี ก่อตัวเป็นเขาวงกตที่เรียกว่า \'ป่าหิน\' ใกล้เมืองคุนหมิง ชาวซาหนีในท้องถิ่นเล่าขานหินผาเหล่านี้ผ่านตำนานอาชือหม่า หญิงสาวผู้งดงามที่กลายร่างเป็นหิน และยังคงยืนทักทายผู้มาเยือนในรูปของเสาหินต้นที่โด่งดังที่สุดจนทุกวันนี้'),
  'kunming/springcity': ('นครแห่งฤดูใบไม้ผลิ', 'บนที่ราบสูงยูนนาน ฤดูหนาวอ่อนโยนและฤดูร้อนเย็นสบาย คุนหมิงจึงได้ชื่อว่า \'นครแห่งฤดูใบไม้ผลิ\' ที่ดอกไม้ไม่เคยโรยรา เมืองนี้เป็นที่ตั้งของตลาดดอกไม้ใหญ่ที่สุดแห่งหนึ่งของเอเชีย แม้ตามหัวมุมถนนก็มีช่อดอกไม้สดวางขาย'),
  'kunming/seagull': ('นกนางนวลหัวดำ', 'ทุกฤดูหนาว นกนางนวลนับพันตัวบินมาจากไซบีเรีย ย้อมริมทะเลสาบและสวนสาธารณะของคุนหมิงให้ขาวโพลน การป้อนอาหารนกจากมือคือพิธีกรรมหน้าหนาวที่ชาวเมืองรัก การกลับมาของฝูงนางนวลถูกเฉลิมฉลองราวกับเป็นสัญญาณประกาศฤดูกาลใหม่ของคุนหมิงเลยทีเดียว'),
  'kunming/ricenoodle': ('ก๋วยเตี๋ยวข้ามสะพาน', 'ก๋วยเตี๋ยวข้ามสะพานคืออาหารประจำถิ่นของยูนนาน น้ำซุปร้อนจัดถูกยกมาเสิร์ฟที่โต๊ะ แล้วเส้นหมี่ข้าวกับเครื่องต่าง ๆ จะถูกใส่ลงชามต่อหน้าคุณ ตำนานเล่าว่าภรรยาผู้หนึ่งซึ่งต้องข้ามสะพานไปส่งอาหารให้สามีที่กำลังตั้งใจอ่านหนังสือ ได้คิดค้นวิธีเก็บความร้อนของน้ำซุปแบบนี้ขึ้นมา'),
  'jinan/spring': ('นครแห่งน้ำพุ', 'ที่จี่หนาน น้ำใต้ดินผุดพุ่งขึ้นสู่ผิวดินใจกลางเมืองพอดี น้ำพุที่โด่งดังที่สุดในบรรดาน้ำพุลือชื่อ 72 แห่งคือน้ำพุเป้าทูที่พวยพุ่งไม่หยุด ใน \'นครแห่งน้ำพุ\' แห่งนี้ น้ำใสไหลผ่านแม้ตามตรอกซอกซอยย่านเก่า และชาวเมืองยังภูมิใจที่ได้ชงชาด้วยน้ำพุธรรมชาติมาจนทุกวันนี้'),
  'jinan/daminglake': ('ทะเลสาบต้าหมิง', 'ทะเลสาบต้าหมิงที่หล่อเลี้ยงด้วยน้ำพุของเมือง คือโอเอซิสกลางเมืองที่ล้อมรอบด้วยต้นหลิวและดอกบัว ในฤดูร้อน เรือพายล่องไปมาระหว่างแปลงบัวที่เบ่งบาน ส่วนศาลาและโรงน้ำชาริมทะเลสาบยังคงสืบสานจังหวะชีวิตอันเชื่องช้าและงามสง่า ที่ทำให้จี่หนานมีชื่อเสียงในวรรณกรรมจีน'),
  'jinan/buddhamountain': ('ภูเขาพันพระพุทธรูป', 'พระพุทธรูปหลายร้อยองค์ถูกสลักลงบนไหล่เขาของภูเขาพระพันองค์ตลอดหลายศตวรรษ ภาพสลักที่เก่าแก่ที่สุดย้อนไปถึงราชวงศ์สุย ผู้มาเยือนที่ไต่ขึ้นไปตามเส้นทางจะได้ชมทั้งพระพุทธรูปในซอกหิน และทิวทัศน์กว้างไกลของจี่หนาน นครแห่งน้ำพุ จากบนยอดเขา'),
  'jinan/poet': ('หลี่ ชิงจ้าว', 'หลี่ชิงเจ้า ผู้ได้รับยกย่องเป็นกวีหญิงที่ยิ่งใหญ่ที่สุดของจีน ถือกำเนิดในนครแห่งน้ำพุแห่งนี้ในสมัยราชวงศ์ซ่ง บทกวีฉืออันละเมียดละไมแฝงความเศร้าของเธอบอกเล่าความรัก การพลัดถิ่น และการสูญเสีย หออนุสรณ์ข้างน้ำพุเป้าทูยังคงรักษาโลกแห่งเสียงน้ำไหลริน ที่ให้กำเนิดบทกวีของเธอไว้จนทุกวันนี้'),
  'ningbo/library': ('หอสมุดเทียนอีเกอ', 'หอเทียนอีเก๋อซึ่งก่อตั้งในสมัยราชวงศ์หมิง คือหอสมุดเอกชนเก่าแก่ที่สุดของเอเชียที่ยังคงอยู่ สร้างขึ้นโดยขุนนางผู้หลงใหลหนังสือ เพื่อปกป้องตำราหายากจากความชื้นและอัคคีภัย หอสมุดถูกออกแบบราวกับวิหารแห่งหนังสือ พร้อมสวน สระน้ำ และกฎตระกูลอันเข้มงวดว่าใครเข้าได้บ้าง'),
  'ningbo/port': ('ท่าเรือหนิงโป-โจวซาน', 'ท่าเรือหนิงโป-โจวซานคือท่าเรือที่คึกคักที่สุดในโลกเมื่อวัดตามปริมาณสินค้า แนวชายฝั่งกลายเป็นป่าเครื่องจักรที่เต็มไปด้วยเรือคอนเทนเนอร์ยักษ์และปั้นจั่นสูงตระหง่าน ประวัติการเดินเรือของหนิงโปหยั่งรากลึกยาวนาน เมืองนี้เคยเป็นหนึ่งในประตูต้นทางของเส้นทางสายไหมทางทะเลในยุคโบราณ'),
  'ningbo/tangyuan': ('ทังหยวน', 'ทังหยวนสไตล์หนิงโปคือขนมบัวลอยแป้งข้าวเหนียวเนื้อนุ่มลื่นไส้งาดำกวนหวานหอม กัดลงไปแล้วไส้อุ่น ๆ จะไหลเยิ้มออกมาเหมือนเซอร์ไพรส์เล็ก ๆ ขนมประจำเทศกาลโคมไฟชนิดนี้มีรูปทรงกลม สื่อถึงความกลมเกลียวและการได้กลับมาอยู่พร้อมหน้าของครอบครัว'),
  'ningbo/seafood': ('อาหารทะเล', 'หนิงโปซึ่งหันหน้าสู่ทะเลจีนตะวันออกจัดสำรับจากท้องทะเล ปลาจวดเหลือง ปู และหอยคือรากฐานของอาหารถิ่น ลิ้นของคนที่นี่เชิดชูสมดุล \'เค็ม-สด\' การนึ่งอย่างเรียบง่ายและการหมักดองอ่อน ๆ ที่ไม่กลบรสชาติแท้ของปลา คือลายเซ็นของครัวแห่งนี้'),
  'shijiazhuang/bridge': ('สะพานจ้าวโจว', 'สะพานเจ้าโจวที่สร้างขึ้นในสมัยราชวงศ์สุยโดยนายช่างหลี่ชุน คือสะพานโค้งหินแบบเปิดช่องเหนือโค้งที่เก่าแก่ที่สุดในโลก โค้งสะพานอันงามสง่านี้ยืนหยัดผ่านอุทกภัยและแผ่นดินไหวมาราว 1,400 ปี และถูกบรรจุในตำราเรียนในฐานะผลงานชิ้นเอกคลาสสิกของวิศวกรรมจีน'),
  'shijiazhuang/clifftemple': ('ภูเขาชางเหยียน', 'บนภูเขาชางเหยียน วัดที่ตั้งอยู่บนสะพานหินซึ่งทอดขึงระหว่างหน้าผาสองฝั่ง คือหนึ่งในภาพที่ตระการตาที่สุดของจีน ต้องไต่บันไดหินสูงชันจากหุบเขาเขียวขจีขึ้นไปจึงจะถึง สถานที่แห่งนี้เคยเป็นฉากหลังของฉากจบในภาพยนตร์เรื่อง \'พยัคฆ์ระห่ำ มังกรผยองโลก\''),
  'shijiazhuang/redbase': ('ซีไป่โป', 'หมู่บ้านซีไป่โพใกล้สือเจียจวงเคยเป็นกองบัญชาการปฏิวัติในช่วงสุดท้ายของสงครามกลางเมือง แผนการก่อตั้งจีนใหม่ถูกวางขึ้นในลานบ้านดินเหล่านี้ ปัจจุบันที่นี่คือหนึ่งในจุดหมายศักดิ์สิทธิ์ของ \'การท่องเที่ยวสีแดง\' บ้านชนบทอันเรียบง่ายยืนเป็นพยานให้การตัดสินใจครั้งใหญ่ของประวัติศาสตร์'),
  'shijiazhuang/pharma': ('เมืองยา', 'สือเจียจวงคือหนึ่งในศูนย์กลางการผลิตยาที่ใหญ่ที่สุดของจีน ได้รับสมญาว่า \'เมืองแห่งยา\' โดยเฉพาะจากการผลิตยาปฏิชีวนะและวัตถุดิบยา เมืองหลวงมณฑลอายุน้อยแห่งนี้เติบโตขึ้นจากการเป็นชุมทางรถไฟ และผสานอัตลักษณ์อุตสาหกรรมเข้ากับเภสัชกรรมและการผลิตสมัยใหม่'),
  'taiyuan/jincitemple': ('วัดจิ้นฉือ', 'วัดจิ้นฉือชานเมืองไท่หยวนคืออุทยานวัดที่งามสง่าที่สุดของจีนตอนเหนือ ด้วยน้ำพุศักดิ์สิทธิ์ ต้นสนไซเปรสอายุนับพันปี และรูปปั้นนางกำนัลสมัยราชวงศ์ซ่ง ในหอไม้ของพระมารดาศักดิ์สิทธิ์ รูปปั้นแต่ละองค์มีสีหน้าต่างกันไป ราวกับพวกนางกระซิบกระซาบกันมานานนับพันปี'),
  'taiyuan/coalcart': ('ดินแดนถ่านหิน', 'ขุนเขาของมณฑลซานซีเต็มไปด้วยสายแร่ถ่านหิน พลังงานส่วนใหญ่ของจีนขุดขึ้นมาจากที่นี่ และไท่หยวนคือเมืองหลวงของความมั่งคั่งนั้น เหมืองแร่มอบอุตสาหกรรม ทางรถไฟ และวัฒนธรรมเครื่องจักรกลหนักให้เมือง วันนี้ไท่หยวนกำลังพยายามถ่วงดุลมรดกถ่านหินด้วยพลังงานสะอาด'),
  'taiyuan/vinegar': ('น้ำส้มสายชูหมักเก่าแก่', 'น้ำส้มสายชูบ่มเก่าของซานซีทำจากข้าวฟ่างและธัญพืชที่หมักบ่มอย่างช้า ๆ โดดเด่นด้วยสีเข้มและรสเปรี้ยวอมควันไฟ จนเป็นราชาแห่งโต๊ะอาหาร คนท้องถิ่นราดน้ำส้มลงบนทุกจาน ตั้งแต่บะหมี่ถึงเกี๊ยว ที่นี่น้ำส้มสายชูไม่ใช่แค่เครื่องปรุง แต่แทบจะเป็นอัตลักษณ์ประจำถิ่นเลยทีเดียว'),
  'taiyuan/twinpagoda': ('เจดีย์คู่', 'เจดีย์แปดเหลี่ยมสมัยราชวงศ์หมิงสององค์ที่ตั้งตระหง่านเคียงคู่กันทางตะวันออกเฉียงใต้ของเมือง คือสัญลักษณ์ที่ไม่เคยเปลี่ยนของไท่หยวนมาหลายศตวรรษ หอคอยก่ออิฐทั้งคู่อวดความประณีตของงานช่างก่อสร้าง และในฤดูใบไม้ผลิ ดอกเหมยที่บานสะพรั่งรอบเจดีย์คือช่วงเวลาถ่ายรูปที่งดงามที่สุดของการมาเยือน'),
  'hohhot/lamatemple': ('วัดต้าจ้าว', 'วัดต้าเจาที่ก่อตั้งในสมัยราชวงศ์หมิงคือหัวใจทางจิตวิญญาณของฮูฮอต สมบัติล้ำค่าที่สุดคือพระพุทธรูปเงินองค์ใหญ่ ศูนย์กลางพุทธศาสนาแบบทิเบตกลางทุ่งหญ้าแห่งนี้มอบโลกอีกใบที่ห่างไกลจากความอึกทึกของเมือง ห่อหุ้มด้วยควันธูป กงล้อมนตรา และเสียงสวดมนต์แผ่วเบา'),
  'hohhot/dairy': ('เมืองหลวงแห่งผลิตภัณฑ์นม', 'แบรนด์นมยักษ์ใหญ่ที่สุดของจีนถือกำเนิดที่ฮูฮอต ประเพณีน้ำนมแห่งทุ่งหญ้าเติบโตเป็นอุตสาหกรรมสมัยใหม่ที่นี่ จนเมืองได้สมญาว่า \'เมืองหลวงแห่งนม\' บนโต๊ะอาหาร ของอร่อยแบบมองโกลอย่างชานม นมแห้ง และครีมข้นยังคงอยู่เคียงคู่กับผลิตภัณฑ์จากโรงงานอย่างกลมกลืน'),
  'hohhot/wrestling': ('มวยปล้ำมองโกเลีย', 'มวยปล้ำมองโกลที่เรียกว่า \'เบิค\' คือการแข่งขันดาวเด่นของเทศกาลนาดัม นักมวยปล้ำก้าวลงสนามในเสื้อกั๊กปักลวดลายพร้อมร่ายรำท่านกอินทรี ผู้ชนะได้รับเสียงปรบมือทั้งจากพละกำลังและความสง่างาม บนทุ่งหญ้า มวยปล้ำถูกนับเป็นหนึ่งใน \'สามทักษะแห่งชายชาตรี\' เคียงคู่การขี่ม้าและการยิงธนู'),
  'hohhot/prairie': ('ทุ่งหญ้า', 'เลยฮูฮอตออกไปเพียงเล็กน้อย ทุ่งหญ้ามองโกลก็ทอดยาวจรดขอบฟ้า ในฤดูร้อน ทุ่งหญ้าเลี้ยงสัตว์พลิ้วไหวดั่งทะเลสีเขียวที่มีฝูงม้าและแกะเล็มหญ้า แขกที่พักในกระโจมเกอร์จะได้รับการต้อนรับด้วยชานมและงานเลี้ยงเนื้อแกะ พอตกค่ำ ท้องฟ้าก็เต็มไปด้วยดวงดาวที่ชาวเมืองหลงลืมไปนานแล้ว'),
  'sanya/resortbeach': ('ชายหาดเขตร้อน', 'ซานย่าที่ปลายใต้สุดของเกาะไหหลำคือเมืองหลวงแห่งการพักผ่อนเขตร้อนของจีน หาดทรายละเอียดดุจแป้งและน้ำทะเลสีเทอร์ควอยซ์ของอ่าวย่าหลงทำให้ที่นี่ได้ชื่อว่า \'ฮาวายแห่งเมืองจีน\' ริมหาดที่เรียงรายด้วยต้นปาล์ม ฤดูร้อนดำเนินไปตลอดทั้งปี นี่คือชายฝั่งไม่กี่แห่งของจีนที่ลงเล่นน้ำทะเลได้แม้ในหน้าหนาว'),
  'sanya/guanyin': ('พระโพธิสัตว์กวนอิม', 'รูปปั้นเจ้าแม่กวนอิมสูง 108 เมตรที่ตั้งตระหง่านเหนือท้องทะเลที่หนานซาน คือหนึ่งในรูปปั้นเทพีที่สูงที่สุดในโลก พระพักตร์ทั้งสามด้านหันสู่แผ่นดิน ท้องทะเล และมหาสมุทรกว้าง เส้นทางที่ทอดสู่เบื้องพระบาทของเจ้าแม่แห่งความเมตตา ดึงดูดทั้งผู้แสวงบุญและนักเดินทางผู้ใคร่รู้'),
  'sanya/diving': ('การดำน้ำ', 'ด้วยน้ำทะเลอุ่นและใสราวคริสตัล ซานย่าคือสวรรค์แห่งการดำน้ำของจีน แนวปะการังรอบเกาะอู๋จื่อโจวคลาคล่ำไปด้วยฝูงปลาหลากสีสัน มือใหม่ดำน้ำในแนวปะการังน้ำตื้นพร้อมครูฝึกได้ แม้มีเพียงหน้ากากสนอร์กเกิลก็มองลงไปชมสวนเขตร้อนใต้ผิวน้ำได้แล้ว'),
  'sanya/coconutdrink': ('มะพร้าว', 'ที่ซานย่า มะพร้าวคือส่วนหนึ่งของชีวิตประจำวัน พ่อค้าแม่ค้าตลอดแนวชายหาดใช้มีดพร้าเปิดลูกมะพร้าวสดแล้วยื่นให้พร้อมหลอดดูด น้ำมะพร้าวเย็นชื่นใจคือยาแก้ร้อนเขตร้อนที่เป็นธรรมชาติที่สุด ส่วนกะทิใช้ปรุงเมนูไก่และของหวานท้องถิ่น และกะลาก็กลายเป็นงานหัตถกรรม'),
  'yangzhou/slenderlake': ('ทะเลสาบซีหูผอม', 'ทะเลสาบโซ่วซีหูหรือ \'ทะเลสาบตะวันตกเรียว\' ได้ชื่อมาจากการคารวะอย่างงดงามต่อทะเลสาบชื่อดังของหางโจว ลำน้ำแคบยาวประดับด้วยต้นหลิว สะพานโค้งสีขาว และศาลาน้อยใหญ่ ทิวทัศน์ที่จักรพรรดิราชวงศ์ชิงเคยหลงใหลระหว่างประพาสแดนใต้แห่งนี้ ยังคงงามสง่าราวภาพวาดพู่กันจีนจนทุกวันนี้'),
  'yangzhou/friedrice': ('ข้าวผัดหยางโจว', 'ข้าวผัดหยางโจวคือเมนูคลาสสิกสีทองแห่งกุ้ง ไข่ และต้นหอม ที่ผัดจนข้าวร่วนเรียงเม็ดสวย ชื่อของมันยังคงอยู่ในเมนูร้านอาหารจีนทั่วทุกมุมโลก เคล็ดลับอยู่ที่ความเรียบง่าย ข้าวทุกเม็ดเคลือบด้วยไข่ วัตถุดิบสดใหม่และพอเหมาะพอดี ไม่ใส่จนล้นจาน'),
  'yangzhou/morningtea': ('ชายามเช้า', 'ที่หยางโจว วันใหม่เริ่มต้นด้วยพิธี \'น้ำชายามเช้า\' ชาเข้มข้นเสิร์ฟคู่ซาลาเปานึ่ง ขนมแป้งหั่นฝอยบางเฉียบ และเสี่ยวหลงเปาไส้น้ำซุป ในโรงน้ำชาเก่าแก่ อาหารเช้ามื้อนี้ทอดยาวได้หลายชั่วโมง การรีบร้อนกินให้เสร็จแทบจะถือว่าเสียมารยาทเลยทีเดียว'),
  'yangzhou/gegarden': ('สวนเก๋อ', 'สวนเก้อที่สร้างโดยพ่อค้าเกลือผู้มั่งคั่ง ได้ชื่อมาจากรูปทรงของใบไผ่ ลูกเล่นที่เลื่องชื่อที่สุดของสวนคือภูเขาหินจำลองที่ใช้หินต่างชนิดสื่อถึงฤดูกาลทั้งสี่ เพียงไม่กี่ก้าวคุณก็เดินจากฤดูใบไม้ผลิสู่ฤดูหนาว ผ่านสุดยอดแห่งศิลปะการจัดสวนแบบจีนคลาสสิก'),
  'weihai/navalisland': ('เกาะหลิวกง', 'เกาะหลิวกงนอกชายฝั่งเวยไห่เคยเป็นฐานทัพของกองเรือเป่ยหยาง ราชนาวีสมัยใหม่ของราชวงศ์ชิง ซึ่งพ่ายแพ้ที่นี่ในสงครามกับกองเรือญี่ปุ่น ปัจจุบันเกาะพร้อมพิพิธภัณฑ์และป้อมปราการเก่าแก่ บอกเล่าหน้าประวัติศาสตร์กองทัพเรือจีนที่เจ็บปวดแต่เปี่ยมบทเรียน'),
  'weihai/swan': ('ทะเลสาบหงส์', 'ทุกฤดูหนาว หงส์เสียงก้องหลายร้อยตัวบินมาจากไซบีเรียเพื่อพำนักในลากูนชายฝั่งใกล้เวยไห่ ภาพนกสีขาวที่ลอยเลื่อนผ่านหมอกยามเช้าดึงดูดช่างภาพและผู้รักธรรมชาติ ส่วนชาวบ้านก็ดูแลและให้อาหารฝูงหงส์ราวกับเป็นเพื่อนบ้านของตัวเอง'),
  'weihai/seacucumber': ('ปลิงทะเล', 'ปลิงทะเลที่เลี้ยงในน้ำทะเลเย็นและสะอาดของเวยไห่ คือหนึ่งในวัตถุดิบล้ำค่าที่สุดบนโต๊ะอาหารจีน สัตว์ทะเลที่เชื่อกันว่าบำรุงร่างกายชั้นเลิศนี้ถูกเสิร์ฟในโอกาสพิเศษและเป็นของขวัญอันทรงเกียรติ ฟาร์มเพาะเลี้ยงตามแนวชายฝั่งคือแหล่งรายได้สำคัญของเมือง'),
  'weihai/cape': ('แหลมสุดตะวันออกของจีน', 'แหลมเฉิงซานโถวทางตะวันออกของเวยไห่ คือหนึ่งในจุดตะวันออกสุดที่แผ่นดินจีนบรรจบท้องทะเล ดวงอาทิตย์ทักทายประเทศจีนที่นี่ก่อนใคร ตำนานเล่าว่าจิ๋นซีฮ่องเต้ ปฐมจักรพรรดิ เคยเดินทางมาไกลถึงที่นี่เพื่อค้นหาดินแดนอมตะเหนือคลื่นทะเล แหลมนี้จึงถูกเรียกอีกชื่อว่า \'สุดขอบฟ้า\''),
  'handan/taichi': ('ไทเก๊ก', 'เมืองกำแพงโบราณกว่างฝู่ใกล้หานตานคือถิ่นกำเนิดของมวยไทเก๊กสายหยางและสายอู๋ ปรมาจารย์ในตำนานหยางลู่ฉานฝึกฝนวิชาที่นี่ ยามเช้า เหล่าศิษย์ที่ร่ายรำท่วงท่าเชื่องช้าลื่นไหลอยู่ใต้แนวกำแพงและในลานบ้าน คือผู้สืบทอดมรดกที่มีชีวิตของศิลปะการต่อสู้สาย \'อ่อน\' แขนงนี้'),
  'handan/congtai': ('หอคอยฉงไถ', 'หอฉงไถหลงเหลือมาจากแคว้นจ้าวอันเกรียงไกรแห่งยุครณรัฐ ลานสูงที่กษัตริย์เคยประทับทอดพระเนตรพระราชพิธีและการซ้อมรบ ปัจจุบันตั้งอยู่ใจกลางสวนสาธารณะ ผู้ที่ขึ้นไปบนหอจะได้มองลงมายังประวัติศาสตร์กว่าสองพันปีของหานตานในฐานะนครหลวงโบราณ'),
  'handan/idiom': ('เมืองแห่งสำนวน', 'หานตานคือ \'เมืองแห่งสำนวน\' สำนวนจีนกว่า 1,500 สำนวนมีต้นกำเนิดจากเหตุการณ์และเรื่องเล่าบนผืนดินแห่งนี้ ที่โด่งดังที่สุดคือ \'เรียนท่าเดินแบบหานตาน\' ว่าด้วยคนที่เลียนแบบผู้อื่นจนลืมท่าเดินของตัวเอง สำนวนนี้สลักชื่อเมืองไว้ในภาษาจีนตลอดกาล'),
  'handan/ciporcelain': ('เครื่องเคลือบฉือโจว', 'เครื่องปั้นฉือโจวโดดเด่นด้วยลวดลายสีดำที่ตวัดพู่กันอย่างอิสระบนน้ำดินสีขาว ทั้งดอกไม้ ปลา และบทกวี ถูกวาดลงบนภาชนะด้วยความจริงใจแบบศิลปะชาวบ้าน ประเพณีที่สืบเนื่องมาตั้งแต่ราชวงศ์ซ่งนี้ยืนหยัดเป็นเซรามิกของชีวิตประจำวัน คู่ขนานกับเครื่องกระเบื้องของราชสำนัก'),
  'daqing/oilpump': ('แหล่งน้ำมัน', 'การค้นพบแหล่งน้ำมันต้าชิ่งช่วยปลดปล่อยสาธารณรัฐประชาชนจีนอันเยาว์วัยจากการพึ่งพาน้ำมันนำเข้า เมืองนี้แทบจะเติบโตขึ้นบนหลุมน้ำมันของตัวเองเลยทีเดียว เครื่องสูบน้ำมันที่ก้มเงยหัวช้า ๆ ยังคงทำงานอยู่กลางที่ราบจนทุกวันนี้ และต้าชิ่งก็จารึกชื่อในประวัติศาสตร์ในฐานะแหล่งน้ำมันใหญ่ที่สุดของจีน'),
  'daqing/oilworker': ('วีรบุรุษเหล็ก', 'หวังจิ้นสี่ คนงานน้ำมันผู้ได้ฉายา \'บุรุษเหล็ก\' จากความมุ่งมั่นในการเปิดหลุมเจาะท่ามกลางความหนาวเหน็บ เล่ากันว่าครั้งหนึ่งเขากระโดดลงบ่อโคลนแล้วใช้ร่างกายตัวเองกวนน้ำโคลนเจาะ พิพิธภัณฑ์ที่ตั้งตามชื่อของเขาและ \'จิตวิญญาณบุรุษเหล็ก\' ยังคงสืบสานตำนานการก่อร่างสร้างเมืองของต้าชิ่งให้มีชีวิตต่อไป'),
  'daqing/reedlake': ('พื้นที่ชุ่มน้ำ', 'ธรรมชาติอันน่าทึ่งซุกซ่อนอยู่ท่ามกลางหลุมน้ำมัน ทะเลสาบดงอ้อและพื้นที่ชุ่มน้ำอันกว้างใหญ่ของต้าชิ่งคือบ้านของนกกระเรียน หงส์ และนกน้ำอพยพ ในฤดูใบไม้ร่วง เมื่อดงอ้อสีทองพลิ้วไหวไปตามสายลม เมืองอุตสาหกรรมแห่งนี้ก็แปลงกายเป็นสวรรค์ของนก'),
  'daqing/hotspring': ('น้ำพุร้อน', 'รอบต้าชิ่ง น้ำแร่ร้อนที่ผุดขึ้นจากใต้พิภพลึกมอบที่พักพิงอันชุบชูกายใจในฤดูหนาวเหน็บหนาวของภาคตะวันออกเฉียงเหนือ อำเภอหลินเตี้ยนสร้างชื่อในฐานะเมืองน้ำพุร้อน การแช่ตัวในสระน้ำไอร้อนระอุคือคำตอบอันอ่อนโยนต่อภูมิอากาศแสนโหดของเมืองน้ำมันแห่งนี้'),
  'zibo/bbq': ('บาร์บีคิวจือป๋อ', 'บาร์บีคิวจือโป๋โด่งดังจากสามสหาย เตาถ่านใบเล็ก ไม้เสียบเนื้อเส้นเรียว และแป้งแผ่นบางนุ่ม คุณย่างไม้ของตัวเองจนสุกกำลังดี แล้วห่อลงแป้งพร้อมต้นหอมสดและซอส พิธีกรรมแสนเป็นกันเองนี้ดังกระหึ่มโซเชียลมีเดียจีน จนดันชื่อเมืองขึ้นเป็นกระแสระดับประเทศเพียงชั่วข้ามคืน'),
  'zibo/cuju': ('กีฬาคูจู', 'ชู่จวี ฟุตบอลรูปแบบเก่าแก่ที่สุดของโลก เคยเล่นกันที่หลินจือ เมืองหลวงของแคว้นฉีโบราณ ซึ่งฟีฟ่ารับรองว่าเป็นต้นกำเนิดของกีฬาฟุตบอล การเดาะลูกหนังให้ลอยด้วยเท้าแบบนี้มีชีวิตอันรุ่มรวย ทอดยาวจากมหรสพในราชสำนักไปจนถึงการฝึกทหาร'),
  'zibo/ceramic': ('เครื่องปั้นดินเผาจือป๋อ', 'เตาเผาของจือโป๋ลุกโชนมานานกว่าพันปี ทำให้เมืองนี้เป็นหนึ่งในศูนย์กลางเซรามิกที่หยั่งรากลึกที่สุดของจีนตอนเหนือ ประเพณีการผลิตที่ครอบคลุมตั้งแต่ภาชนะใช้สอยประจำวันถึงเครื่องกระเบื้องชั้นศิลปะ ยังมีชีวิตอยู่ในพิพิธภัณฑ์และโรงช่าง งานแสดงเซรามิกของเมืองดึงดูดช่างฝีมือจากทั่วประเทศ'),
  'zibo/glass': ('เครื่องแก้วหลิวหลี', 'หลิวหลี งานแก้วสีหลอมเหลวที่ปั้นแต่งด้วยมือ คืองานฝีมือเล่นแสงของจือโป๋ อำเภอปั๋วซานมีชื่อเสียงในฐานะศูนย์กลางทางประวัติศาสตร์ของศิลปะแขนงนี้ ช่างฝีมือใช้คีมดึงและดัดแก้วที่ร้อนแดง ลูกปัด นก และแจกันที่ได้จึงเปล่งประกายกลางแดดราวกระจกสี'),
  'taian/mounttai': ('ภูเขาไท่ซาน', 'เขาไท่ซาน ผู้นำแห่งห้าขุนเขาศักดิ์สิทธิ์ คือยอดเขาที่ศักดิ์สิทธิ์ที่สุดของจีน เป็นเวลาหลายศตวรรษที่จักรพรรดิเสด็จมาประกอบพิธีบวงสรวงเพื่อประกาศรัชสมัยต่อสวรรค์ ณ ที่แห่งนี้ จารึกของกวีและนักอักษรวิจิตรถูกสลักลงบนหินผาของภูเขามรดกโลกยูเนสโกแห่งนี้ หินทุกก้อนคือหน้าหนึ่งของประวัติศาสตร์'),
  'taian/sunrise': ('ชมพระอาทิตย์ขึ้นบนยอดเขา', 'รางวัลสูงสุดของการพิชิตเขาไท่ซานคือการชมดวงอาทิตย์ขึ้นเหนือทะเลเมฆบนยอดเขา ผู้คนนับพันปีนเขาตลอดทั้งคืนเพื่อรอรุ่งอรุณที่ยอดเง็กเซียนฮ่องเต้ เมื่อขอบฟ้าเปลี่ยนเป็นสีแดงเพลิง เสียงเฮดังก้องจากฝูงชนก็ชะล้างความเหนื่อยล้าให้หายไปในพริบตา'),
  'taian/stonesteps': ('บันไดหินสู่ยอดเขา', 'บันไดหินราว 7,000 ขั้นที่ทอดสู่ยอดเขาคือบททดสอบร่างกายที่ผู้แสวงบุญไต่ขึ้นทีละก้าวมานานหลายศตวรรษ ช่วงที่ชันที่สุดคือ \'สิบแปดโค้งสู่สวรรค์\' ส่วนเหล่าลูกหาบที่แบกสัมภาระขึ้นลงบันไดเหล่านี้ทุกวัน คือวีรบุรุษผู้เงียบงันของขุนเขา'),
  'taian/daitemple': ('วัดไต้เมี่ยว', 'วัดไต้เมี่ยวที่ตีนเขาคือศาสนสถานอันโอ่อ่าที่จักรพรรดิเคยประทับพักและเตรียมพระองค์ก่อนขึ้นประกอบพิธีบนเขาไท่ซาน วิหารใหญ่สถาปัตยกรรมแบบพระราชวังมีชื่อเสียงจากจิตรกรรมฝาผนังขนาดมหึมาที่บอกเล่าการเสด็จของเทพแห่งเขาไท่ซาน ต้นสนไซเปรสโบราณในลานวัดคือพยานแห่งกาลเวลา'),
  'lianyungang/monkey': ('ภูเขาฮัวกั่วซาน', 'เขาฮวากั่วซานหรือ \'ภูเขาดอกไม้ผลไม้\' บ้านเกิดของราชาวานรซุนหงอคงจากวรรณกรรม \'ไซอิ๋ว\' ตั้งตระหง่านอยู่ที่นี่ ทางเข้าถ้ำม่านน้ำซ่อนอยู่หลังม่านน้ำตก และฝูงลิงแสมตัวจริงที่ไต่ป่ายอยู่ตามโขดหิน ก็ทำให้เส้นแบ่งระหว่างตำนานกับทิวทัศน์เลือนรางลงไปทุกที'),
  'lianyungang/seaport': ('ท่าเรือเหลียนหยุนกัง', 'เหลียนหยุนกั่งคือปลายทางฝั่งแปซิฟิกของสะพานแผ่นดินทางรถไฟที่ทอดข้ามทวีปยูเรเชีย ขบวนรถไฟที่บรรทุกสินค้าจากที่นี่แล่นผ่านเอเชียกลางมุ่งสู่ยุโรป ท่าเรือที่ได้ชื่อว่าประตูทะเลตะวันออกของเส้นทางสายไหมแห่งนี้ เปรียบดั่งภาคต่อสมัยใหม่ของเส้นทางการค้าโบราณ'),
  'lianyungang/mountain': ('ภูเขาหยุนไถ', 'ยอดผาสูงชันของเขาหยุนไถครอบครองจุดสูงสุดของมณฑลเจียงซู นับเป็นข้อยกเว้นอันน่าทึ่งในมณฑลที่ขึ้นชื่อเรื่องที่ราบลุ่มต่ำ ด้วยไหล่เขาปกคลุมด้วยผืนป่า วัดวาอาราม และสันเขาที่มองเห็นทะเล เทือกเขาแห่งนี้คือที่หลบภัยสู่ธรรมชาติของชาวเมือง'),
  'lianyungang/crystal': ('ดินแดนแห่งคริสตัล', 'อำเภอตงไห่ในเหลียนหยุนกั่งเป็นที่ตั้งของตลาดคริสตัลควอตซ์ใหญ่ที่สุดแห่งหนึ่งของโลก ผลึกใสบริสุทธิ์ที่ขุดจากผืนดินแถบนี้ถูกนำไปใช้ตั้งแต่เครื่องประดับจนถึงวัตถุดิบอุตสาหกรรม แผงร้านค้าในตลาดของเมืองจึงระยิบระยับไปด้วยหินแวววาว'),
  'maanshan/libai': ('กวีหลี่ไป๋', 'หลี่ไป๋ ผู้ได้รับยกย่องเป็นกวีที่ยิ่งใหญ่ที่สุดของจีน ใช้ชีวิตบั้นปลายในแถบเมืองริมน้ำแห่งนี้ สุสานของท่านอยู่ที่ตางถูใกล้ ๆ กัน อุทยานอนุสรณ์ยังคงรักษาร่องรอยของยอดกวีผู้แปรสุรา ดวงจันทร์ และอิสรภาพให้เป็นบทกวี หม่าอันซานจึงเรียกตนเองอย่างภาคภูมิว่า \'เมืองแห่งกวีนิพนธ์\''),
  'maanshan/steel': ('เมืองเหล็กกล้า', 'โรงถลุงเหล็กหม่ากังทำให้หม่าอันซานเป็นหนึ่งในฐานอุตสาหกรรมเหล็กกล้าสำคัญของจีน เตาถลุงสูงพ่นควันอยู่ริมฝั่งแม่น้ำแยงซีมานานหลายทศวรรษ เมืองนี้ถ่วงดุลอัตลักษณ์อุตสาหกรรมหนักด้วยอดีตอันเป็นกวี ฟากหนึ่งคือเหล็กหลอมเหลว อีกฟากคือบทกวีของหลี่ไป๋'),
  'maanshan/rivercliff': ('หน้าผาไฉ่สือจี๋', 'หน้าผาไฉสือจีที่ดิ่งตรงลงสู่แม่น้ำแยงซี มอบหนึ่งในทิวทัศน์ที่เป็นกวีที่สุดของสายน้ำนี้ ตำนานเล่าว่าหลี่ไป๋พลัดตกลงไปในแม่น้ำที่นี่ขณะเอื้อมกอดเงาจันทร์บนผิวน้ำ แล้วก้าวสู่ความเป็นอมตะ ศาลาและทางเดินบนหน้าผายังคงกระซิบเล่าเรื่องราวนี้อยู่จนทุกวันนี้'),
  'maanshan/moonwine': ('จันทราและสุรา', 'ดวงจันทร์และสุรา สองมโนภาพอันยิ่งใหญ่ในบทกวีของหลี่ไป๋ ยังคงถูกเฉลิมฉลองที่หม่าอันซาน เมืองจัดเทศกาลกวีนิพนธ์เพื่อรำลึกถึงท่านเป็นประจำ การชูจอกริมแม่น้ำพลางชมดวงจันทร์ คือวิธีเรียบง่ายที่สุดในการแบ่งปันความรู้สึกเดียวกันกับกวีเมื่อพันปีก่อน'),
  'longyan/tulou': ('ถู่โหลวหย่งติ้ง', 'ถู่โหลวทรงกลมขนาดยักษ์ที่กระจายอยู่ตามขุนเขาของหย่งติ้ง คือบ้านป้อมปราการที่ชาวฮากกาก่อขึ้นจากดินและไม้ ปัจจุบันเป็นมรดกโลกยูเนสโก หลังกำแพงดินหนา ครอบครัวหลายสิบครัวเรือนใช้ชีวิตเคียงกัน ควันไฟจากเตาที่ลอยขึ้นจากลานกลางบ้าน คือกลิ่นอายของชีวิตชุมชนที่ดำเนินมาหลายศตวรรษ'),
  'longyan/redmeeting': ('การประชุมกู่เถียน', 'ในปี 1929 การประชุมกู่เถียนครั้งประวัติศาสตร์ที่กำหนดหลักการและทิศทางของกองทัพแดง จัดขึ้นในหมู่บ้านกลางหุบเขาแห่งนี้ของหลงเหยียน หอประชุมผนังปูนขาวยังได้รับการอนุรักษ์ไว้จนทุกวันนี้ หมู่บ้านจึงเป็นจุดหมายของผู้ที่ต้องการตามรอยหนึ่งในจุดเปลี่ยนของประวัติศาสตร์การปฏิวัติ'),
  'longyan/hakka': ('วัฒนธรรมฮากกา', 'ชาวฮากกา ซึ่งชื่อมีความหมายว่า \'ครอบครัวผู้มาเยือน\' ได้ชื่อนี้จากการอพยพหนีสงครามลงใต้จากจีนตอนเหนือ ในขุนเขาของหลงเหยียน พวกเขาธำรงภาษาอันเป็นเอกลักษณ์ อาหารอย่างไก่อบเกลือ และสายใยครอบครัวอันเหนียวแน่นไว้ได้นานหลายศตวรรษ'),
  'longyan/mountain': ('ภูเขากวนจื้อ', 'เขากวนไจ้เป็นที่รู้จักจากยอดหินสีแดงที่ว่ากันว่าคล้ายหมวกขุนนางตุลาการโบราณ หน้าผาหินแดงแบบตันเสียเหล่านี้รายล้อมด้วยแอ่งน้ำใสและหุบเหวสูงชัน ด้วยบันไดที่สกัดลงในเนื้อหินและการล่องเรือชมทะเลสาบ ภูเขาแห่งนี้จึงได้ชื่อว่าเป็นไข่มุกธรรมชาติแห่งฝูเจี้ยนตอนใต้'),
  'sanming/danxia': ('ไท่หนิงตานเซี่ย', 'ไท่หนิงทางตะวันตกเฉียงเหนือของมณฑลฝูเจี้ยนเป็นอุทยานธรณีโลกของยูเนสโก เต็มไปด้วยหน้าผาหินทรายสีแดง โตรกผาแคบ และถ้ำน้อยใหญ่ สายน้ำใช้เวลาหลายล้านปีกัดเซาะจนเกิดเขาวงกตหินแห่งนี้ วันนี้คุณล่องเรือลัดเลาะไปตามลำธารสีเขียวมรกตที่ไหลเลียบผนังผาสีแดงเข้มได้อย่างเพลิดเพลิน'),
  'sanming/shaxian': ('ของว่างซาเซี่ยน', 'อาหารพื้นบ้านอันเรียบง่ายของเขตซาเซี่ยนกลายเป็นปรากฏการณ์ระดับประเทศด้วยเมนูราคาถูกแต่อิ่มท้อง เกี๊ยวแผ่นแป้งบางเฉียบ บะหมี่คลุกซอสถั่วลิสง และซุปตุ๋นหอมกรุ่น ถูกเสิร์ฟด้วยความอบอุ่นแบบเดียวกันในร้านอาหารว่างซาเซี่ยนที่พบได้แทบทุกถนนทั่วประเทศจีน'),
  'sanming/forest': ('เมืองหลวงสีเขียว', 'ซานหมิงติดอันดับเมืองที่มีป่าไม้หนาแน่นที่สุดแห่งหนึ่งของจีน ภูเขาปกคลุมด้วยสีเขียวตั้งแต่สันเขาจรดหุบเขา จากเมืองค้าไม้ในอดีต วันนี้เมืองหันมาสู่การท่องเที่ยวเชิงนิเวศ และภูมิใจกับสมญานาม "เมืองหลวงสีเขียว" ด้วยอากาศบริสุทธิ์และเส้นทางเดินป่ามากมาย'),
  'sanming/goldenlake': ('ทะเลสาบจินหู', 'ทะเลสาบทองคำหรือจินหูเป็นอ่างเก็บน้ำกว้างใหญ่ที่คดเคี้ยวไปตามหน้าผาตานเซี๋ยสีแดงของไท่หนิง เรือนำเที่ยวพาคุณลอดโตรกน้ำแคบ ๆ ผ่านผนังผาสูงชันและวัดกันลู่ที่สร้างซ้อนอยู่ในเพิงผา นับเป็นภูมิทัศน์หายากที่สายน้ำมาบรรจบกับศิลา'),
  'ningde/mudflat': ('หาดโคลนเซี่ยผู่', 'ทุกวันเมื่อน้ำทะเลลดที่เซี่ยผู่ หาดโคลนกว้างสุดสายตาจะปรากฏขึ้นและเปล่งประกายตามแสงที่แปรเปลี่ยน แปลงเลี้ยงสาหร่าย แนวไม้ไผ่ที่ปักเรียงราย และชาวประมงที่ทำงานในน้ำตื้น ทำให้ชายฝั่งแห่งนี้กลายเป็นจุดนัดพบระดับโลกของเหล่าช่างภาพ'),
  'ningde/whitetea': ('ชาขาวฝูติ่ง', 'ฝูติ่งคือถิ่นกำเนิดของชาขาวจีน ยอดอ่อนที่ปกคลุมด้วยขนสีเงินเพียงถูกผึ่งให้เหี่ยวแล้วอบแห้ง โดยไม่ผ่านการคั่วเลย คำกล่าวท้องถิ่นที่ว่า "หนึ่งปีคือชา สามปีคือยา เจ็ดปีคือของล้ำค่า" สะท้อนว่าใบชาอันบอบบางนี้ยิ่งเก็บนานยิ่งทวีคุณค่า'),
  'ningde/taimu': ('ภูเขาไท่มู่', 'ภูเขาไท่หมู่ตั้งตระหง่านเหนือทะเลด้วยยอดหินแกรนิตมนกลม ซอกผาแคบ และช่องถ้ำลึกลับ ผู้คนขนานนามมาแต่โบราณว่า "แดนสวรรค์กลางทะเล" เส้นทางเดินที่ลัดเลาะระหว่างก้อนหินจะพาคุณสู่จุดชมวิวที่สายหมอกและมหาสมุทรมาบรรจบกัน'),
  'ningde/croaker': ('ปลาจวดเหลือง', 'อ่าวซานตูอ้าวอันสงบกำบังคลื่นลมของหนิงเต๋อคือฐานเพาะเลี้ยงปลาจวดเหลืองใหญ่ที่สุดของจีน ฟาร์มกระชังลอยน้ำเรียงตัวกันจนเหมือนหมู่บ้านทั้งหมู่บ้านกลางทะเล เนื้อปลาสีขาวอันนุ่มละมุนเพียงนึ่งแบบเรียบง่ายก็ขึ้นแท่นจานเด่นบนโต๊ะอาหารของชาวฝูเจี้ยน'),
  'shaoguan/redcliff': ('ภูเขาตานเซี่ย', 'ภูเขาตานเซี๋ยคือเทือกหินทรายแดงที่เป็นต้นกำเนิดของชื่อภูมิลักษณ์ "ตานเซี๋ย" ทั่วโลก และได้รับการขึ้นทะเบียนเป็นมรดกโลกของยูเนสโก แท่งหินและเสาผาที่ลมกับสายน้ำแกะสลักจะเรืองแสงราวถ่านไฟยามอาทิตย์อัสดง เที่ยวชมได้ทั้งทางเดินคดเคี้ยวและการล่องเรือแม่น้ำ'),
  'shaoguan/chantemple': ('วัดหนานหัว', 'วัดหนานหัวใกล้เมืองเสากวานคือสถานที่ที่ท่านเว่ยหล่าง (ฮุ่ยเหนิง) พระสังฆปริณายกองค์ที่หกแห่งพุทธศาสนานิกายเซน เผยแผ่คำสอน ด้วยประวัติศาสตร์ยาวนานเกือบหนึ่งพันห้าร้อยปี ที่นี่ยังคงเป็นศูนย์กลางศักดิ์สิทธิ์ของเซนสายใต้ ที่ผู้จาริกแสวงบุญยังคงตามรอยพระอาจารย์ท่ามกลางควันธูปหอม'),
  'shaoguan/ancestor': ('จูจี้เซี่ยง', 'ตรอกจูจีในเมืองหนานสยงเคยเป็นจุดแวะพักของครอบครัวที่อพยพจากภาคเหนือในสมัยราชวงศ์ซ่งก่อนเดินทางไปตั้งรกรากทางใต้ ปัจจุบันชาวกวางตุ้งหลายล้านคนสืบสายตระกูลย้อนกลับมายังตรอกหินแคบ ๆ แห่งนี้ และกลับมาค้นหาชื่อบรรพบุรุษของตนปีแล้วปีเล่า'),
  'shaoguan/yaodance': ('ชาวเย้า', 'ชาวเหยาที่อาศัยในอำเภอภูเขาของเสากวานมีชื่อเสียงจากเครื่องแต่งกายปักลวดลายอันงดงามตระการตาและระบำกลองยาว ยามเทศกาลเก็บเกี่ยว เสียงกลองจะก้องกังวานไปทั่วหุบเขา ส่วนลวดลายปักผ้าก็ถ่ายทอดประวัติศาสตร์ของตระกูลจากรุ่นสู่รุ่นดั่งภาษาที่ไม่มีตัวอักษร'),
  'zhanjiang/oyster': ('หอยนางรมจ้านเจียง', 'หอยนางรมที่เลี้ยงในน่านน้ำตอนใต้อันอบอุ่นและสะอาดของจ้านเจียงเติบโตอ้วนกลม เนื้อขาวนุ่มดั่งน้ำนม ยามค่ำคืนหอยจะถูกย่างบนเตาถ่านพร้อมกระเทียมและน้ำมันตามแผงริมถนน รสชาติหอมกลิ่นทะเลนี้คือพิธีกรรมประจำค่ำคืนที่อยู่ใจกลางชีวิตยามราตรีของเมือง'),
  'zhanjiang/navy': ('ท่าเรือทัพเรือ', 'ด้วยท่าเรือธรรมชาติน้ำลึกที่กำบังคลื่นลมอย่างดี จ้านเจียงจึงเป็นที่ตั้งของกองเรือทะเลใต้แห่งกองทัพเรือจีน เมืองท่าที่ครั้งหนึ่งเคยเป็นดินแดนเช่าของฝรั่งเศสในชื่อกว่างโจววาน วันนี้กลายเป็นประตูยุทธศาสตร์ของประเทศสู่ทะเลจีนใต้'),
  'zhanjiang/mangrove': ('ป่าชายเลน', 'ป่าชายเลนตามแนวชายฝั่งจ้านเจียงคือเขตอนุรักษ์ป่าโกงกางที่ใหญ่ที่สุดของจีน ผืนป่าน้ำเค็มที่เอ่อท้นและเหือดแห้งตามจังหวะน้ำขึ้นน้ำลงแห่งนี้เป็นบ้านของนกยาง ปลาตีน และปู ขณะที่รากไม้อันโยงใยช่วยกำบังชายฝั่งจากพายุและเป็นเรือนเพาะชำตามธรรมชาติให้ลูกปลา'),
  'zhanjiang/donghai': ('เกาะตงไห่', 'เกาะตงไห่นอกชายฝั่งจ้านเจียงมีชื่อเสียงจากชายหาดที่ทอดยาวต่อเนื่องหลายกิโลเมตรโดยไม่ขาดตอน สายลมที่พัดสม่ำเสมอดึงดูดเหล่านักโต้คลื่น และเกาะยังเลื่องชื่อด้วย "ระบำมังกรมนุษย์" การแสดงดั้งเดิมที่ผู้แสดงหลายสิบคนเกาะไหล่ต่อกันจนกลายร่างเป็นมังกรตัวเดียว'),
  'maoming/lychee': ('เมืองหลวงแห่งลิ้นจี่', 'เม่าหมิงคือหนึ่งในแหล่งปลูกลิ้นจี่ที่ยิ่งใหญ่ที่สุดของโลก ต้นฤดูร้อนเนินเขาจะแดงระเรื่อไปด้วยผลไม้สุก ในสมัยจักรพรรดิ ลิ้นจี่จากดินแดนนี้ถูกส่งด่วนไปถวายราชสำนักเป็นเครื่องบรรณาการ และต้นลิ้นจี่อายุหลายร้อยปีในสวนก็ยังคงออกผลจนถึงทุกวันนี้'),
  'maoming/refinery': ('ฐานปิโตรเคมี', 'เม่าหมิงเติบโตเป็นเมืองอุตสาหกรรมในทศวรรษ 1950 จากการแปรรูปหินน้ำมัน และปัจจุบันเป็นที่ตั้งของฐานปิโตรเคมีที่ใหญ่ที่สุดแห่งหนึ่งของจีนตอนใต้ โรงกลั่นและโรงงานเอทิลีนมอบกระดูกสันหลังทางเศรษฐกิจอันแข็งแกร่งให้กับภูมิภาคสีเขียวที่มั่งคั่งด้วยเกษตรกรรมแห่งนี้'),
  'maoming/ladyxian': ('สตรีเสียน', 'ท่านหญิงเสี่ยน ผู้นำหญิงผู้ชาญฉลาดแห่งศตวรรษที่หก ได้รวมชนเผ่าต่าง ๆ ในดินแดนใต้สุดให้เป็นหนึ่งเดียวอย่างสันติ รอบเม่าหมิงมีวัดหลายร้อยแห่งที่อุทิศแด่ท่าน และพิธีรำลึกประจำปีคือประจักษ์พยานของความเคารพที่สืบเนื่องมาราวหนึ่งพันห้าร้อยปี'),
  'maoming/seaside': ('ชายหาด', 'ชายหาดของเม่าหมิงที่ได้รับการโปรโมตในนาม "หาดหมายเลขหนึ่งของจีน" ทอดยาวหลายกิโลเมตรด้วยผืนทรายสีทอง ป่าสนทะเลที่ปลูกเรียงรายตามชายฝั่งทำหน้าที่เป็นแนวกำบังลมสีเขียว ครอบครัวมาว่ายน้ำเล่นกันทั้งวันก่อนปิดท้ายด้วยมื้ออาหารทะเลในร้านริมหาด'),
  'zhaoqing/sevenstar': ('เขาเจ็ดดาว', 'ยอดเขาหินปูนเจ็ดยอดผุดขึ้นจากทะเลสาบซิงหูในตำแหน่งที่ว่ากันว่าเรียงตัวเหมือนกลุ่มดาวกระบวยใหญ่ ภายในหินซ่อนถ้ำที่เรียงรายด้วยจารึกสะสมมาหลายศตวรรษ และการเดินเล่นบนคันทางเลียบทะเลสาบจะทำให้เข้าใจว่าเหตุใดที่นี่จึงถูกขนานนามว่า "กุ้ยหลินแห่งกวางตุ้ง"'),
  'zhaoqing/inkstone': ('หินฝนหมึกตวน', 'ในบรรดา "สี่สิ่งล้ำค่าแห่งห้องหนังสือ" แท่นฝนหมึกที่เลื่องชื่อที่สุดคือหินตวนแห่งเมืองจ้าวชิ่ง หินสีม่วงที่ขุดจากเหมืองที่นี่มาตั้งแต่ราชวงศ์ถังจะกลายเป็นงานศิลปะในมือของช่างแกะสลัก แท่นหินตวนชั้นดีช่วยรักษาหมึกให้ชุ่มนานและถนอมพู่กันอย่างนุ่มนวล'),
  'zhaoqing/dinghu': ('ภูเขาติ่งหู', 'ภูเขาติ่งหูได้รับการประกาศเป็นเขตอนุรักษ์ธรรมชาติแห่งแรกของจีนในปี 1956 ด้วยป่าฝนกึ่งเขตร้อนอันบริสุทธิ์ไร้การรบกวน น้ำตกหลายสาย และวัดชิงหยุน ภูเขาแห่งนี้จึงเป็นที่พักพิงอันเย็นสบายที่ชาวเมืองเรียกอย่างเอ็นดูว่า "บาร์ออกซิเจน" ตามธรรมชาติ'),
  'zhaoqing/songwall': ('กำแพงเมืองสมัยซ่ง', 'กำแพงเมืองจ้าวชิ่งสร้างขึ้นในสมัยราชวงศ์ซ่งและยังคงสภาพเกือบสมบูรณ์ตลอดทั้งแนวจนถึงปัจจุบัน ชั้นอิฐบันทึกร่องรอยการซ่อมแซมของราชวงศ์แล้วราชวงศ์เล่า การเดินบนเชิงเทินจึงเปรียบเสมือนการเดินทางย้อนผ่านประวัติศาสตร์เมืองเกือบหนึ่งพันปี'),
  'huizhou/westlake': ('ทะเลสาบตะวันตกหุ้ยโจว', 'ทะเลสาบซีหูแห่งฮุ่ยโจวคือทัศนียภาพคลาสสิกอันงามสง่า ด้วยคันทางร่มเงาต้นหลิว สะพานหิน และเกาะน้อยใหญ่ กวีเอกซูตงปอผู้ถูกเนรเทศมาที่นี่ได้จารึกทะเลสาบไว้ในบทกวีให้เป็นอมตะ และคันทางริมทะเลสาบสายหนึ่งก็ยังคงใช้ชื่อของท่านมาจนถึงทุกวันนี้'),
  'huizhou/luofu': ('เขาหลัวฝู', 'ภูเขาหลัวฝูคือหนึ่งในภูเขาศักดิ์สิทธิ์ที่สุดของลัทธิเต๋าในจีนตอนใต้ ที่ดึงดูดเหล่าฤๅษีและนักเล่นแร่แปรธาตุขึ้นสู่ยอดเขามานานหลายศตวรรษ ผืนป่าที่เลื่องชื่อด้านสมุนไพรซ่อนวัดวาอาราม ธารน้ำพุ และเส้นทางเดินที่ไต่ขึ้นสู่หมู่เมฆเอาไว้'),
  'huizhou/alchemy': ('วิชาเล่นแร่แปรธาตุของเก่อหง', 'เก่อหง นักเล่นแร่แปรธาตุและแพทย์แห่งราชวงศ์จิ้น ปลีกตัวมาที่ภูเขาหลัวฝูเพื่อปรุงยาอายุวัฒนะและเขียนตำราแพทย์ของท่าน บันทึกเรื่องสมุนไพรชิงเฮาในคู่มือโบราณของท่านได้กลายเป็นแรงบันดาลใจให้การค้นพบยารักษามาลาเรียสมัยใหม่ในอีกหลายศตวรรษต่อมา'),
  'huizhou/xunliao': ('อ่าวซวิ่นเหลียว', 'อ่าวสวินเหลียวมีเสน่ห์ด้วยน้ำทะเลสีเทอร์ควอยซ์ตื้นใสและแนวหาดทรายสีอ่อนที่ทอดยาว จนกลายเป็นสถานตากอากาศยอดนิยมบนชายฝั่งกวางตุ้ง หมู่บ้านที่ครั้งหนึ่งเคยเป็นชุมชนประมงเล็ก ๆ วันนี้เสิร์ฟอาหารทะเลสดใหม่ และท้องทะเลอันสงบก็เหมาะกับครอบครัวที่มีเด็กเล็ก'),
  'meizhou/weilongwu': ('เมืองหลวงของชาวฮากกา', 'เหมยโจวได้รับการยกย่องเป็นเมืองหลวงทางจิตวิญญาณของชาวฮากกา (จีนแคะ) ที่กระจายตัวอยู่ทั่วโลก บ้านเหวยหลงอูรูปเกือกม้าอิงแนบเนินเขา รวบรวมคนทั้งตระกูลใหญ่ไว้ใต้หลังคาเดียวกัน และลานบ้านก็ยังคงคึกคักด้วยงานเทศกาลของตระกูลจนถึงทุกวันนี้'),
  'meizhou/saltchicken': ('ไก่เกลือ', 'ไก่อบเกลือคือตำรับคลาสสิกที่โด่งดังที่สุดของอาหารฮากกา ไก่ทั้งตัวถูกห่อกระดาษแล้วฝังลงในเกลือเม็ดหยาบร้อนจัดจนสุก เกลือไม่ได้ทำให้เนื้อแห้ง แต่กลับขังน้ำหวานฉ่ำไว้ภายใน ได้เนื้อไก่นุ่มดั่งแพรไหมหอมกรุ่นกลิ่นขิง'),
  'meizhou/football': ('แหล่งกำเนิดฟุตบอล', 'เหมยโจวคือหนึ่งในดินแดนแรก ๆ ที่ฟุตบอลสมัยใหม่หยั่งรากลงในจีน จนได้รับสมญานาม "อู่ข้าวอู่น้ำของฟุตบอลจีน" หลี่ฮุ่ยถัง ยอดกองหน้าในตำนานถือกำเนิดที่นี่ และไฟรักลูกหนังก็ยังคงลุกโชนตั้งแต่สนามหมู่บ้านไปจนถึงสโมสรอาชีพ'),
  'meizhou/plum': ('ดอกเหมย', 'ชื่อเมืองเหมยโจวมาจากตัวอักษรที่แปลว่า "บ๊วย" และแม่น้ำเหมยเจียงหรือแม่น้ำบ๊วยก็หล่อเลี้ยงเมืองนี้ ดอกบ๊วยที่ผลิบานท่ามกลางความหนาวเหน็บของฤดูหนาวคือสัญลักษณ์แห่งจิตวิญญาณอันอดทนบากบั่นของชาวฮากกา และปรากฏเป็นลวดลายประดับอยู่ทั่วทั้งเมือง'),
  'jiangmen/diaolou': ('เตียวโหลวไคผิง', 'หอเตี้ยวโหลวที่ตั้งตระหง่านกลางนาข้าวของไคผิงสร้างขึ้นในต้นศตวรรษที่ยี่สิบโดยชาวจีนโพ้นทะเลที่กลับมาจากต่างแดน ออกแบบเป็นป้อมปราการป้องกันโจรและน้ำท่วม อาคารเหล่านี้ผสมผสานเสาแบบตะวันตกเข้ากับหลังคาจีน และปัจจุบันได้รับการขึ้นทะเบียนเป็นมรดกโลกของยูเนสโก'),
  'jiangmen/qiaoxiang': ('ถิ่นฐานชาวจีนโพ้นทะเล', 'เจียงเหมินและภูมิภาคอู่อี้โดยรอบคือบ้านเกิดบรรพบุรุษของชาวจีนโพ้นทะเลหลายล้านคน ชาวจีนพลัดถิ่นจากทวีปอเมริกาจรดเอเชียตะวันออกเฉียงใต้ส่งเงินกลับมาสร้างโรงเรียน ถนน และคฤหาสน์ในบ้านเกิด มอบเอกลักษณ์ที่ผสานตะวันออกกับตะวันตกให้กับเมืองนี้'),
  'jiangmen/chenpi': ('เฉินผี', 'เฉินผีหรือผิวส้มแห้งของซินฮุ่ยต้องผ่านการตากแดดแล้วบ่มนานหลายปีก่อนนำมาใช้ มันมอบกลิ่นหอมอันลุ่มลึกให้อาหารกวางตุ้งและเป็นของล้ำค่าในการแพทย์แผนโบราณ ผิวส้มที่บ่มจนได้ที่จึงถูกทะนุถนอมราวกับไวน์ชั้นเลิศที่บ่มมานานปี'),
  'jiangmen/birds': ('อุทยานนก', '"สวรรค์ของนก" ที่ซินฮุ่ยแท้จริงแล้วคือต้นไทรยักษ์เพียงต้นเดียวที่แผ่กิ่งหยั่งรากจนปกคลุมทั่วทั้งเกาะเล็ก ๆ นกยางและนกน้ำนับพันมาเกาะพักอาศัยที่นี่ และความเรียงชื่อดังของนักเขียนปาจินก็ทำให้เกาะสีเขียวแห่งนี้เป็นที่รักของผู้คนทั่วทั้งจีน'),
  'yangjiang/knife': ('เมืองมีด', 'หยางเจียงคือเมืองหลวงแห่งมีดและกรรไกรของจีน มีดครัวส่วนใหญ่ของประเทศผลิตจากโรงช่างและโรงงานของเมืองนี้ ประเพณีตีเหล็กที่สืบทอดมาหลายศตวรรษได้หลอมรวมเข้ากับเทคโนโลยีเหล็กกล้าสมัยใหม่ พาแบรนด์ท้องถิ่นก้าวไกลไปสู่ห้องครัวทั่วโลก'),
  'yangjiang/shipwreck': ('ซากเรือหนานไห่หมายเลข 1', 'หนานไห่หมายเลข 1 คือเรือสินค้าสมัยราชวงศ์ซ่งที่อับปางบนเส้นทางสายไหมทางทะเลและหลับใหลอยู่ใต้ท้องทะเลนานหลายศตวรรษ เรือถูกกู้ขึ้นมาทั้งลำและปัจจุบันพักอยู่ในพิพิธภัณฑ์แท็งก์กระจกบนเกาะไห่หลิง โดยมีเครื่องกระเบื้องนับหมื่นชิ้นถูกนำขึ้นมาจากระวางเรือ'),
  'yangjiang/hailing': ('เกาะไห่หลิง', 'เกาะไห่หลิง พร้อมอ่าวต้าเจี่ยวรูปจันทร์เสี้ยวและหาดทรายอันนุ่มละเอียด คือหนึ่งในเกาะตากอากาศที่เป็นที่รักที่สุดของกวางตุ้ง กลางวันเหมาะแก่การว่ายน้ำเล่นคลื่น ยามเย็นลิ้มรสอาหารทะเลสดจากท่าเรือประมง และเกาะยังเป็นที่ตั้งของพิพิธภัณฑ์ซากเรือหนานไห่หมายเลข 1 อีกด้วย'),
  'yangjiang/kite': ('เมืองว่าว', 'หยางเจียงได้รับการยกย่องคู่กับเมืองเหวยฝางทางเหนือว่าเป็นหนึ่งในสองเมืองหลวงแห่งว่าวของจีน ว่าวโครงไม้ไผ่แบบดั้งเดิมถูกประดิษฐ์ด้วยมือที่นี่สืบต่อกันมาหลายชั่วอายุคน และทุกฤดูใบไม้ร่วงในเทศกาลฉงหยาง ท้องฟ้าจะเต็มไปด้วยปีกหลากสีสัน'),
  'qingyuan/rafting': ('แหล่งล่องแก่ง', 'ด้วยธารน้ำเชี่ยวที่ไหลหลากลงจากขุนเขา ชิงหย่วนจึงได้ชื่อในจีนว่าเป็น "บ้านของกีฬาล่องแก่ง" ฤดูร้อนนักท่องเที่ยวนับพันมาล่องเรือยางฝ่าสายน้ำฟองฟู ขณะที่หุบเขามีป่าไม้เย็นชื้นและแอ่งน้ำกลางโขดหินให้หลบร้อนไกลจากความอบอ้าวของเมือง'),
  'qingyuan/chicken': ('ไก่ชิงหยวน', 'ไก่พื้นเมืองขนลายจุดของชิงหย่วน กระดูกเล็กและรสชาติลุ่มลึก คือไก่ที่ถูกตามหามากที่สุดในอาหารกวางตุ้ง ไก่ที่เลี้ยงแบบปล่อยอิสระนี้มักถูกปรุงเพียงต้มสุกเสิร์ฟกับน้ำจิ้มขิงต้นหอม ความเรียบง่ายนั้นเองคือข้อพิสูจน์คุณภาพของมัน'),
  'qingyuan/hotspring': ('น้ำพุร้อน', 'น้ำพุร้อนอุดมแร่ธาตุที่ผุดขึ้นตามหุบเขาของชิงหย่วนทำให้เมืองนี้กลายเป็นศูนย์กลางสปาของกวางตุ้ง ไอน้ำลอยกรุ่นจากบ่อกลางแจ้งท่ามกลางเสียงป่าไผ่ไหวเสียดสียามลมพัด และนักท่องเที่ยวสุดสัปดาห์จากกว่างโจวก็มาแช่น้ำละลายความเหนื่อยล้ากันที่นี่'),
  'qingyuan/yaoterrace': ('นาขั้นบันไดเผ่าเย้า', 'ในหมู่บ้านชาวเหยาแห่งเหลียนหนาน นาขั้นบันไดไต่ระดับขึ้นไปตามไหล่เขาทีละชั้น คันนาที่สร้างด้วยมือมาหลายศตวรรษจะกลายเป็นกระจกเงาแห่งผืนน้ำในฤดูใบไม้ผลิและบันไดสีทองในฤดูใบไม้ร่วง ขณะที่หมู่บ้านเหยาโบราณยังคงดำรงชีวิตอยู่ท่ามกลางผืนนาเหล่านั้น'),
  'chaozhou/guangjibridge': ('สะพานกวงจี้', 'สะพานกว่างจี้ที่ทอดข้ามแม่น้ำหานเจียง เริ่มสร้างในสมัยราชวงศ์ซ่ง โดดเด่นไม่เหมือนใครด้วยช่วงกลางสะพานที่เป็นเรือผูกเรียงต่อกัน ส่วนสะพานเรือนี้จะเปิดออกทุกวันเพื่อให้เรือใหญ่แล่นผ่าน ทำให้ได้รับการยกย่องเป็นหนึ่งในสี่สะพานโบราณอันเลื่องชื่อของจีน'),
  'chaozhou/woodcarving': ('งานแกะสลักไม้ปิดทอง', 'งานแกะสลักไม้ปิดทองของเฉาโจว (แต้จิ๋ว) คืองานฝีมือระดับตำนานที่ซ้อนฉากแล้วฉากเล่าไว้ในแผ่นไม้เพียงแผ่นเดียว ทุกรายละเอียดตั้งแต่แหจับปลาไปจนถึงวีรบุรุษในงิ้วถูกแกะอย่างประณีตแม่นยำ และผลงานปิดทองคำเปลวเหล่านี้ก็ประดับวัดวาและคฤหาสน์ให้เปล่งประกายระยิบระยับ'),
  'chaozhou/chaoxiu': ('ผ้าปักเฉาโจว', 'งานปักเฉาโจวคือสายที่หรูหราที่สุดของงานเข็มแห่งกวางตุ้ง ด้ายทองและเงินถูกปักทับวัสดุรองจนเกิดลายนูนราวงานประติมากรรม มังกรและหงส์ดูราวกับพร้อมจะโผนทะยานออกจากผืนผ้า ประดับประดาทั้งชุดเจ้าสาวและเครื่องแต่งกายงิ้วมาช้านาน'),
  'chaozhou/kaiyuan': ('วัดไคหยวน', 'วัดไคหยวนก่อตั้งขึ้นในปี 738 ในรัชศกไคหยวนแห่งราชวงศ์ถัง และยังคงใช้ชื่อรัชสมัยนั้นมาจนถึงทุกวันนี้ การสักการะในลานวัดดำเนินต่อเนื่องมานานกว่าหนึ่งพันปี กระถางธูปยักษ์ส่งควันคุกรุ่นใต้วิหารที่ประดับด้วยงานแกะสลักไม้ชั้นเยี่ยมที่สุดของเฉาโจว'),
  'jieyang/citygate': ('ประตูจิ้นเซียน', 'ประตูจิ้นเสียนหรือ "ประตูต้อนรับผู้ทรงคุณธรรม" คือสัญลักษณ์อันงามสง่าที่หลงเหลือจากเมืองเจียหยางโบราณ หอไม้ชายคาซ้อนชั้นของประตูมองลงสู่คูเมืองเบื้องล่าง และชื่อของมันก็สื่อถึงความปรารถนาของเมืองที่จะต้อนรับผู้มีปัญญาและคุณงามความดี'),
  'jieyang/jade': ('เมืองหลวงแห่งหยก', 'หยางเหมย เมืองเล็กในสังกัดเจียหยาง คือหนึ่งในศูนย์กลางแกะสลักและค้าหยกที่ใหญ่ที่สุดของจีน หยกเจไดต์ดิบจากเมียนมาถูกตัด แกะสลัก และขัดเงาที่นี่ และในตรอกตลาด เหล่าเซียนหยกก็อ่านสีเขียวที่ซ่อนอยู่ในหินแต่ละก้อนราวกับการเสี่ยงพนัน'),
  'jieyang/jieyanglou': ('หอเจียหยาง', 'หอเจียหยางคืออนุสรณ์สถานสมัยใหม่ที่ฟื้นคืนสถาปัตยกรรมโบราณด้วยชายคาแบบดั้งเดิมอันอ่อนช้อยและรูปทรงสง่าผ่าเผย ภายในจัดแสดงนิทรรศการทางวัฒนธรรม หอแห่งนี้คือความภาคภูมิใจในรากเหง้าของชาวเฉาซ่านที่ถ่ายทอดออกมาเป็นหินและไม้'),
  'jieyang/beefbroth': ('ซุปเนื้อเฉาซาน', 'ซุปเนื้อและหม้อไฟเนื้อวัวแบบเฉาซ่านคือศาสตร์อาหารที่อุทิศให้กับความสด เนื้อแต่ละส่วนของวัวมีชื่อเรียกเฉพาะและเวลาลวกในน้ำซุปใสที่นับกันเป็นวินาที เสิร์ฟคู่กับน้ำจิ้มซาฉา ความเชี่ยวชาญที่ซ่อนอยู่ในความเรียบง่ายนี้คือความภาคภูมิใจของภูมิภาค'),
  'yunfu/marble': ('อาณาจักรหิน', 'หยุนฝูเป็นที่รู้จักในฐานะเมืองหลวงแห่งงานหินของจีน หินอ่อนและหินแกรนิตถูกตัดและขัดเงาที่นี่มาหลายชั่วอายุคน โรงงานนับพันที่เรียงรายตามทางหลวงส่งท็อปเคาน์เตอร์ รูปสลัก และหินตกแต่งอาคารไปทั่วโลก หินคืออาชีพเลี้ยงปากท้องประจำวันของเมืองนี้'),
  'yunfu/patriarch': ('ปรมาจารย์องค์ที่หก', 'ท่านเว่ยหล่าง (ฮุ่ยเหนิง) พระสังฆปริณายกองค์ที่หกแห่งพุทธศาสนานิกายเซน ถือกำเนิดที่ซินซิงในเขตหยุนฝูและใช้ชีวิตช่วงสุดท้ายที่นี่ วัดกั๋วเอินที่สร้างขึ้นเป็นเกียรติแด่ท่านคือศูนย์รวมใจอันสงบที่ดึงดูดผู้แสวงบุญ ที่นี่คือจุดเริ่มต้นเรื่องราวของท่าน จากเด็กตัดฟืนสู่พระอาจารย์ผู้ตรัสรู้'),
  'yunfu/tianlu': ('ภูเขาเทียนลู่', 'ภูเขาเทียนลู่คือมงกุฎสีเขียวของหยุนฝู สันเขาทอดยาวขึ้นสู่หมู่เมฆและไหล่เขาปกคลุมด้วยไร่ชา ยามเช้าหุบเขามักถูกเติมเต็มด้วยทะเลเมฆ มอบรางวัลแก่นักเดินเขาที่ปีนขึ้นไปรอชมอาทิตย์ขึ้นด้วยภาพยอดเขาที่ผุดพ้นขึ้นจากสายหมอก'),
  'yunfu/xijiang': ('แม่น้ำซีเจียง', 'ซีเจียงหรือแม่น้ำตะวันตกคือแขนงหลักของระบบแม่น้ำจูเจียง และเป็นหนึ่งในเส้นทางน้ำที่คึกคักที่สุดของจีนตอนใต้ เรือลำเลียงสินค้าแล่นผ่านหน้าเมืองหยุนฝูทั้งวันทั้งคืน และแม่น้ำสายนี้ก็ยังคงเป็นเส้นเลือดใหญ่ที่ขนหินและผลผลิตการเกษตรล่องลงไปยังกว่างโจวและออกสู่โลกกว้าง'),
  'liuzhou/luosifen': ('หลัวซือเฝิ่น', 'หลัวซือเฟิ่น เส้นหมี่หอยขมแห่งหลิ่วโจว เลื่องชื่อด้วยน้ำซุปที่เคี่ยวกับหอยขมแม่น้ำและกลิ่นฉุนเปรี้ยวจี๊ดของหน่อไม้ดอง กลิ่นของมันอาจสร้างเสียงแตกแยกตั้งแต่ไกล แต่ลิ้มรสเพียงครั้งเดียวก็มักติดใจ และในรูปแบบบะหมี่กึ่งสำเร็จรูป จานท้องถิ่นนี้ได้พิชิตทั้งจีนและก้าวไกลไปทั่วโลก'),
  'liuzhou/autocity': ('เมืองยานยนต์', 'หลิ่วโจวคือหัวใจอุตสาหกรรมของกว่างซีและเป็นหนึ่งในฐานการผลิตรถยนต์ที่สำคัญของจีน รถยนต์ไฟฟ้าคันเล็กราคาย่อมเยาที่ผลิตที่นี่กลายเป็นสัญลักษณ์ประจำท้องถนนของเมือง ชาวเมืองรักมันเพราะสามารถแทรกเข้าช่องจอดรถที่แคบที่สุดได้อย่างสบาย'),
  'liuzhou/karst': ('ภูมิประเทศคาสต์แม่น้ำหลิ่ว', 'แม่น้ำหลิ่วเจียงโอบวนรอบเมืองราวสายเข็มขัด โดยมียอดเขาหินปูนตั้งตระหง่านอยู่ทุกทิศ โค้งน้ำอันยิ่งใหญ่นี้ทำให้หลิ่วโจวได้รับสมญานาม "เมืองกาน้ำชา" และใจกลางเมืองอุตสาหกรรมแห่งนี้ สวนริมแม่น้ำและยอดเขาคาสต์ก็มอบความงามทางธรรมชาติที่เหนือความคาดหมาย'),
  'liuzhou/liuhou': ('หลิวจงหยวน', 'หลิวจงหยวน มหากวีแห่งราชวงศ์ถัง รับตำแหน่งเจ้าเมืองในถิ่นเนรเทศของตนที่หลิ่วโจว ท่านสั่งขุดบ่อน้ำให้ราษฎรและดูแลคนยากไร้ ศาลเจ้าที่อุทิศแด่ท่านตั้งอยู่ในสวนหลิ่วโหวใจกลางเมือง และมหากวีผู้นี้ก็ยังคงผูกพันแนบแน่นกับเมืองที่ท่านใช้ชีวิตในบั้นปลาย'),
  'wuzhou/gemstone': ('เมืองหลวงแห่งอัญมณี', 'อู๋โจวคือเมืองหลวงแห่งอัญมณีสังเคราะห์ของโลก เพชรเทียมเซอร์โคเนียส่วนใหญ่ของโลกถูกเจียระไนและขัดเงาในโรงงานริมแม่น้ำของเมืองนี้ มือช่างผู้ชำนาญเจียรเหลี่ยมแล้วเหลี่ยมเล่าลงบนเม็ดหินจิ๋ว ก่อนอัญมณีระยิบระยับจะกระจายจากที่นี่สู่ตลาดเครื่องประดับทั่วโลก'),
  'wuzhou/liubaotea': ('ชาหลิ่วเป่า', 'ชาลิ่วเป่าของอู๋โจวคือชาหมักสีเข้มที่ยิ่งบ่มนานปียิ่งกลมกล่อม ครั้งหนึ่งเคยถูกส่งทางเรือแม่น้ำไปให้คนงานเหมืองในเอเชียตะวันออกเฉียงใต้ ผู้เชื่อมั่นว่าชานี้ช่วยปรับสมดุลร่างกายในภูมิอากาศชื้น ปัจจุบันตะกร้าชาบ่มเก่าแก่กลายเป็นของหายากที่นักสะสมเสาะแสวงหา'),
  'wuzhou/turtlejelly': ('กุยหลิงเกา', 'อู๋โจวได้ชื่อว่าเป็นบ้านเกิดของกุยหลิงเกา วุ้นสีดำที่ปรุงขึ้นจากสมุนไพรบำรุงร่างกาย วุ้นรสขมอ่อน ๆ นี้กินแบบเย็นราดน้ำผึ้ง เป็นประเพณีดับร้อนที่เชื่อกันว่าช่วยขับ "ไฟใน" ของร่างกายในฤดูร้อนอันชื้นแฉะของแดนใต้'),
  'wuzhou/dragonmother': ('ศาลเจ้าแม่มังกร', 'วัดพระแม่มังกรริมฝั่งแม่น้ำซีเจียงอุทิศแด่เทพีผู้ได้รับการนับถือเป็นผู้พิทักษ์ของชาวลุ่มน้ำ ตำนานเล่าว่าพระแม่มังกรเลี้ยงดูมังกรห้าตัวดั่งลูกแท้ ๆ และปกป้องผู้คนจากอุทกภัย ในวันเทศกาลวัดจะคลาคล่ำไปด้วยควันธูปและริบบิ้นคำอธิษฐาน'),
  'beihai/silverbeach': ('หาดเงิน', 'หาดเงินแห่งเป๋ยไห่ระยิบระยับสมชื่อ ผืนทรายขาวที่อุดมด้วยผลึกควอตซ์เปล่งประกายสีเงินกลางแสงแดด ชายหาดที่ได้รับการยกย่องว่าเป็น "หาดอันดับหนึ่งใต้ฟ้า" นี้ทอดยาวหลายกิโลเมตร และทะเลตื้นอันอบอุ่นก็มอบพื้นที่ว่ายน้ำและเดินเล่นอย่างไม่มีที่สิ้นสุด'),
  'beihai/pearl': ('เมืองไข่มุก', 'เหอผู่ในเขตเป๋ยไห่เลื่องชื่อเรื่องไข่มุกมาตั้งแต่สมัยราชวงศ์ฮั่น "ไข่มุกใต้" ของที่นี่จัดเป็นเครื่องบรรณาการล้ำค่าที่สุดที่ถวายแด่ราชสำนัก สำนวน "ไข่มุกคืนสู่เหอผู่" ถือกำเนิดบนชายฝั่งแห่งนี้ และฟาร์มไข่มุกกับตลาดเครื่องประดับก็ยังคงสืบสานประเพณีให้มีชีวิตต่อไป'),
  'beihai/weizhou': ('เกาะเวยโจว', 'เกาะเหวยโจวนอกชายฝั่งเป๋ยไห่เป็นที่รู้จักในฐานะเกาะภูเขาไฟที่อายุน้อยที่สุดของจีน ผาหินลาวาสีดำ แนวปะการัง และสวนกล้วยโอบล้อมชายฝั่งของเกาะ ส่วนโบสถ์คาทอลิกหินที่เหล่ามิชชันนารีสร้างขึ้นในศตวรรษที่สิบเก้าก็ยืนเป็นภาพที่เหนือความคาดหมายที่สุดบนเกาะ'),
  'beihai/oldstreet': ('ถนนเก่า', 'ถนนสายเก่าของเป๋ยไห่เรียงรายด้วยอาคารฉีโหลวที่มีทางเดินโค้งซุ้ม ซึ่งผุดขึ้นเมื่อท่าเรือเปิดรับการค้าต่างชาติในปลายศตวรรษที่สิบเก้า หน้าอาคารทรงโค้งสะท้อนกลิ่นอายของเอเชียตะวันออกเฉียงใต้และยุโรป และวันนี้ถนนก็ยังรักษาอดีตให้มีชีวิตท่ามกลางแผงหอยนางรมทอดและร่องรอยสถานกงสุลเก่า'),
  'qinzhou/nixingpottery': ('เครื่องปั้นดินเผาหนีซิง', 'เครื่องปั้นดินเผาหนีซิงของชินโจวเผาโดยไม่เคลือบใด ๆ แต่กลับเกิดสีบรอนซ์ แดงเข้ม และม่วงขึ้นเองภายในเตาเผา ทำจากดินเหนียวจากสองฟากฝั่งแม่น้ำที่นำมาผสมกัน งานฝีมือนี้ได้รับการจัดอันดับเป็นหนึ่งในสี่ประเพณีเครื่องปั้นดินเผาอันเลื่องชื่อของจีน'),
  'qinzhou/dolphin': ('โลมาขาว', 'อ่าวซานเหนียงแห่งชินโจวคือถิ่นอาศัยที่เป็นที่รู้จักมากที่สุดแห่งหนึ่งของโลมาขาวจีนอันหายาก สัตว์เลี้ยงลูกด้วยนมแสนสง่างามนี้จะเปลี่ยนเป็นสีชมพูเมื่ออายุมากขึ้นและโผล่ขึ้นเหนือน้ำข้างเรือนำเที่ยว ชาวบ้านที่นี่ภาคภูมิใจในการปกป้องสิ่งที่พวกเขาเรียกว่า "แพนด้าแห่งท้องทะเล"'),
  'qinzhou/oysterfarm': ('แหล่งเลี้ยงหอยนางรม', 'ทะเลเม่าเหว่ยอันตื้นและอุดมด้วยสารอาหารของชินโจวคือแหล่งอนุบาลลูกหอยนางรมที่ยิ่งใหญ่ที่สุดแห่งหนึ่งของจีน ผิวน้ำปกคลุมด้วยแพลอยน้ำที่เรียงกันเป็นแถวแล้วแถวเล่า และผลผลิตเนื้อแน่นอวบอ้วนก็ทำให้เมืองนี้เป็นเมืองหลวงหอยนางรมของแดนใต้ ที่เตาย่างในฤดูเทศกาลไม่เคยดับ'),
  'qinzhou/general': ('นายพลเฟิง จื่อไฉ', 'เฝิงจื่อไฉ ขุนพลแห่งราชวงศ์ชิง หวนคืนจากการเกษียณในวัยชราเพื่อนำทัพและคว้าชัยชนะครั้งประวัติศาสตร์เหนือการรุกรานที่ด่านเจิ้นหนานบริเวณชายแดนเวียดนาม ที่บ้านเกิดชินโจว จวนเก่าของท่านได้รับการอนุรักษ์เป็นพิพิธภัณฑ์ และชื่อของท่านก็ยังคงเป็นสัญลักษณ์แห่งการปกป้องมาตุภูมิ'),
  'guigang/lotus': ('เมืองบัว', 'กุ้ยก่างเป็นที่รู้จักในจีนในนาม "เมืองดอกบัว" ยามฤดูร้อนสระน้ำและท้องทุ่งรอบเมืองจะดารดาษด้วยดอกบัวสีชมพูและสีขาว รากบัวและเม็ดบัวคือวัตถุดิบประจำครัวท้องถิ่น และเทศกาลดอกบัวประจำปีก็ทำให้ทั้งเมืองครึกครื้นด้วยงานเฉลิมฉลอง'),
  'guigang/uprising': ('การก่อการกำเริบจินเทียน', 'ในปี 1851 ณ หมู่บ้านจินเถียนในเขตกุ้ยผิง หงซิ่วเฉวียนได้ชูธงการลุกฮือไท่ผิง หนึ่งในขบวนการประชาชนที่ยิ่งใหญ่ที่สุดของศตวรรษที่สิบเก้าได้แผ่ขยายออกไปจากที่นี่จนสั่นสะเทือนครึ่งประเทศจีน และวันนี้อนุสรณ์สถานในหมู่บ้านก็บอกเล่าเรื่องราวของยุคแห่งพายุนั้น'),
  'guigang/nanshan': ('วัดหนานซาน', 'วัดหนานซานแห่งกุ้ยก่างคือศาสนสถานอายุนับพันปีที่สร้างแทรกอยู่ในถ้ำธรรมชาติของเขาหินปูน ผนังถ้ำเรียงรายด้วยจารึกและบทกวีที่สลักสะสมกันมาหลายราชวงศ์ ขณะที่พระพุทธรูปประทับนิ่งสงบอยู่ในห้องโถงหินอันเย็นฉ่ำ'),
  'guigang/sugarcane': ('อ้อย', 'กว่างซีคือแหล่งผลิตน้ำตาลที่ใหญ่ที่สุดของจีน และที่ราบลุ่มแม่น้ำอันอุดมสมบูรณ์ของกุ้ยก่างก็คือส่วนสำคัญของการเก็บเกี่ยวอันหอมหวานนี้ พอถึงฤดูใบไม้ร่วงต้นอ้อยจะสูงท่วมหัวคน และในฤดูตัดอ้อยถนนหนทางก็เนืองแน่นด้วยรถบรรทุกที่ลำเลียงอ้อยสู่โรงงาน'),
  'yulin/medicine': ('ตลาดสมุนไพร', 'ตลาดสมุนไพรของอวี้หลินคือหนึ่งในศูนย์กลางการค้ายาแผนโบราณที่ใหญ่ที่สุดของจีนตอนใต้ ตามทางเดินอบอวลด้วยกลิ่นราก เปลือกไม้ และดอกไม้แห้งที่คละเคล้ากัน และพ่อค้าที่นี่ก็รู้อุปนิสัยของสมุนไพรทุกชนิดขึ้นใจ ในฐานะทายาทของภูมิปัญญาที่สั่งสมมาหลายศตวรรษ'),
  'yulin/goldenpalace': ('วังหยุนเทียน', 'หอหยุนเทียนคืออาคารทางวัฒนธรรมอันโอฬารที่ตีความสถาปัตยกรรมพระราชวังโบราณขึ้นใหม่ในขนาดมหึมา แต่ละชั้นจัดแสดงงานแกะสลักอันละเอียดลออ รูปหล่อสำริด และฉากจากตำนานปรัมปรา ส่วนยอดหอปิดทองก็เป็นจุดเด่นที่สะดุดตาที่สุดของเส้นขอบฟ้าเมือง'),
  'yulin/lychee': ('สวนลิ้นจี่', 'เนินเขาและหุบเขาอันอบอุ่นของอวี้หลินปกคลุมด้วยสวนลิ้นจี่และลำไย ต้นฤดูร้อนกิ่งไม้จะโน้มลู่ลงด้วยพวงผลสีแดง แผงตลาดล้นหลามด้วยผลไม้หอมหวาน และครอบครัวต่างเฉลิมฉลองวันเก็บผลราวกับเป็นวันเทศกาล'),
  'yulin/beef': ('เนื้อหนิวปา', 'หนิวปา ของว่างขึ้นชื่อประจำอวี้หลิน ทำจากเนื้อวัวแล่บางที่ค่อย ๆ ตากแห้งแล้วเคี่ยวอย่างช้า ๆ ในซอสเครื่องเทศ เนื้อสีเข้ม หวานอ่อน ๆ และเข้มข้นถึงรสนี้กินคู่กับข้าวสวยหรือแกล้มน้ำชา โดยสูตรลับถูกส่งต่อกันภายในครอบครัวจากรุ่นสู่รุ่น'),
  'baise/redbase': ('การก่อการกำเริบไป๋เซ่อ', 'ในปี 1929 การลุกฮือไป่เซ่อที่นำโดยเติ้งเสี่ยวผิงในวัยหนุ่มได้ก่อตั้งฐานที่มั่นปฏิวัติขึ้นริมแม่น้ำโยวเจียง เมืองนี้จึงเป็นหมุดหมายสำคัญบนเส้นทาง "ความทรงจำสีแดง" ของจีน โดยหอรำลึกและอาคารกองบัญชาการเก่ายังคงถ่ายทอดยุคสมัยนั้นมาสู่ปัจจุบัน'),
  'baise/sinkhole': ('หลุมยุบเล่อเย่', 'หลุมยุบยักษ์หรือ "เทียนเคิง" แห่งอำเภอเล่อเย่รวมตัวกันเป็นหนึ่งในกลุ่มหลุมยุบที่หนาแน่นที่สุดในโลก ผืนป่าที่มนุษย์ไม่เคยแตะต้องเติบโตอยู่ที่ก้นหลุมลึกลงไปหลายร้อยเมตร และแม่น้ำใต้ดินกับระบบถ้ำก็ทำให้ที่นี่เป็นขวัญใจของนักธรณีวิทยาและนักสำรวจถ้ำ'),
  'baise/mango': ('เมืองหลวงแห่งมะม่วง', 'หุบเขาร้อนแดดจัดของไป่เซ่อติดอันดับแหล่งปลูกมะม่วงที่สำคัญที่สุดของจีน กลางฤดูร้อนไหล่เขาจะเปลี่ยนเป็นสีทองอร่าม รถบรรทุกลำเลียงผลไม้หวานฉ่ำไปทุกมุมประเทศ และมะม่วงก็กลายเป็นทั้งแหล่งรายได้เลี้ยงชีพและสัญลักษณ์ความภาคภูมิใจของอำเภอภูเขาเหล่านี้'),
  'baise/aluminum': ('เมืองอะลูมิเนียม', 'ขุนเขาแห่งไป่เซ่ออุดมด้วยแร่บอกไซต์ สินแร่ที่ทำให้เมืองนี้กลายเป็นฐานทางใต้ของอุตสาหกรรมอะลูมิเนียมจีน เหมืองแร่และโรงถลุงคือกระดูกสันหลังของเศรษฐกิจภูมิภาค และโลหะ "สีเงิน" ใต้ผืนดินสีแดงนี้ก็มอบงานให้กับครอบครัวนับพัน'),
  'hechi/longevity': ('ปาหม่า ดินแดนแห่งผู้มีอายุยืน', 'ปาหม่าในเขตเหอฉือคือ "ดินแดนแห่งอายุวัฒนะ" ที่โด่งดังระดับโลก ด้วยสัดส่วนผู้อยู่อาศัยที่อายุเกินหนึ่งร้อยปีสูงอย่างน่าทึ่ง อากาศบริสุทธิ์ อาหารเรียบง่าย และชีวิตที่ไม่เร่งรีบถูกเชื่อว่าเป็นเคล็ดลับ ผู้คนนับพันจึงเดินทางมาแสวงหาสุขภาพในหุบเขาเหล่านี้ทุกปี'),
  'hechi/folksong': ('หลิวซานเจี่ย', 'อี๋โจวในเหอฉือได้รับเกียรติเป็นบ้านเกิดของหลิวซานเจี่ย นักร้องเพลงพื้นบ้านในตำนานของชาวจ้วง ในนิทานเล่าขาน "นางฟ้าแห่งเสียงเพลง" เอาชนะเหล่าเจ้าที่ดินด้วยการประชันเพลงแบบด้นสด ประเพณีนี้ยังคงเบ่งบานอย่างมีชีวิตชีวาในงานมหกรรมเพลงพื้นบ้านจนถึงทุกวันนี้'),
  'hechi/bronzedrum': ('กลองสำริด', 'กลองมโหระทึกคือหนึ่งในวัตถุศักดิ์สิทธิ์ที่สุดของชนชาติทางใต้อย่างชาวจ้วงและชาวเหยา และเหอฉือก็ได้ชื่อว่าเป็นหัวใจของวัฒนธรรมกลองมโหระทึกที่ยังมีชีวิต กลองลายนูนจะถูกตีในงานเทศกาลด้วยความเชื่อว่าเสียงของมันเรียกพรและการคุ้มครอง และหลายหมู่บ้านก็เก็บรักษากลองอายุหลายร้อยปีไว้ดั่งมรดกตกทอด'),
  'hechi/geopark': ('อุทยานธรณีคาสต์', 'ผืนดินคาสต์ของเหอฉือคือห้องทดลองทางธรรมชาติแห่งหลุมยุบ ห้องถ้ำอันมโหฬาร และแม่น้ำใต้ดิน สะพานหินธรรมชาติและช่องแสงบนเพดานถ้ำรอบเฟิ่งซานคือดาวเด่นของอุทยานธรณี และที่ใดที่แสงส่องลอดผ่านปล่องลงไป โลกที่ซ่อนเร้นอยู่เบื้องล่างก็ปรากฏให้เห็น'),
  'laibin/sugarcity': ('เมืองหลวงแห่งน้ำตาล', 'ที่ราบของไหลปินปกคลุมด้วยไร่อ้อยไกลสุดลูกหูลูกตา จนได้รับสมญานาม "เมืองหลวงน้ำตาลของจีน" เมื่อฤดูเก็บเกี่ยวหน้าหนาวเริ่มต้นขึ้น ปล่องโรงงานก็เริ่มพ่นควัน เปลี่ยนอ้อยให้เป็นน้ำตาล กากน้ำตาล และกระดาษ ขณะที่กลิ่นหอมหวานลอยอบอวลไปทั่วเมืองน้อยใหญ่'),
  'laibin/yao': ('ชาวเย้าต้าเหยา', 'เทือกเขาต้าเหยาแห่งจินซิ่วในเขตไหลปินคือบ้านของชาวเหยาห้าสาขาที่แตกต่างกัน แต่ละกลุ่มมีเครื่องแต่งกาย สำเนียงภาษา และพิธีกรรมเป็นของตนเอง เครื่องประดับเงินและเครื่องสวมศีรษะปักลายส่องประกายในงานเทศกาลหมู่บ้าน ทำให้จินซิ่วเป็นพิพิธภัณฑ์วัฒนธรรมที่มีชีวิต'),
  'laibin/hongshui': ('แม่น้ำหงสุ่ย', 'หงสุ่ย แม่น้ำที่ได้ชื่อจากตะกอนสีแดงที่มันพัดพา คือสายน้ำทรงพลังที่ผ่ากลางขุนเขาแห่งกว่างซี เขื่อนที่สร้างตามหุบเขาส่งกระแสไฟฟ้าไปทั่วแดนใต้ ขณะที่หมู่บ้านริมน้ำก็ได้ชื่นชมทิวทัศน์ที่แม่น้ำแกะสลักไว้ระหว่างยอดเขาคาสต์'),
  'laibin/shengtang': ('ภูเขาเซิ่งถัง', 'ภูเขาเชิ่งถังคือยอดสูงสุดของเทือกเขาต้าเหยา และนับเป็นหนึ่งในยอดเขาที่เปรียบดั่งหลังคาแห่งกว่างซี ฤดูใบไม้ผลิไหล่เขาจะลุกโชนด้วยดอกกุหลาบพันปีสีแดง ส่วนบนยอดเขา ทะเลเมฆ แสงอรุณ และสายหมอกที่ปลิวไสวตามลมคือรางวัลสำหรับผู้ที่ปีนขึ้นไป'),
  'chongzuo/waterfall': ('น้ำตกเต๋อเทียน', 'น้ำตกเต๋อเทียนทิ้งตัวลงเป็นชั้นกว้างเหนือแม่น้ำบนพรมแดนจีน–เวียดนาม และได้ชื่อว่าเป็นน้ำตกข้ามพรมแดนที่ใหญ่ที่สุดในเอเชีย แพไม้ไผ่พาคุณเข้าใกล้ละอองน้ำเย็นฉ่ำของม่านน้ำตก ขณะที่ยอดเขาคาสต์ที่รายล้อมก็แปลงทั้งฉากให้กลายเป็นภาพวาดพู่กันจีน'),
  'chongzuo/langur': ('ค่างหัวขาว', 'ค่างหัวขาวอาศัยอยู่เฉพาะบนเขาหินปูนของฉงจั่วเท่านั้น และนับเป็นไพรเมตที่หายากที่สุดชนิดหนึ่งของโลก มันนอนหลับในซอกหน้าผายามค่ำคืนและกระโดดข้ามผาหินสูงชันยามกลางวัน และด้วยเขตอนุรักษ์ที่คุ้มครอง ประชากรของมันก็กำลังค่อย ๆ ฟื้นตัว'),
  'chongzuo/rockart': ('ศิลปะบนหินฮวาซาน', 'ภาพเขียนสีแดงบนหน้าผาแม่น้ำจั่วเจียง ซึ่งชาวหลัวเยว่วาดไว้เมื่อราวสองพันปีก่อน แสดงภาพผู้คนนับพันร่ายรำในท่วงท่าคล้ายกบ วิธีการวาดบนผาสูงชันที่แทบเข้าถึงไม่ได้นั้นยังคงเป็นที่ถกเถียง และศิลปะบนหินนี้ก็ได้รับการขึ้นทะเบียนเป็นมรดกโลกของยูเนสโก'),
  'chongzuo/borderpass': ('ด่านมิตรภาพ', 'ด่านโหย่วอี้กวานหรือด่านมิตรภาพคือประตูพรมแดนทางประวัติศาสตร์ที่เชื่อมจีนกับเวียดนาม และนับเป็นหนึ่งในด่านอันเลื่องชื่อของจีน หอประตูโค้งท่ามกลางขุนเขาเขียวขจีเคยต้อนรับกองทัพ กองคาราวาน และคณะทูตมานานหลายศตวรรษ และวันนี้ก็ยังคงเป็นประตูการค้าชายแดนอันคึกคักมีชีวิตชีวา'),
  'beijing/great-wall': ('กำแพงเมืองจีน', 'ป้อมปราการที่ยาวที่สุดในโลก — กว่า 20,000 กิโลเมตร สร้างขึ้นต่อเนื่องหลายศตวรรษเพื่อปกป้องพรมแดนทางเหนือของจีน ช่วงปาต๋าหลิ่งใกล้ปักกิ่ง ด้วยขั้นบันไดหินและหอสังเกตการณ์บนสันเขา คือช่วงกำแพงที่มีผู้มาเยือนมากที่สุด'),
  'beijing/temple': ('หอสักการะฟ้าเทียนถาน', 'หมู่อาคารศักดิ์สิทธิ์ที่จักรพรรดิราชวงศ์หมิงและชิงเสด็จมาถวายสักการะฟ้าทุกปีเพื่อขอพรให้ผลเก็บเกี่ยวอุดมสมบูรณ์ หลังคาทรงกลมสีน้ำเงินสามชั้นของมัน — ซึ่งสร้างโดยไม่ใช้ตะปูแม้แต่ตัวเดียว — คือหนึ่งในสัญลักษณ์ที่เป็นที่จดจำมากที่สุดของสถาปัตยกรรมจีน'),
  'beijing/pagoda': ('เจดีย์เทียนหนิง', 'เจดีย์อิฐ 13 ชั้นสูงราว 57 เมตรจากราชวงศ์เหลียว ด้วยลวดลายสลักนูนและเรือนทรงแปดเหลี่ยม นับเป็นหนึ่งในสิ่งก่อสร้างเก่าแก่ที่สุดที่ยังคงเหลืออยู่ของปักกิ่ง — ประจักษ์พยานแห่งประวัติศาสตร์พันปีของเมือง'),
  'beijing/opera': ('อุปรากรปักกิ่ง', 'ศิลปะการแสดงจีนดั้งเดิมอายุ 200 ปีที่หลอมรวมการขับร้อง บทเจรจา ศิลปะการต่อสู้ และกายกรรมเข้าด้วยกัน การเขียนหน้าหลากสี (เหลียนผู่) ของนักแสดงเผยนิสัยของแต่ละตัวละคร: สีแดงหมายถึงความภักดี สีขาวหมายถึงความเจ้าเล่ห์'),
  'zunyi/huiyi': ('สถานที่ประชุมจุนอี้', 'ในช่วงวันเวลาอันมืดมนที่สุดของการเดินทัพทางไกล เหล่าผู้นำพรรคคอมมิวนิสต์ได้มาประชุมกันที่คฤหาสน์หินสีเทาหลังนี้ในปี 1935 เพื่อวางเส้นทางใหม่ให้แก่การปฏิวัติ และเปิดทางสู่การก้าวขึ้นเป็นผู้นำของเหมา เจ๋อตง ปัจจุบันบ้านหลังนี้กลายเป็นพิพิธภัณฑ์ที่ทำให้จุนอี้เป็นหัวใจของแผนที่ \'การท่องเที่ยวสีแดง\' ของจีน'),
  'zunyi/moutai': ('เมืองเหมาไถ', 'เมืองเล็ก ๆ ชื่อเหมาไถริมแม่น้ำชื่อสุ่ย คือบ้านเกิดของไป๋จิ่วในตำนานที่ได้รับการยกย่องว่าเป็นสุราประจำชาติของจีน สุรารสร้อนแรงชนิดนี้กลั่นจากข้าวฟ่างและบ่มนานหลายปี จนกลายเป็นเครื่องดื่มคู่งานเลี้ยงระดับรัฐ แม้แต่อากาศในเมืองก็ยังอบอวลไปด้วยกลิ่นหอมของการหมักบ่ม'),
  'zunyi/loushan': ('ช่องเขาโหลวซาน', 'ด่านโหลวซานอันสูงชันที่ผ่ากลางขุนเขา คือสมรภูมิแห่งชัยชนะครั้งประวัติศาสตร์ของกองทัพแดงระหว่างการเดินทัพทางไกล เหมา เจ๋อตงได้ประพันธ์บทกวีอันเลื่องชื่อที่นี่จนทำให้ด่านแห่งนี้เป็นอมตะ ทุกวันนี้ผู้มาเยือนจะปีนขึ้นหน้าผาที่ปกคลุมด้วยหมอก และอ่านบทกวีของท่านที่สลักไว้บนแผ่นหิน'),
  'zunyi/chishui': ('น้ำตกชื่อสุ่ย', 'น้ำตกหลายสายทิ้งตัวลงจากหน้าผาหินตันเซี่ยสีแดงของชื่อสุ่ย สู่หุบเขาแห่งป่าไผ่และเฟิร์นต้นยักษ์ที่หลงเหลือมาตั้งแต่ยุคไดโนเสาร์ ชื่อเมืองแปลว่า \'น้ำสีแดง\' เพราะแม่น้ำจะไหลเป็นสีแดงเข้มหลังฝนตก และภูมิทัศน์แห่งนี้เป็นส่วนหนึ่งของมรดกโลกทางธรรมชาติ \'ตันเซี่ยแห่งจีน\' ของยูเนสโก'),
  'liupanshui/coolcity': ('เมืองแห่งความเย็นสบาย', 'ลิ่วผานสุ่ยตั้งอยู่บนที่ราบสูงที่ฤดูร้อนเย็นสบายชื่นใจ จึงภาคภูมิใจกับสมญานาม \'เมืองหลวงแห่งความเย็นของจีน\' ทุกฤดูร้อนผู้คนจากเสฉวนและฉงชิ่งที่ร้อนระอุจะพากันหลบร้อนมาที่นี่ และเมืองก็รู้จักเปลี่ยนอากาศอันสดชื่นนี้ให้กลายเป็นเทศกาลและการท่องเที่ยวบนที่สูง'),
  'liupanshui/coal': ('ทะเลถ่านหินแห่งภาคตะวันตกเฉียงใต้', 'ลิ่วผานสุ่ยก่อร่างขึ้นบนสายแร่ถ่านหินอันอุดมสมบูรณ์ และเป็นเตาพลังงานของจีนตะวันตกเฉียงใต้มาอย่างยาวนาน เมืองเติบโตขึ้นรอบเหมืองแร่และโรงเหล็กในยุคเร่งพัฒนาอุตสาหกรรมครั้งใหญ่ของศตวรรษที่ยี่สิบ และทุกวันนี้กำลังพยายามสร้างสมดุลระหว่างอัตลักษณ์ชาวเหมืองกับพลังงานสีเขียวและการท่องเที่ยว'),
  'liupanshui/grassland': ('ทุ่งหญ้าอูเหมิง', 'ทุ่งหญ้าอันกว้างไกลสุดสายตาบนที่ราบสูงอูเหมิงซึ่งอยู่ใกล้ชิดหมู่เมฆ ประดับประดาด้วยฝูงม้าและแถวกังหันลมเรียงรายที่เส้นขอบฟ้า ชาวบ้านเผ่าอี๋และเหมียวต้อนฝูงสัตว์ออกหากินตลอดฤดูร้อนอันเย็นสบาย และบางครั้งหมอกบนที่สูงก็โรยตัวลงมาในพริบตา เปลี่ยนภาพทั้งหมดให้กลายเป็นดินแดนในเทพนิยาย'),
  'liupanshui/kiwi': ('กีวีไส้แดง', 'กีวีเนื้อแดงเจริญงอกงามบนที่สูงอันเย็นชุ่มหมอกรอบลิ่วผานสุ่ย จนกลายเป็นขุมทรัพย์สีเขียวแสนหวานของเมือง ผลไม้ที่ใจกลางแดงเรื่อดั่งทับทิมชนิดนี้หวานกว่ากีวีทั่วไป และเมื่อถึงฤดูเก็บเกี่ยว หมู่บ้านบนภูเขาก็คึกคักไปด้วยลังกีวีกองพะเนิน'),
  'anshun/huangguoshu': ('น้ำตกหวงกั่วซู่', 'หวงกั่วซู่ น้ำตกที่ใหญ่ที่สุดของจีน ทิ้งตัวลงมาอย่างกึกก้องจากความสูง 77 เมตร และสาดสายรุ้งกระจายไปทั่วละอองน้ำ มีเส้นทางลอดผ่านถ้ำม่านน้ำด้านหลังน้ำตก ให้คุณมองออกมาจากหลังสายน้ำอันเชี่ยวกราก ฉากในละครโทรทัศน์คลาสสิกเรื่องไซอิ๋วก็ถ่ายทำกันที่นี่'),
  'anshun/dixi': ('งิ้วพื้นบ้านตี้ซี่', 'ตี้ซี่ การแสดงกลางลานหมู่บ้านด้วยหน้ากากนักรบไม้แกะสลักและเสียงฆ้องกระหึ่ม ได้รับการขนานนามว่าเป็น \'ฟอสซิลมีชีวิตแห่งงิ้วจีน\' ละครพิธีกรรมนี้เดินทางมาถึงกุ้ยโจวพร้อมทหารประจำการสมัยราชวงศ์หมิง และยังคงเล่าขานมหากาพย์สงครามโบราณด้วยความเร่าร้อนเช่นเดิมมาราวหกศตวรรษ'),
  'anshun/batik': ('ผ้าบาติก', 'หญิงชาวปู้อีและเหมียวใช้ขี้ผึ้งร้อนหลอมเหลววาดลายนก ดอกไม้ และลวดลายก้นหอยลงบนผืนผ้า แล้วจุ่มผ้าลงในน้ำย้อมสีครามเข้ม สีที่ซึมเข้าไปตามรอยแตกเล็ก ๆ ของขี้ผึ้งทำให้ผ้าแต่ละผืนมีเอกลักษณ์ไม่ซ้ำใคร ผ้าบาติกอันชุ่นจึงได้ชื่อว่าเป็นงานหัตถศิลป์ที่ไม่มีฝาแฝด'),
  'anshun/tunpu': ('หมู่บ้านถุนผู่', 'ในหมู่บ้านค่ายทหารหินที่กองทัพราชวงศ์หมิงก่อตั้งขึ้นเมื่อราว 600 ปีก่อน ชาวถุนผู่ยังคงสวมชุดแบบหนานจิงโบราณของบรรพบุรุษและพูดสำเนียงเก่าแก่มาจนถึงทุกวันนี้ การเดินเล่นตามตรอกกำแพงหินให้ความรู้สึกราวกับก้าวเข้าไปในเมืองยุคหมิงที่หยุดนิ่งอยู่กับกาลเวลา'),
  'bijie/azalea': ('ทุ่งดอกอาซาเลียร้อยลี้', 'ทุกฤดูใบไม้ผลิ สันเขาของปี้เจี๋ยจะลุกโชนด้วยดอกกุหลาบพันปีสีแดง ชมพู และม่วง โดย \'แนวกุหลาบพันปีร้อยหลี่\' ได้ชื่อว่าเป็นป่ากุหลาบพันปีธรรมชาติที่ใหญ่ที่สุดในโลก ในเทศกาลเดือนเมษายน ชาวบ้านเผ่าอี๋และเหมียวจะร้องเพลงต้อนรับฤดูใบไม้ผลิท่ามกลางทะเลดอกไม้'),
  'bijie/zhijin': ('ถ้ำจือจิน', 'ถ้ำจือจิน ที่ซึ่งหินงอกยักษ์ตั้งตระหง่านราวป่าหิน ได้รับฉายาว่า \'พระราชวังใต้พิภพ\' และนับเป็นหนึ่งในถ้ำที่ตระการตาที่สุดของจีน ในห้องโถงขนาดใหญ่เท่ามหาวิหาร หินปูนรูปทรงประณีตอย่าง \'ต้นไม้ฝนสีเงิน\' ทำให้ผู้มาเยือนตกอยู่ในภวังค์'),
  'bijie/caohai': ('นกกระเรียนทะเลสาบเฉ่าไห่', 'เฉ่าไห่ ทะเลสาบน้ำตื้นเต็มไปด้วยพงหญ้าบนที่ราบสูงเวยหนิง กลายเป็นที่พักพิงฤดูหนาวของนกกระเรียนคอดำอันหายากทุกปี เมื่อหมอกยามเช้าจางลง เสียงร้องของนกนับพันจะดังก้องทั่วผืนน้ำ ขณะคนเรือค่อย ๆ ถ่อพาผู้มาเยือนลัดเลาะไปตามดงกกอย่างเงียบเชียบ'),
  'bijie/potato': ('มันฝรั่งเมืองปี้เจี๋ย', 'มันฝรั่งที่ปลูกบนที่สูงอากาศเย็นแดดดี ทำให้ปี้เจี๋ยเป็นหนึ่งในยุ้งฉางมันฝรั่งใหญ่ของจีน และมันฝรั่งเวยหนิงก็มีชื่อเสียงไปทั่วประเทศ ไม่ว่าจะเผาบนถ่าน ทอดกรอบ หรือคลุกซอสพริกตามแผงริมทาง มันฝรั่งแสนธรรมดานี้คือราชาแห่งครัวบนที่ราบสูง'),
  'qujing/rapeseed': ('ทุ่งดอกเรปซีดหลัวผิง', 'ปลายฤดูหนาวของทุกปี ที่ราบหลัวผิงจะถูกปกคลุมด้วยดอกคาโนลาสีทองอร่าม โดยมีเขาหินปูนโผล่ขึ้นกลางท้องทุ่งราวเกาะน้อยใหญ่ในทะเลสีเหลือง ทะเลดอกไม้นี้ดึงดูดคนเลี้ยงผึ้ง ช่างภาพ และคนรักน้ำผึ้งจากทั่วสารทิศ แม้แต่อากาศก็ยังหอมหวาน'),
  'qujing/ham': ('แฮมซวนเวย์', 'แฮมเซวียนเวยที่หมักเกลือและตากลมภูเขามาหลายศตวรรษ คือความภาคภูมิใจของสำรับอาหารยูนนาน เนื้อสีแดงกุหลาบและกลิ่นหอมลึกล้ำทำให้มันติดอันดับแฮมที่มีชื่อเสียงที่สุดของจีน และถูกนำไปปรุงรสสารพัดเมนู ตั้งแต่น้ำซุปไปจนถึงขนมไหว้พระจันทร์ในเทศกาล'),
  'qujing/jiulong': ('น้ำตกจิ่วหลง', 'ใกล้เมืองหลัวผิง แม่น้ำ \'เก้ามังกร\' หรือจิ่วหลง ไหลลดหลั่นลงมาเป็นขั้นบันไดน้ำตก แต่ละชั้นมีความกว้างและบุคลิกเฉพาะตัว ในฤดูน้ำหลาก ภาพน้ำตกที่มีทุ่งดอกคาโนลาสีทองเป็นกรอบ นับเป็นหนึ่งในสายน้ำตกที่งดงามที่สุดของจีน'),
  'qujing/sandforest': ('ป่าทรายหลากสี', 'ในป่าทรายหลากสีแห่งลู่เหลียง แท่งทรายที่ถูกลมและฝนกัดเซาะแกะสลัก เปล่งประกายไล่เฉดตั้งแต่สีทอง สีสนิม ไปจนถึงสีขาวและสีม่วง สีสันเหล่านี้แปรเปลี่ยนไปตามแสง ทำให้สวนประติมากรรมธรรมชาติแห่งนี้เป็นฉากโปรดของกองถ่ายภาพยนตร์และช่างภาพ'),
  'yuxi/fuxian': ('ทะเลสาบฝูเซียน', 'ฝูเซียน หนึ่งในทะเลสาบที่ลึกที่สุดของจีน ฝังตัวอยู่ในที่ราบสูงยูนนานราวกระจกเงาแห่งขุนเขาที่น้ำใสดั่งแก้วผลึก ตำนานเล่าขานถึงเมืองโบราณที่จมอยู่ใต้ผืนน้ำ และชาวประมงในหมู่บ้านริมฝั่งก็ยังคงทอดแหจับปลาคั่งลั่งตัวจิ๋วอันเลื่องชื่อของทะเลสาบ'),
  'yuxi/nieer': ('เนี่ยเอ๋อร์', 'เนี่ย เอ่อร์ ผู้ประพันธ์เพลงชาติจีน มาจากครอบครัวชาวอวี้ซี และเมืองก็ภูมิใจยกย่องเขาเป็นลูกหลานของตน ด้วยสวนดนตรี อนุสรณ์สถาน และเทศกาลในนามของเขา อวี้ซีส่งต่อท่วงทำนองของนักประพันธ์ผู้จากไปตั้งแต่วัยเยาว์นี้จากรุ่นสู่รุ่น'),
  'yuxi/chengjiang': ('แหล่งฟอสซิลเฉิงเจียง', 'แหล่งฟอสซิลยุคแคมเบรียนอายุ 530 ล้านปีแห่งเฉิงเจียง เป็นมรดกโลกของยูเนสโกที่เผยให้เห็นรุ่งอรุณของสิ่งมีชีวิตในอาณาจักรสัตว์อย่างละเอียดน่าทึ่ง แม้แต่เนื้อเยื่ออ่อนนุ่มก็ยังประทับรอยอยู่ในหิน ทำให้สิ่งมีชีวิตเหล่านี้เป็นประจักษ์พยานที่ทรงคุณค่าที่สุดของ \'การระเบิดครั้งใหญ่ยุคแคมเบรียน\''),
  'yuxi/kiln': ('เตาเผาอวี้ซี', 'เตาเผาโบราณแห่งอวี้ซีซึ่งมีอายุย้อนไปถึงสมัยราชวงศ์หยวน ได้ชื่อว่าเป็นแหล่งกำเนิดเครื่องเคลือบลายครามของยูนนาน ช่างปั้นท้องถิ่นซึ่งอยู่ห่างไกลจากจิ่งเต๋อเจิ้นอันโด่งดัง ได้พัฒนาสไตล์เฉพาะตัวขึ้นมา และฝากลายเซ็นไว้ในประเพณีเครื่องปั้นดินเผาของภาคตะวันตกเฉียงใต้ด้วยภาชนะลวดลายสีโคบอลต์'),
  'dali/threepagodas': ('เจดีย์สามองค์', 'เจดีย์สามองค์อันงามสง่าที่ตั้งตระหง่านเชิงเทือกเขาชางซานมานับพันปี คือสัญลักษณ์ของอาณาจักรโบราณหนานเจ้าและต้าหลี่ เจดีย์เหล่านี้ยืนหยัดผ่านแผ่นดินไหวมาหลายศตวรรษ และประกอบกันเป็นภาพโปสการ์ดอันเป็นที่รักที่สุดของต้าหลี่ โดยมียอดเขาหิมะเป็นฉากหลังและสระน้ำสะท้อนเงาอยู่เบื้องหน้า'),
  'dali/erhai': ('ทะเลสาบเอ๋อไห่', 'เอ๋อร์ไห่ ทะเลสาบบนที่สูงซึ่งได้ชื่อจากรูปทรงคล้ายใบหู ทอดตัวอยู่ระหว่างเทือกเขาชางซานกับที่ราบต้าหลี่ หมู่บ้านชาวไป๋กำแพงขาวประดับประดาอยู่ตามชายฝั่ง การปั่นจักรยานเลียบทะเลสาบและชมเรือประมงยามอาทิตย์ขึ้น นับเป็นความสุขคลาสสิกของต้าหลี่'),
  'dali/cangshan': ('เทือกเขาชางซาน', 'ชางซานที่มียอดเขาสิบเก้ายอดและลำธารสิบแปดสายไหลผ่านระหว่างกลาง ตั้งตระหง่านราวม่านสีเขียวอยู่เบื้องหลังต้าหลี่ หินอ่อนในภาษาจีนเรียกตรงตัวว่า \'หินต้าหลี่\' ก็เพราะเหตุนี้ หินลวดลายงดงามที่ขุดจากสายแร่ของภูเขาลูกนี้ประดับพระราชวังและวัดวาอารามมานานหลายศตวรรษ'),
  'dali/wind': ('ลม ดอกไม้ หิมะ จันทร์', 'สายลมแห่งเซี่ยกวาน ดอกไม้แห่งซ่างกวาน หิมะแห่งชางซาน และดวงจันทร์เหนือเอ๋อร์ไห่ — ความงามทั้งสี่ของต้าหลี่ถูกท่องขานราวบทกวีบทเดียว แม้แต่เครื่องประดับศีรษะของหญิงชาวไป๋ก็ถักทอสัญลักษณ์ทั้งสี่นี้ไว้ นับเป็นสูตรอันงดงามที่เมืองใช้สรุปธรรมชาติของตนเอง'),
  'lijiang/oldtown': ('เมืองเก่าลี่เจียง', 'เมืองเก่าลี่เจียงที่ถักทอขึ้นจากคูคลอง ตรอกหินกรวด และบ้านไม้หลังคากระเบื้อง คือหัวใจที่ยังมีลมหายใจของวัฒนธรรมน่าซี เมืองมรดกโลกยูเนสโกที่ขึ้นชื่อว่าสร้างโดยไร้กำแพงเมืองแห่งนี้ เคยเป็นที่พักของกองคาราวานบนเส้นทางค้าชาม้า และเสียงน้ำไหลก็ยังคงคลอตามคุณไปทุกตรอกซอย'),
  'lijiang/snowmountain': ('ภูเขาหิมะมังกรหยก', 'ภูเขาหิมะมังกรหยก ด้วยยอดธารน้ำแข็งสูง 5,596 เมตร เปล่งประกายเหนือลี่เจียงราวมังกรหลับใหล ชาวน่าซีถือว่าภูเขาลูกนี้ศักดิ์สิทธิ์ กระเช้าลอยฟ้าพานักท่องเที่ยวขึ้นสู่อุทยานธารน้ำแข็ง ขณะที่หุบเขาพระจันทร์สีน้ำเงินที่ตีนเขาก็สะกดทุกสายตาด้วยแอ่งน้ำสีเทอร์ควอยซ์'),
  'lijiang/dongba': ('อักษรตงปา', 'ตงปา อักษรภาพของนักบวชชาวน่าซี ได้ชื่อว่าเป็นระบบอักษรภาพสุดท้ายของโลกที่ยังใช้งานอยู่จริง ต้นฉบับลายมือนับพันเล่มบันทึกพิธีกรรมบูชาภูตธรรมชาติและจักรวาลทัศน์ของชาวน่าซี คลังเอกสารอันหาที่เปรียบมิได้นี้ได้รับการขึ้นทะเบียนในโครงการความทรงจำแห่งโลกของยูเนสโก'),
  'lijiang/tigerleaping': ('ช่องแคบเสือกระโจน', 'ตำนานเล่าว่าเสือตัวหนึ่งกระโจนข้ามจุดที่แคบที่สุดของแม่น้ำจินซาได้ในการกระโดดเพียงครั้งเดียว ช่องเขาจึงได้ชื่อว่า \'ช่องแคบเสือกระโจน\' โตรกลึกที่ทิ้งดิ่งลงระหว่างภูเขาหิมะมังกรหยกกับภูเขาฮาบา นับเป็นหนึ่งในหุบผาที่ลึกที่สุดในโลก และเส้นทางเดินเลียบไหล่เขาสูงก็เป็นความฝันของนักเดินป่า'),
  'lincang/dianhong': ('ชาดำเตียนหง', 'เตียนหง ชาดำยอดทองแห่งเฟิ่งชิ่ง เป็นชารุ่นใหม่ที่เพิ่งถือกำเนิดในศตวรรษที่ผ่านมา แต่ก็นำพาชื่อเสียงของยูนนานสู่สายตาชาวโลกอย่างรวดเร็ว น้ำชากลิ่นน้ำผึ้งแกมคาราเมลทำให้มันติดอันดับชาดำที่ทรงเกียรติที่สุดของจีน โดยได้ความลุ่มลึกพิเศษจากใบของต้นชาโบราณ'),
  'lincang/wadrum': ('กลองไม้ชาวว้า', 'ชาวว้าถือว่ากลองไม้เป็นของศักดิ์สิทธิ์ ว่ากันว่าเสียงกลองคือสะพานเชื่อมระหว่างสวรรค์กับมนุษย์ ในหมู่บ้านบนดอยแห่งชางหยวน ระบำกลองสะบัดผม ที่หญิงสาวสะบัดผมยาวไปตามจังหวะ จะกระหึ่มก้องไปทั้งหุบเขาในวันเก็บเกี่ยวและงานเทศกาล'),
  'lincang/teatrees': ('ต้นชาโบราณ', 'ขุนเขาชุ่มหมอกของหลินชางเป็นที่พำนักของต้นชาป่าและต้นชาโบราณที่อายุนับกันเป็นศตวรรษหรือกระทั่งนับพันปี เก็บงำผืนป่าอันเป็นแหล่งกำเนิดของชาเอาไว้ ในฤดูเก็บเกี่ยวใบชาฤดูใบไม้ผลิ ชาวบ้านจะพาดบันไดปีนขึ้นต้นชายักษ์ และใบชาเก่าแก่เหล่านี้ก็กลายเป็นชาผู่เอ๋อร์ที่เป็นที่ต้องการที่สุดในโลก'),
  'lincang/lancang': ('แม่น้ำล้านช้าง', 'แม่น้ำหลานชาง ต้นสายของแม่น้ำโขง ไหลลงมาจากทิเบตและกัดเซาะผ่านหุบเขาลึกของหลินชาง มุ่งลงใต้สู่เอเชียตะวันออกเฉียงใต้ เขื่อนที่เรียงรายตามลำน้ำให้แสงสว่างแก่ภูมิภาค ขณะที่ไร่ชาและสวนผลไม้เขตร้อนไต่ระดับขึ้นไปตามลาดเขาเหนือสองฝั่งน้ำ'),
  'puer/tea': ('ชาผูเอ่อร์', 'ชาผู่เอ๋อร์อัดแผ่นซึ่งตั้งชื่อตามเมืองภูเขาแห่งนี้ คือขุมทรัพย์มีชีวิตที่ยิ่งเก่าบ่มยิ่งกลมกล่อมและทวีมูลค่า ใบชาที่อัดเป็นก้อนคล้ายขนมเค้กเก็บได้นานหลายสิบปี ในอดีตกองคาราวานล่อเคยขนแผ่นชาเหล่านี้ข้ามขุนเขาไปยังทิเบตและราชสำนัก'),
  'puer/coffee': ('เมืองหลวงแห่งกาแฟของจีน', 'กาแฟส่วนใหญ่ของจีนปลูกในไร่อาราบิก้าบนลาดเขาชุ่มหมอกของผู่เอ๋อร์ เมืองหลวงแห่งชาจึงหอมกรุ่นกลิ่นลาเต้อย่างน่าประหลาดใจ ไร่กาแฟเปิดทัวร์ชิมท่ามกลางผลกาแฟสุกแดง และเหล่าบาริสต้ารุ่นใหม่ก็มุ่งมั่นนำเมล็ดกาแฟท้องถิ่นก้าวขึ้นสู่เวทีโลก'),
  'puer/teahorse': ('เส้นทางสายชาและม้า', 'เส้นทางค้าชาม้าโบราณ ที่กองคาราวานล่อขนแผ่นชาอัดไปยังทิเบตและนำม้ากลับมายังจีน เริ่มต้นจากผู่เอ๋อร์แล้วไต่ขึ้นสู่ช่องเขาที่ห่มคลุมด้วยเมฆหมอก ร่องรอยของทางคาราวานปูหินและเมืองพักแรมเก่าแก่ ยังคงรักษาความทรงจำของการค้าอันทรหดนั้นให้มีชีวิตอยู่จนทุกวันนี้'),
  'puer/peafowl': ('นกยูงเขียว', 'ป่าเขตร้อนรอบผู่เอ๋อร์เป็นหนึ่งในที่หลบภัยแห่งสุดท้ายของนกยูงเขียว หนึ่งในนกที่หายากที่สุดของจีน เขตอนุรักษ์ที่นี่ไม่เพียงปกป้องนกอันงามสง่านี้ แต่ยังเป็นบ้านของช้างป่าและชะนีด้วย เมืองแห่งนี้จึงภาคภูมิใจในผืนป่าไม่แพ้ใบชาของตน'),
  'baoshan/volcano': ('ภูเขาไฟเถิงชง', 'กรวยภูเขาไฟที่สงบนิ่งแล้ว 97 ลูกเรียงรายอยู่บนที่ราบเถิงชง ทำให้ภูมิทัศน์ดูราวกับพื้นผิวดวงจันทร์ นักท่องเที่ยวปีนขึ้นไปยังขอบปล่อง หรือลอยละล่องเหนือกรวยภูเขาไฟด้วยบอลลูนลมร้อน แม้แต่ผนังบ้านเรือนในเมืองก็ยังก่อขึ้นด้วยหินลาวาสีดำ'),
  'baoshan/rehai': ('หุบเขาเร่อไห่', 'ในหุบเขา \'ทะเลร้อน\' ของเถิงชง น้ำพุร้อนพวยพุ่งไอน้ำและแอ่งน้ำเดือดปุด ๆ ที่โด่งดังที่สุดคือ \'หม้อเดือดยักษ์\' ขนาดมหึมา นักท่องเที่ยวชิมไข่ที่ต้มสุกด้วยไอน้ำพุ แล้วแช่ตัวในบ่อน้ำแร่ เสาะหาความอบอุ่นบำบัดจากผืนดินภูเขาไฟแห่งนี้'),
  'baoshan/heshun': ('เมืองโบราณเหอซุ่น', 'เหอชุ่น เมืองหินของพ่อค้าที่ออกไปค้าขายถึงพม่าและไกลกว่านั้นมาหลายศตวรรษ ได้เห็นลูกหลานส่งทรัพย์สินกลับบ้านในรูปคฤหาสน์งามสง่าและโรงเรียน เมืองซึ่งเป็นที่ตั้งของห้องสมุดหมู่บ้านที่เก่าแก่ที่สุดแห่งหนึ่งของจีนแห่งนี้ แผ่ความสงบร่มเย็นด้วยสระบัวและสะพานหิน'),
  'baoshan/gaoligong': ('เทือกเขาเกาลี่กง', 'เทือกเขาเกาลี่กงที่ทอดยาวตามแนวชายแดนเมียนมา คือขุมทรัพย์แห่งชีวิต ด้วยหุบเขาผีเสื้อ ป่าอบอุ่น และพืชพรรณนับพันชนิด เทือกเขาที่ไต่ระดับจากหุบเขาเขตร้อนสู่สันเขาหิมะแห่งนี้ เป็นที่พักพิงของสัตว์หายากนับไม่ถ้วน ตั้งแต่ชะนีไปจนถึงนกที่พบเห็นได้ยากยิ่ง'),
  'deyang/sanxingdui': ('แหล่งโบราณคดีซานซิงตุย', 'หน้ากากสำริดยักษ์ดวงตาโปนที่ขุดพบจากหลุมบูชายัญซึ่งค้นพบในปี 1986 ได้นำอารยธรรมสู่อันลึกลับอายุ 3,000 ปีออกมาสู่แสงสว่าง ด้วยคทาทองคำและต้นไม้สำริดศักดิ์สิทธิ์ ซานซิงตุยนับเป็นหนึ่งในความประหลาดใจครั้งยิ่งใหญ่ที่สุดของวงการโบราณคดีจีน'),
  'deyang/jiannanchun': ('เหล้าเจี้ยนหนานชุน', 'เจี้ยนหนานชุน สุราที่กลั่นในเหมียนจู๋ คือไป๋จิ่วเก่าแก่ที่มีชื่อปรากฏในบรรดาสุราที่ถวายราชสำนักสมัยราชวงศ์ถัง ด้วยบ่อหมักโบราณที่ใช้งานต่อเนื่องมิขาดสายและกลิ่นหอมละมุนดั่งดอกไม้ มันจึงยืนอยู่ในหมู่ชื่อที่ทรงเกียรติที่สุดของประเพณีสุราแห่งเสฉวน'),
  'deyang/nianhua': ('ภาพพิมพ์ปีใหม่เหมียนจู๋', 'ภาพพิมพ์แกะไม้ปีใหม่ระบายสีด้วยมือของเหมียนจู๋ แขวนโชคลาภไว้ที่บานประตู ทั้งเทพผู้พิทักษ์ เด็กน้อยจ้ำม่ำ และสัญลักษณ์แห่งความอุดมสมบูรณ์ ศิลปะนี้นับเป็นหนึ่งในประเพณีภาพเหนียนฮว่าอันยิ่งใหญ่ของจีน โดยฝีแปรงปิดท้ายอันมีชีวิตชีวาของช่างฝีมือทำให้ภาพพิมพ์ทุกแผ่นกลายเป็นงานศิลปะที่ไม่ซ้ำกัน'),
  'deyang/turbine': ('เมืองหลวงแห่งอุตสาหกรรมหนัก', 'กังหันยักษ์ เครื่องกำเนิดไฟฟ้า และอุปกรณ์โรงไฟฟ้าส่วนใหญ่ของประเทศ ถูกหลอมตีขึ้นในโรงงานมหึมาของเต๋อหยาง เมืองซึ่งได้ชื่อว่าเป็นเมืองหลวงแห่งเครื่องจักรกลหนักแห่งนี้ คือหนึ่งในกล้ามเนื้อเหล็กกล้าที่ค้ำจุนโครงสร้างพื้นฐานด้านพลังงานของจีนอย่างเงียบ ๆ'),
  'mianyang/libai': ('บ้านเกิดของหลี่ไป๋', 'หลี่ไป๋ กวีอมตะ ใช้ชีวิตวัยเยาว์ท่ามกลางขุนเขาแห่งเจียงโหยว ที่ซึ่งบทกวีอุทิศแด่แสงจันทร์และสุราของเขาได้หยั่งรากเป็นครั้งแรก อนุสรณ์สถานและพิพิธภัณฑ์ในนามของเขารวบรวมผู้รักบทกวีมาพบกันทุกปี บนรอยเท้าของปรมาจารย์ในตำนานแห่งยุคถังผู้นี้'),
  'mianyang/sciencecity': ('เมืองแห่งวิทยาศาสตร์', 'เหมียนหยาง เมืองเดียวที่ครองสมญาอย่างเป็นทางการว่า \'เมืองวิทยาศาสตร์และเทคโนโลยี\' ของจีน สร้างอนาคตด้วยสถาบันวิจัยและโรงงานอิเล็กทรอนิกส์ เมืองบ้านเกิดของโทรทัศน์ยี่ห้อฉางหงแห่งนี้ คือใบหน้าในชุดกาวน์ห้องแล็บที่ฉลาดหลักแหลมที่สุดของเสฉวน'),
  'mianyang/qiang': ('หอคอยหินชาวเชียง', 'ในหมู่บ้านบนภูเขาของเป่ยชวน หอสังเกตการณ์หินของชาวเชียงตั้งตระหง่านมาหลายศตวรรษ หอที่ก่อขึ้นอย่างชำนิชำนาญเหล่านี้เป็นทั้งป้อมป้องกันและเครื่องหมายแห่งเกียรติยศ หมู่บ้านชาวเชียงที่สืบทอดความเชื่อเรื่องหินขาวและงานปักผ้าขนสัตว์ ยังคงหล่อเลี้ยงวัฒนธรรมภูเขาอันเก่าแก่ให้มีชีวิต'),
  'mianyang/mifen': ('เส้นหมี่เหมียนหยาง', 'เส้นหมี่ข้าวเส้นเล็กที่ลอยควันฉุยในน้ำซุปไก่ เนื้อ หรือเครื่องใน ปลุกเหมียนหยางให้ตื่นในยามเช้าตรู่ เส้นบางเบานุ่มละมุนสุกได้ในไม่กี่วินาที และภาพผู้คนก้มหน้าซดหมี่ร้อน ๆ อยู่หน้าเคาน์เตอร์ ก็คือพิธีกรรมยามเช้าที่ซื่อสัตย์ที่สุดของเมืองนี้'),
  'nanchong/langzhong': ('เมืองโบราณหลางจง', 'หลางจง หนึ่งในเมืองโบราณที่วางผังตามหลักฮวงจุ้ยซึ่งได้รับการอนุรักษ์ไว้ดีที่สุด หลับใหลอยู่ในอ้อมกอดของโค้งแม่น้ำเจียหลิง ในฐานะบ้านเกิดของลั่วเซี่ยหง นักดาราศาสตร์สมัยราชวงศ์ฮั่น เมืองนี้ได้รับเกียรติว่าเป็นแหล่งกำเนิดประเพณีตรุษจีน และตรอกซอยหอมกลิ่นน้ำส้มสายชูก็ยังคงรักษาโครงสร้างสมัยหมิง-ชิงไว้ครบถ้วน'),
  'nanchong/silk': ('เมืองหลวงแห่งผ้าไหม', 'ด้วยประเพณีปลูกหม่อนเลี้ยงไหมและทอผ้ากว่าสองพันปี หนานชงครองสมญานามเมืองหลวงแห่งผ้าไหมของจีนตะวันตก เมืองที่เคยป้อนผืนผ้าให้เส้นทางสายไหมแห่งนี้ ทุกวันนี้ยังคงมีชีวิตอยู่ด้วยโรงสาวไหมและพิพิธภัณฑ์ผ้าไหม โดยผ้าเนื้อเงางามของเมืองยังคงเดินทางสู่ตลาดทั่วโลก'),
  'nanchong/zhangfei': ('เนื้อวัวจางเฟย', 'จางเฟย (เตียวหุย) วีรบุรุษแห่งยุคสามก๊ก เคยประจำการอยู่ที่หลางจงเป็นเวลานาน และศาลเจ้าของเขาก็ยังคงตั้งอยู่ในเมืองจนทุกวันนี้ เนื้อวัวหมักเครื่องเทศตากแห้งที่ตั้งชื่อตามเขา ซึ่งภายนอกดำสนิทแต่ภายในแดงดั่งกุหลาบ คือการหยอกล้ออย่างมีเสน่ห์ถึงภาพลักษณ์ใบหน้าดำอันลือชื่อของวีรบุรุษผู้นี้'),
  'nanchong/zhude': ('บ้านเกิดของจูเต๋อ', 'จอมพลจูเต๋อ หนึ่งในผู้บัญชาการผู้ร่วมก่อตั้งกองทัพปลดปล่อยประชาชน เกิดในบ้านชาวนายากจนที่อี๋หลง บ้านไร่อันเรียบง่ายและหอรำลึกของเขาเป็นจุดแสวงบุญแห่งหนึ่งของประวัติศาสตร์จีนสมัยใหม่ ที่ซึ่งผู้มาเยือนได้สัมผัสพลังของจุดเริ่มต้นอันต่ำต้อย'),
  'yibin/wuliangye': ('เหล้าอู่เหลียงเย่', 'อู่เหลียงเย่ กลั่นจากข้าวฟ่าง ข้าวเจ้า ข้าวเหนียว ข้าวสาลี และข้าวโพด จึงได้ชื่อจาก \'ธัญพืชทั้งห้า\' นี้ และนับเป็นหนึ่งในแบรนด์ไป๋จิ่วที่ทรงคุณค่าที่สุดของจีน ภูมิอากาศชื้นของอี๋ปินและบ่อหมักอายุนับร้อยปี มอบกลิ่นหอมซับซ้อนหลายชั้นอันเป็นเอกลักษณ์ให้แก่สุราชนิดนี้'),
  'yibin/firstcity': ('เมืองแรกแห่งแม่น้ำแยงซี', 'ณ จุดที่แม่น้ำหมินและแม่น้ำจินซามาบรรจบกัน สายน้ำจึงเริ่มใช้ชื่อว่าแยงซี ด้วยเหตุนี้อี๋ปินจึงถูกขนานนามว่า \'เมืองแรกแห่งแม่น้ำแยงซี\' แหลมที่สายน้ำสองสีมาบรรจบกัน ปัจจุบันกลายเป็นสวนริมน้ำ และเป็นภูมิทัศน์สัญลักษณ์ที่เมืองภาคภูมิใจที่สุด'),
  'yibin/bamboosea': ('ทะเลไผ่ซู่หนาน', 'ทะเลไผ่สู่หนานที่ห่มคลุมเนินเขากว่าร้อยลูก พลิ้วไหวตามสายลมราวมหาสมุทรสีเขียวอันไร้ขอบเขต เส้นทางเดินป่าอันร่มเย็น น้ำตกที่ซ่อนเร้น และอาหารที่รังสรรค์จากหน่อไม้ โอบกอดผู้มาเยือนไว้ ส่วนกองถ่ายภาพยนตร์ก็หวนกลับมาใช้ผืนป่าเขียวขจีนี้เป็นฉากครั้งแล้วครั้งเล่า'),
  'yibin/ranmian': ('หมี่คลุกน้ำมัน', '\'หรานเมี่ยน\' บะหมี่ที่นวดแทบไม่ใช้น้ำแล้วคลุกเคล้าด้วยน้ำมันหอม ได้ชื่อว่า \'บะหมี่ลุกไหม้\' เพราะแห้งพอที่น้ำมันจะติดไฟได้ ด้วยพริก ฮวาเจียวเสฉวน และถั่วลิสงคั่ว มันคือดาวเด่นที่ปลุกทุกประสาทสัมผัสของอาหารเช้าแบบอี๋ปิน'),
  'luzhou/laojiao': ('โรงบ่มเหล้าหลูโจวเหล่าเจี้ยว', 'บ่อหมักดินโคลนที่ใช้งานต่อเนื่องมาตั้งแต่ปี 1573 คือหัวใจของประเพณีไป๋จิ่ว \'กลิ่นหอมเข้มข้น\' แห่งหลูโจว วัฒนธรรมจุลินทรีย์ที่มีชีวิตในบ่อถูกส่งต่อจากรุ่นสู่รุ่น และเหล่าปรมาจารย์นักกลั่นเชื่อว่าบ่อที่เก่าแก่ที่สุดจะมอบกลิ่นหอมลึกล้ำที่สุดให้แก่สุรา'),
  'luzhou/port': ('ท่าเรือแม่น้ำแยงซี', 'หลูโจวก่อตั้งขึ้น ณ จุดที่แม่น้ำถัวไหลมาบรรจบกับแม่น้ำแยงซี จึงเป็นประตูน้ำของเสฉวนที่เปิดออกสู่ทะเล ท่าเรือของเมืองขนถ่ายเกลือ สุรา และธัญพืชมาหลายศตวรรษ และทุกวันนี้ท่าเรือคอนเทนเนอร์ก็ยังคงเชื่อมโยงมณฑลตอนในเข้ากับแยงซีตอนล่างและโลกกว้าง'),
  'luzhou/longan': ('สวนลำไย', 'ลำไย ผลไม้ลูกเล็กหวานฉ่ำดั่งน้ำผึ้งที่เรียกกันว่า \'ดวงตามังกร\' เติบโตบนลาดเขาอบอุ่นตามหุบเขาแม่น้ำของหลูโจว เมืองนี้เป็นที่ตั้งของสวนลำไยขนาดใหญ่ที่อยู่เหนือสุดของจีนบางแห่ง และผลไม้ที่สุกช้านี้ก็กองพูนแผงตลาดในฤดูใบไม้ร่วง'),
  'luzhou/umbrella': ('ร่มกระดาษน้ำมัน', 'ร่มกระดาษเคลือบน้ำมันทำมือของช่างฝีมือแห่งเฟินสุ่ย ด้วยโครงไม้ไผ่และลวดลายวาดมือ คืองานหัตถศิลป์อันงามสง่าอายุสี่ศตวรรษ ร่มแต่ละคันผ่านขั้นตอนนับสิบ และเมื่อกางออกก็มิใช่เพียงกันฝนแต่ยังกางรับโชคลาภ รูปทรงกลมของมันคือสัญลักษณ์แห่งความสมบูรณ์และความสุข'),
  'leshan/giantbuddha': ('พระใหญ่เล่อซาน', 'พระพุทธรูปประทับนั่งสูง 71 เมตรที่สลักเข้าไปในหน้าผา เฝ้ามองจุดบรรจบอันเชี่ยวกรากของแม่น้ำสามสายอย่างสงบนิ่งมาสิบสองศตวรรษ โครงการมหึมานี้ริเริ่มโดยพระไห่ทงแห่งยุคถังเพื่อคุ้มครองเรือที่แล่นผ่าน ปัจจุบันเป็นมรดกโลกยูเนสโก เพียงบนนิ้วพระบาทก็มีคนยืนได้นับสิบคน'),
  'leshan/emei': ('ภูเขาเอ๋อเหมย', 'ภูเขาเอ๋อเหมย (ง้อไบ๊) หนึ่งในสี่ภูเขาศักดิ์สิทธิ์แห่งพุทธศาสนา เรียกหาผู้แสวงบุญและนักเดินเขาด้วยยอดเขาทองคำที่เปล่งประกายเหนือทะเลเมฆ เส้นทางเดินไต่ผ่านอารามโบราณ และในวันที่โชคดี บนยอดเขาจะปรากฏรุ้งวงแหวนที่เรียกกันว่า \'แสงแห่งพระพุทธเจ้า\''),
  'leshan/monkeys': ('ลิงแสมแห่งภูเขาเอ๋อเหมย', 'ลิงแม็กแคกจอมซนที่อาศัยตามเส้นทางเดินของเขาเอ๋อเหมย ขึ้นชื่อเรื่องความกล้าค้นกระเป๋าผู้แสวงบุญอย่างไม่เกรงใจ ชาวบ้านเรียกพวกมันว่าเจ้าบ้านแห่งขุนเขา ลิงที่นั่งเอกเขนกบนราวกันตกและโพสท่าถ่ายรูป ทิ้งความทรงจำที่ขบขันที่สุด — และแสบที่สุด — ของการไต่เขาไว้ให้นักเดินทาง'),
  'leshan/qiaojiao': ('ซุปเนื้อเฉียวเจี่ยว', '\'เฉียวเจี่ยว\' ซุปเนื้อวัวที่เคี่ยวนานหลายชั่วโมงกับสมุนไพรและเครื่องเทศ ได้ชื่อจากลูกค้าสมัยก่อนที่ยกเท้าพาดม้านั่งสูงหน้าร้านขณะซดน้ำซุป ชามร้อนควันฉุยที่เป็นตำนานข้างถนนของเล่อซานมาราวหนึ่งศตวรรษนี้ เปลี่ยนแม้แต่เครื่องในธรรมดาให้กลายเป็นงานเลี้ยง'),
  'zigong/saltwell': ('บ่อเกลือลึกหนึ่งกิโลเมตร', 'จื้อก้งดำรงชีพด้วยบ่อเกลือมาราวสองพันปี และอัจฉริยภาพการเจาะบ่อด้วยสายเคเบิลไม้ไผ่ก็ถึงจุดสูงสุดที่บ่อเซินไห่ บ่อแรกในโลกที่เจาะลึกเกินหนึ่งพันเมตร หอเจาะไม้และพิพิธภัณฑ์เกลือยังคงเล่าเรื่องราวอัจฉริยะของ \'เมืองหลวงแห่งเกลือ\' นี้ต่อไป'),
  'zigong/lantern': ('เทศกาลโคมไฟจื้อกง', 'ทุกเทศกาลปีใหม่ จื้อก้งจะกลายเป็นแดนมหัศจรรย์ของสวนโคมไฟยักษ์เรืองแสง มังกร พระราชวัง และตัวละครจากนิทานผุดขึ้นจากผ้าไหมและโครงเหล็ก ทุกวันนี้ช่างโคมไฟของเมืองยังออกไปเนรมิตเทศกาลแห่งแสงเหล่านี้ในเมืองต่าง ๆ ทั่วโลกอีกด้วย'),
  'zigong/dinosaur': ('พิพิธภัณฑ์ไดโนเสาร์', 'ฟอสซิลนับพันชิ้นที่ผุดขึ้นจากชั้นหินยุคจูแรสซิกที่ต้าซานผู่ ทำให้จื้อก้งเป็นเมืองหลวงไดโนเสาร์ของจีน พิพิธภัณฑ์ที่สร้างคร่อมหลุมขุดค้นจัดแสดงชั้นกระดูกในสภาพเดิมที่ค้นพบ และโครงกระดูกซอโรพอดสูงตระหง่านก็พาผู้มาเยือนดำดิ่งสู่ยุคจูแรสซิก'),
  'zigong/rabbit': ('เนื้อกระต่ายเย็น', '\'เหลิงทู่\' เนื้อกระต่ายเสิร์ฟเย็นในน้ำมันพริกกับฮวาเจียวเสฉวนและถั่วลิสง คือหนึ่งในอาหารเรียกน้ำย่อยที่แซ่บกล้าที่สุดของเสฉวน และจื้อก้งก็คือบ้านเกิดของมัน อาหารเมืองนี้ถือกำเนิดจากสำรับอิ่มหนำของกรรมกรเหมืองเกลือ และยังคงรักษาประเพณีใส่เครื่องเทศอย่างใจป้ำไว้จนทุกวันนี้'),
  'panzhihua/steel': ('เมืองหลวงแห่งแร่เหล็กและไทเทเนียม', 'พานจือฮวาที่สร้างขึ้นในหุบเขาสูงชันของแม่น้ำจินซา คือมหานครเหล็กกล้าที่ถลุงแหล่งแร่วาเนเดียม-ไทเทเนียมที่อุดมที่สุดในโลก เมืองที่ผุดขึ้นจากความว่างเปล่าในยุคเร่งอุตสาหกรรมครั้งใหญ่ของศตวรรษที่ยี่สิบแห่งนี้ ได้ชื่อมาจากดอกงิ้วสีแดงเพลิงอันเป็นเอกลักษณ์ของท้องถิ่น'),
  'panzhihua/fruitvalley': ('หุบเขาผลไม้แดดจัด', 'มะม่วง ทับทิม และกล้วยแห่งหุบเขาจินซาอันร้อนแล้ง สุกงอมได้แม้ล่วงเข้าฤดูหนาวในภูมิอากาศจุลภาคที่แดดจัดแห่งนี้ มะม่วงเก็บเกี่ยวปลายฤดูคือความภาคภูมิใจของเมือง และสวนผลไม้ก็แต่งแต้มรสชาติเขตร้อนอย่างเหนือความคาดหมายให้แก่เมืองเหล็กกล้าแห่งนี้'),
  'panzhihua/sunshine': ('เมืองแห่งแสงแดดฤดูหนาว', 'ด้วยแสงแดดราว 2,700 ชั่วโมงต่อปี พานจือฮวาคือจุดหมายเพื่อสุขภาพของผู้ที่มองหาฤดูหนาวอันอบอุ่นสดใส ผู้เกษียณที่หนีความหนาวเหน็บจากภาคเหนือมาพำนักที่นี่ตลอดฤดู และเมืองก็เชิดชูแสงแดดของตนด้วยค่ายกีฬาและรีสอร์ตน้ำพุร้อน'),
  'panzhihua/jinsha': ('แม่น้ำจินซา', 'จินซา \'แม่น้ำทรายทอง\' คือต้นน้ำของแม่น้ำแยงซี ที่กัดเซาะหุบเขาลึกขณะไหลเชี่ยวผ่านใจกลางพานจือฮวา เขื่อนไฟฟ้าพลังน้ำตามลำน้ำหล่อเลี้ยงพลังงานให้ทั้งภูมิภาค ขณะที่สะพานและทางเดินเลียบน้ำก็เติมชีวิตชีวาให้สองฟากฝั่ง'),
  'dazhou/gas': ('เมืองหลวงแห่งก๊าซธรรมชาติ', 'ใต้ผืนดินของต๋าโจวคือผู่กวาง หนึ่งในแหล่งก๊าซธรรมชาติที่ใหญ่ที่สุดของจีน ทำให้เมืองนี้เป็นฐานพลังงานระดับชาติ ท่อส่งก๊าซทอดยาวจากที่นี่สู่เมืองอุตสาหกรรมทางตะวันออก และเศรษฐกิจก๊าซก็เปิดศักราชใหม่ให้แก่มุมภูเขาแห่งนี้ของเสฉวน'),
  'dazhou/ba': ('มรดกอาณาจักรปา', 'ที่นี่คือดินแดนของนักรบปาโบราณผู้เลื่องชื่อเรื่องดาบรูปใบหลิว เครื่องสำริดลายเสือของพวกเขายังคงส่งเสียงผ่านซากโบราณสถานหลัวเจียปา วัฒนธรรมลึกลับของชนนักรบแห่งหุบเขาแม่น้ำกลุ่มนี้ ประกอบขึ้นเป็นชั้นที่เก่าแก่ที่สุดชั้นหนึ่งของประวัติศาสตร์เสฉวน'),
  'dazhou/dengying': ('เนื้อวัวเติงอิ่ง', 'เนื้อวัว \'เติงหยิ่ง\' ที่หั่นบางจนแสงลอดผ่านได้ราวโปร่งแสงหน้าตะเกียง ได้ชื่อมาจากหนังตะลุงที่เคยเชิดฉายด้วยแสงโคมไฟ แผ่นเนื้อกรอบบางดั่งกระดาษเคลือบด้วยเครื่องเทศหวานเผ็ดร้อน และของว่างแสนประณีตแห่งต๋าโจวนี้ก็ประดับโต๊ะอาหารมานานกว่าศตวรรษ'),
  'dazhou/hanque': ('หอหินตระกูลฮั่น', 'หอหิน \'เชวี่ย\' อายุสองพันปีที่ยืนตระหง่านกลางท้องทุ่งของชวีเซี่ยน คือความงามอันหาได้ยากของสถาปัตยกรรมสมัยฮั่นที่หลงเหลือมาถึงปัจจุบัน หอประตูแกะสลักที่ครั้งหนึ่งเคยตั้งเด่นตามทางเข้าสุสานเหล่านี้ จารึกโลกยุคฮั่นลงบนแผ่นหินด้วยภาพสัตว์ในตำนานและฉากชีวิตประจำวัน'),
  'guangyuan/jianmen': ('ด่านเจี้ยนเหมิน', 'ด่านเจี้ยนเหมิน ที่ว่ากันว่า \'คนเดียวเฝ้าด่าน หมื่นคนมิอาจผ่าน\' คือกุญแจล็อกเส้นทางสู่โบราณ ด้วยหน้าผาที่ตั้งชันราวคมดาบ ด่านซึ่งเป็นจุดยุทธศาสตร์ของกองทัพมาตั้งแต่ยุคสามก๊กแห่งนี้ ชวนให้นึกถึงวรรคทองของหลี่ไป๋ที่ว่าเส้นทางสู่แคว้นสู่นั้น \'ยากยิ่งกว่าปีนขึ้นฟ้า\''),
  'guangyuan/wuzetian': ('บ้านเกิดของบูเช็กเทียน', 'เชื่อกันว่าบูเช็กเทียน (อู่เจ๋อเทียน) จักรพรรดินีหญิงเพียงพระองค์เดียวในประวัติศาสตร์จีน ประสูติที่กว่างหยวน และวัดหวงเจ๋อก็เชิดชูพระนางมานับพันปี เมืองเฉลิมฉลองผู้ปกครองผู้ทรงอำนาจพระองค์นี้ด้วยเทศกาลสตรีประจำปี ขณะที่พระรูปของพระนางประทับนั่งอย่างสงบเยือกเย็นในวัดริมแม่น้ำ'),
  'guangyuan/plankroad': ('ทางเดินไม้โบราณ', 'ทางเดินไม้กระดานที่พาดบนคานซึ่งตอกฝังเข้าไปในหน้าผาสูงชัน คืออนุสรณ์แห่งความกล้าหาญที่ทำให้เส้นทางสู่ ซึ่ง \'ยากยิ่งกว่าปีนขึ้นฟ้า\' นั้นพอจะสัญจรได้ ร่องรอยของทางเดินโบราณยังหลงเหลืออยู่ที่โตรกหมิงเยว่ ที่ซึ่งผู้มาเยือนเดินบนแผ่นกระดานที่บูรณะแล้ว และสัมผัสจังหวะหัวใจของกองคาราวานในอดีต'),
  'guangyuan/cypress': ('ระเบียงต้นสนชุ่ยหยุน', 'ต้นสนไซเพรสเก่าแก่นับหมื่นต้นเรียงรายสองข้างเส้นทางโบราณ เปลี่ยนระเบียงชุ่ยหยุนให้กลายเป็นอุโมงค์สีเขียว ตำนานยกความดีความชอบการปลูกส่วนหนึ่งให้คำสั่งของจางเฟย (เตียวหุย) วีรบุรุษยุคสามก๊ก และถนนร่มรื่นสายนี้นับเป็นแนวปลูกต้นไม้ริมทางที่เก่าแก่ที่สุดในโลกที่ยังคงเหลือรอด'),
  'yaan/panda': ('แหล่งกำเนิดหมีแพนด้า', 'แพนด้ายักษ์ได้รับการบรรยายทางวิทยาศาสตร์เป็นครั้งแรกที่เป่าซิงในปี 1869 เมื่อรายงานของอาร์ม็อง ดาวิด นักธรรมชาติวิทยาชาวฝรั่งเศส แนะนำสัตว์แสนน่ารักชนิดนี้ให้โลกรู้จัก ศูนย์แพนด้าปี้เฟิงเสียสืบสานมรดกนี้ต่อไป และป่าไผ่ชุ่มหมอกของหย่าอันก็ยังคงเป็นอู่กำเนิดของแพนด้า'),
  'yaan/rain': ('เมืองแห่งสายฝน', '\'สายฝนหย่า\' ชะล้างหลังคาบ้านเรือนแทบทุกค่ำคืน และทุกเช้าเมืองก็เปล่งประกายด้วยสีเขียวสดนับพันเฉดที่เพิ่งถูกชำระล้าง ชาวเมืองนับความงามสามประการ ได้แก่ ฝนหย่า ปลาหย่า และสาวหย่า สามสิ่งนี้สรุปจิตวิญญาณอันอ่อนโยนและอุดมสมบูรณ์ของเมืองแห่งสายฝนได้อย่างครบถ้วน'),
  'yaan/mengding': ('ชาเขาเหมิงติ่ง', 'ตำนานเล่าว่าชาถูกปลูกด้วยมือมนุษย์เป็นครั้งแรกบนภูเขาเหมิงติ่งเมื่อราวสองพันปีก่อน ภูเขาลูกนี้จึงได้รับสมญาว่าอู่กำเนิดแห่งวัฒนธรรมชา ใบชาจากสวนโบราณบนยอดเขาถูกถวายแด่จักรพรรดิมานานหลายศตวรรษ และพิธีชงชาก็ยังคงจัดขึ้นบนลาดเขาชุ่มหมอกจนทุกวันนี้'),
  'yaan/yayu': ('ปลาหย่า', 'ปลาหย่าในตำนานที่เติบโตในลำธารน้ำละลายจากหิมะ ถูกเสิร์ฟบนโต๊ะในหม้อดินเดือดปุด และนับเป็นหนึ่งในความงามสามประการของเมือง ปลาซึ่งเลื่องชื่อเรื่องเนื้อขาวแน่นนี้ซ่อนกระดูกชิ้นเล็กรูปดาบไว้ในหัว และตำนานท้องถิ่นก็ผูกเรื่องเล่าไว้กับ \'ดาบ\' เล่มนี้มากมาย'),
  'xianyang/qincapital': ('เมืองหลวงจักรวรรดิฉิน', 'ที่นี่เคยเป็นเมืองหลวงของราชวงศ์ฉิน ราชวงศ์แรกที่รวมแผ่นดินจีนเป็นหนึ่งเดียว จิ๋นซีฮ่องเต้ทรงเริ่มเส้นทางสู่จักรวรรดิจากเสียนหยางแห่งนี้ ปัจจุบันพระราชวังเหลือเพียงแหล่งโบราณคดี ที่ซึ่งเครื่องสำริดและฐานรากอาคารกระซิบเล่าถึงอำนาจเมื่อกว่าสองพันปีก่อน'),
  'xianyang/qianling': ('สุสานเฉียนหลิง', 'เฉียนหลิง สุสานร่วมที่เจาะเข้าไปในภูเขาของบูเช็กเทียนและจักรพรรดิเกาจงพระสวามี เป็นหนึ่งในสุสานหลวงราชวงศ์ถังไม่กี่แห่งที่รอดพ้นจากการปล้นสะดมมาถึงเรา ทหารหินและรูปสลักทูตต่างชาติเรียงรายตามทางวิญญาณ ขณะที่ศิลาไร้จารึกอันลือชื่อของบูเช็กเทียนก็ปล่อยให้ประวัติศาสตร์เป็นผู้ตัดสินพระนางเอง'),
  'xianyang/zhengguo': ('คลองเจิ้งกั๋ว', 'คลองเจิ้งกั๋วที่ขุดขึ้นในปลายยุครณรัฐ ทดน้ำหล่อเลี้ยงที่ราบกวานจงจนกลายเป็นยุ้งฉางของแคว้นฉิน และวางรากฐานทางเศรษฐกิจของการรวมแผ่นดิน ระบบชลประทานที่หล่อเลี้ยงภูมิภาคมากว่าสองพันปีนี้ คือผลงานชิ้นเอกแห่งอัจฉริยภาพทางวิศวกรรมโบราณ'),
  'xianyang/guokui': ('ขนมปังแผ่นกั๋วขุย', '\'กัวขุย\' แผ่นแป้งกรอบหนาใหญ่เท่าฝาหม้อ นับเป็นหนึ่งใน \'สิบสิ่งประหลาด\' อันลือชื่อของมณฑลส่านซี ขนมปังแบนนี้อบช้า ๆ บนไฟฟืนจนเก็บได้นานหลายวัน และเรื่องเล่าก็สืบย้อนไปถึงการศึกโบราณ ที่ว่ากันว่าเหล่าทหารใช้หมวกเหล็กของตนต่างกระทะอบขนมปังนี้'),
  'baoji/bronze': ('เมืองหลวงแห่งเครื่องสัมฤทธิ์', 'จากผืนดินของเป่าจี ดินแดนหัวใจของราชวงศ์โจว มีภาชนะสำริดจารึกอักษรนับพันชิ้นผุดขึ้นมา ในจำนวนนั้นคือเหอจุน ซึ่งจารึกคำว่า \'จงกั๋ว\' (จีน) ที่เก่าแก่ที่สุดเท่าที่รู้จัก พิพิธภัณฑ์สำริดของเมืองจัดแสดงฝีมือช่างอายุสามพันปีนี้ด้วยคอลเลกชันที่มั่งคั่งที่สุดแห่งหนึ่งของโลก'),
  'baoji/famen': ('วัดฝ่าเหมิน', 'วัดฝ่าเหมิน ผู้พิทักษ์พระบรมสารีริกธาตุกระดูกนิ้วพระหัตถ์ของพระพุทธเจ้า เคยเป็นคลังศักดิ์สิทธิ์ของจักรพรรดิราชวงศ์ถัง เมื่อห้องใต้ดินลับใต้เจดีย์ถูกเปิดออกในปี 1987 ขุมทรัพย์ยุคถังอันตระการตาทั้งทองคำ เงิน และผ้าไหมก็ปรากฏสู่แสงตะวัน ปัจจุบันมีศาสนสถานขนาดมโหฬารประดิษฐานพระธาตุองค์นี้'),
  'baoji/taibai': ('ภูเขาไท่ไป๋', 'ไท่ไป๋ หลังคาสูง 3,771 เมตรของเทือกเขาฉินหลิ่ง หล่อเลี้ยงตำนานด้วยหิมะที่คงอยู่แม้ล่วงเข้าฤดูร้อน \'หิมะเดือนมิถุนายนบนไท่ไป๋\' คือหนึ่งในทัศนียภาพเลื่องชื่อของกวานจงโบราณ เส้นทางเดินสู่ทะเลสาบธารน้ำแข็งบนยอดเขา พาคุณย่ำไปบนเส้นแบ่งทางธรรมชาติระหว่างจีนเหนือกับจีนใต้'),
  'baoji/saozi': ('บะหมี่เซ่าจื่อ', 'บะหมี่ \'เส้าจึ\' แห่งฉีซานในซอสเนื้อรสเปรี้ยวเผ็ด ได้ชื่อว่าเป็นรสชาติที่ยังมีชีวิตของครัวยุคราชวงศ์โจว ด้วยเส้นที่เรียวยาวและเหนียวนุ่มเด้งลิ้น น้ำส้มสายชูและพริกทอดเริงระบำร่วมกับแครอท ไข่ และเห็ดหูหนู ส่วนการเลี้ยงแขกในงานแต่งงานด้วยบะหมี่ชามแล้วชามเล่าก็เป็นธรรมเนียมสืบทอดมาหลายร้อยปี'),
};
